UPDATE `quest_offer_reward` SET `RewardText`='The Dragon Isles is a beautiful place, $n.\n\nI must be on my way, but first let me give you a hand.', `VerifiedBuild`=66102 WHERE `ID`=59985; -- An End to Beginnings
UPDATE `quest_offer_reward` SET `RewardText`='Victory is ours today, $n. More must be done, and I believe you are ready to go off to new adventures.', `VerifiedBuild`=66102 WHERE `ID`=59984; -- Dungeon: Darkmaul Citadel
UPDATE `quest_offer_reward` SET `VerifiedBuild`=66102 WHERE `ID` IN (59981, 59979, 59978, 59975, 56839, 59947, 59945, 59946, 59944, 59943, 54933, 59970, 59949, 59948, 59940, 59939, 59935, 59933, 59930, 59929, 59927);
UPDATE `quest_offer_reward` SET `RewardText`='I\'m glad to see the catapults are shattered, and you\'re in one piece.\n\nIt can be rare to achieve both with Cork\'s inventions.', `VerifiedBuild`=66102 WHERE `ID`=59980; -- Catapult Destruction
UPDATE `quest_offer_reward` SET `RewardText`='We\'ve got to be prepared for anything on this island.\n\nAlso, Throg found this bag nearby and thought you might have use of it.', `VerifiedBuild`=66102 WHERE `ID`=59950; -- Stocking Up on Supplies
UPDATE `quest_offer_reward` SET `RewardText`='Hmph, it\'s about time. I suppose you\'ll need my help to find out what else is going on.', `VerifiedBuild`=66102 WHERE `ID`=59942; -- The Re-Deather
UPDATE `quest_offer_reward` SET `RewardText`='Cork turned the device meant for enlarging things into a weapon capable of untold destruction?\n\nThe goblins in Orgrimmar may give him an award for this.', `VerifiedBuild`=66102 WHERE `ID`=59941; -- Re-sizing the Situation
UPDATE `quest_offer_reward` SET `RewardText`='You sure got some guts! I respect that. I joined this expedition thinkin\' it\'d be a quick and easy way to make a little profit.\n\nBut now with all this shadow magic and crazy ogres... maybe I can make a LOT of profit!', `VerifiedBuild`=66102 WHERE `ID`=59938; -- Down with the Quilboar
UPDATE `quest_offer_reward` SET `RewardText`='<Won\'sa quickly eats the meat that you cooked.>\n\nLooks I not gonna be knockin\' on Bwonsamdi\'s door, after all.\n\nYa best hurry. Da quilboar have some of da expedition!', `VerifiedBuild`=66102 WHERE `ID`=59932; -- Cooking Meat
UPDATE `quest_offer_reward` SET `RewardText`='I\'m stabilizing Won\'sa wounds, but she needs food before she starves.', `VerifiedBuild`=66102 WHERE `ID`=59931; -- Finding the Lost Expedition
UPDATE `quest_offer_reward` SET `RewardText`='Some force is manipulating this storm!\n\nStay near me when the ship crashes. I\'ll keep you safe.', `VerifiedBuild`=66102 WHERE `ID`=59928; -- Brace for Impact
UPDATE `quest_offer_reward` SET `RewardText`='Good, you\'ve kept training since we set sail.\n\nI must investigate this storm. Some unnatural force is behind it.\n\nSpar with Throg. He will assess your skills and decide on your role once we make landfall.', `VerifiedBuild`=66102 WHERE `ID`=59926; -- Warming Up
UPDATE `quest_offer_reward` SET `RewardText`='Braving the dark depths of Azj-Kahet is no easy feat, soldier. \n\nYour work down there has bought the people of Hallowfall a moment\'s reprieve.', `VerifiedBuild`=66102 WHERE `ID`=88916; -- Radiant Incursion: Sureki's End
UPDATE `quest_offer_reward` SET `RewardText`='Your efforts to thwart the siege of Dunelle\'s Kindness have been a blessing for all of Hallowall.\n\nHad the Dawntower been extinguished, eastern Hallowfall would\'ve been plunged into darkness.\n\nThank you, $n.', `VerifiedBuild`=66102 WHERE `ID`=87480; -- Sureki Incursion: The Eastern Assault

