UPDATE `quest_offer_reward_locale` SET `VerifiedBuild`=56311 WHERE (`locale`='itIT' AND `ID` IN (46727,26320,26319,26297,26296,26295,26292,26291,26290,26288,26349,26348,26353,26286,26287,26271,26266,26257,26252,26230,26213));
UPDATE `quest_offer_reward_locale` SET `RewardText`='Helix responsabile degli attacchi degli Gnoll?$B$B<Kearnen gira la testa verso la torre.>$B$BÈ rinchiuso lì dentro da giorni. Stavo giusto aspettando una scusa per andare a prenderlo.', `VerifiedBuild`=56311 WHERE (`ID`=26289 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Ti faccio i miei complimenti, $gcoraggioso:coraggiosa; $C. Le rocce della costa delle Marche Occidentali saranno ancora visibili e, grazie al tuo duro lavoro, molte vite saranno risparmiate.$b$bSono morto inutilmente su questa spiaggia e ora non voglio che altri facciano la mia stessa fine.', `VerifiedBuild`=56311 WHERE (`ID`=26347 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Sì... un tempo ero di carne e ossa, proprio come te, $gragazzo:ragazza;. Be\', almeno fino al giorno in cui i Murloc attaccarono il faro...', `VerifiedBuild`=56311 WHERE (`ID`=26371 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='<I cardini della vecchia cassa sono arrugginiti ma funzionano ancora. Forzi l\'apertura e prendi il bottino.>$b$b<Congratulazioni!>', `VerifiedBuild`=56311 WHERE (`ID`=26356 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='\"Hai quasi raggiunto la meta, $gcacciatore:cacciatrice; di tesori!\"', `VerifiedBuild`=56311 WHERE (`ID`=26355 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='\"Ottimo lavoro, $gcacciatore:cacciatrice; di tesori!\"', `VerifiedBuild`=56311 WHERE (`ID`=26354 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Certo, $gcaro:cara;. La nostra bambina lavora a Guardiacolle e conosce bene i mendicanti delle Marche Occidentali. Forse ha sentito qualcosa. Prima di andare, vorrei darti un po\' del mio Stufato delle Marche Occidentali e raccontarti qualcosa sulla nostra cara bambina.', `VerifiedBuild`=56311 WHERE (`ID`=26270 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Che tu sia $gbenedetto:benedetta;. Sono giorni che questi poveri orfani non mangiano un pasto caldo.$b$bSembra che sia avanzato abbastanza cibo da poter nutrire anche altri mendicanti delle Marche Occidentali.', `VerifiedBuild`=56311 WHERE (`ID`=26241 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Grazie, $gfratello:sorella;. Hai reso un grande servigio a me e mia moglie. Ti prometto che non lo dimenticherò. Non ho molti soldi, ma puoi prendere tutto quello che ho.', `VerifiedBuild`=56311 WHERE (`ID`=26237 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Horatio Laine? Quell\'uomo è un pezzo di sterco. Sporco come le mie mutande.$b$bAscoltami, $gamico:amica; di solito non do consigli, ma tu mi sei $gsimpatico:simpatica;. VAI VIA DALLE MARCHE OCCIDENTALI. Ci sei già dentro fino al collo, ma se continui così, presto arriverà l\'onda.', `VerifiedBuild`=56311 WHERE (`ID`=26236 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='$GNovellino:Novellina;, qui abbiamo a che fare con un\'organizzazione. Per aver ucciso in pieno giorno il vagabondo più ricco delle Marche Occidentali senza lasciare traccia, deve esserci sotto qualcosa di grosso. Qualcuno con molto potere. Cos\'hai scoperto finora?', `VerifiedBuild`=56311 WHERE (`ID`=26232 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='<Lou si tappa le orecchie con le mani e inizia a strillare.>$B$BBASTA! SMETTILA! FERMATI! Non voglio starti a sentire, non voglio saperlo e non mi interessa! Da queste parti un\'informazione del genere è un biglietto di sola andata per la fossa.$b$bHo un\'altra informazione da darti e, per quel che mi riguarda, abbiamo concluso.', `VerifiedBuild`=56311 WHERE (`ID`=26228 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Guarda, non abbiamo più stanze per...$b$bTi ha mandato Horatio? Va bene... allora, come posso aiutarti?$b$bNon è qui, vero? Sa che non mi sto nascondendo da lui, vero? Sto solo provando a volare basso, capisci?', `VerifiedBuild`=56311 WHERE (`ID`=26215 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Una grande scoperta, $gnovellino:novellina;. In ufficio ho una pila di questa roba. Sostanzialmente, siamo tornati al punto di partenza. Cosa sappiamo? Qualcuno che ama scrivere storie ha spedito una lettera ai Ciglioarcuato.$b$bSembra di essere in una storia... ma vera.', `VerifiedBuild`=56311 WHERE (`ID`=26214 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Gnoll e Murloc? Scempiaggini, $gragazzo:ragazza;! So bene come gli Gnoll e i Murloc riducono le loro vittime, e non è questo il caso. Sarebbe troppo facile. Troppo... perfetto.$b$bInoltre, le vittime di Ciglioarcuato vivevano abusivamente in questa fattoria da 5 anni. No, chiunque li abbia ammazzati aveva delle buone ragioni per farlo. Si tratta di un omicidio e noi riusciremo a scoprire chi è stato.', `VerifiedBuild`=56311 WHERE (`ID`=26209 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Questo atto non conta niente. Guarda la data. I Ciglioarcuato hanno occupato abusivamente la Cascina dei Jensen per cinque anni.$B$BA quanto pare non hanno mai avuto il tempo per riparare il carro...', `VerifiedBuild`=56311 WHERE (`ID`=184 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Omicidio, $gnovellino:novellina;. Si chiama omicidio quello che vedi lì davanti a te.', `VerifiedBuild`=56311 WHERE (`ID`=26378 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Vedo che ti sei $gdato:data; da fare! Hai la nostra gratitudine, $n.', `VerifiedBuild`=56288 WHERE (`ID`=11 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Ti manda il Maresciallo Dughan? Non fai parte dell\'esercito, ma se Dughan si fida di te, chi sono io per contraddirlo?$B$BLa nostra situazione è a dir poco disperata. Spero tu possa aiutarci.', `VerifiedBuild`=56288 WHERE (`ID`=239 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='La Miniera Venarossa è piena di Coboldi? Questa non ci voleva!$B$BGrazie per il tuo rapporto, $n, anche se avrei preferito delle buone notizie.', `VerifiedBuild`=56288 WHERE (`ID`=76 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='L\'hai trovato? Ottimo lavoro, $n. Non \"collezionerà\" più niente dalle miniere di Elwynn!$B$BQuesto anello che hai recuperato è interessante... lo portano i membri della vecchia Gilda dei Tagliapietre di Roccavento. Erano anni che non ne vedevo uno, da quando la Fratellanza dei Defias imperversava per queste terre.', `VerifiedBuild`=56288 WHERE (`ID`=147 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Questi avanzi andranno bene, anche se sono un po\' rovinati...$B$BEcco a te!', `VerifiedBuild`=56288 WHERE (`ID`=83 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Ah, grazie per il buono. Scegli pure l\'armatura che preferisci.$B$BSpero ti tornerà utile. Buona fortuna, $C.', `VerifiedBuild`=56288 WHERE (`ID`=59 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Hai portato le pinne? Magnifico! Il Maresciallo Dughan è preoccupato per il problema dei Murloc nella parte orientale di Elwynn. Volevo rassicurarlo dicendogli che è tutto sotto controllo.$B$BGrazie a te ora posso farlo.', `VerifiedBuild`=56288 WHERE (`ID`=46 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `VerifiedBuild`=56288 WHERE (`locale`='itIT' AND `ID` IN (71,45,123,26152,37,35,62,47,106,86,54,26390,26389,29083,29081,29078));
UPDATE `quest_offer_reward_locale` SET `RewardText`='Eccellente! Grazie a te dovrei riuscire a completare l\'ordine in tempo. Prendi queste monete per il disturbo, in segno di gratitudine.$B$BGrazie ancora e addio.', `VerifiedBuild`=56288 WHERE (`ID`=5545 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Grazie mille per il tuo aiuto, $n. C\'è qualcosa nella foresta che rende questi animali così aggressivi.$B$BDi qualunque cosa si tratti, spero resti lì.', `VerifiedBuild`=56288 WHERE (`ID`=52 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Santo cielo! Mi sento in colpa a ingannare la mia famiglia, ma i miei sentimenti verso Tommy Joe sono troppo forti per poterli ignorare.$B$BGrazie, $n. Berrò questo liquore alla prima occasione utile e poi andrò dal mio amore.$B$BTi prego di accettare questo.', `VerifiedBuild`=56288 WHERE (`ID`=114 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Vedo che ti sei $gprocurato:procurata; le alghe! Molto bene. Ora aspetta un momento mentre preparo la pozione...', `VerifiedBuild`=56288 WHERE (`ID`=112 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Mi piange il cuore per quei due poveri ragazzi, Maybell e Tommy Joe. Mi ricordano me, quand\'ero giovane e innamorato.$B$BDeve pur esserci qualcosa che posso fare per aiutarli. Fammi pensare...', `VerifiedBuild`=56288 WHERE (`ID`=107 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Vedo che ti sei $gdato:data; da fare con i Coboldi. Grazie per le candele, $n. Tieni la tua ricompensa...', `VerifiedBuild`=56288 WHERE (`ID`=60 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Oh, l\'hai trovata! Grazie, tesoro, grazie!$B$BPrendi questo oggetto... apparteneva a mio marito, diceva sempre che portava fortuna. Vorrei tanto che non se lo fosse dimenticato nella sua ultima missione! *sniff*', `VerifiedBuild`=56288 WHERE (`ID`=87 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Mmm, delizioso! Questo pasticcio è il migliore che abbia mai mangiato!$B$BSento già che mi sta tornando la memoria...', `VerifiedBuild`=56288 WHERE (`ID`=84 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Finché la rivalità tra le nostre famiglie andrà avanti, la storia d\'amore tra Tommy Joe e Maybell non ha futuro. Forse però possiamo farli stare insieme, anche solo per un po\'.$B$BMmm... vediamo cosa si può fare...', `VerifiedBuild`=56288 WHERE (`ID`=111 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Cos\'è che hai perso? Be\', io non ho preso nessuna collana, non sono un ladro!$B$BPotrei dirti chi è stato, ma... <Billy Maclure ghigna.>... sono troppo affamato per ricordarmi il suo nome.', `VerifiedBuild`=56288 WHERE (`ID`=85 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Grazie al cielo! Quella scrofa stava divorando tutto il nostro raccolto! Grazie, $n.$B$BScegli pure la tua ricompensa tra questi oggetti.', `VerifiedBuild`=56288 WHERE (`ID`=88 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Sì, ho parlato con Remy. Lo rispetto come mercante, anche se tutti i rapporti sui Murloc a est sono a dir poco superficiali.$B$BCapisco la tua preoccupazione, ma finché non riceverò un rapporto militare sulla minaccia dei Murloc non posso inviare altre truppe a est.', `VerifiedBuild`=56288 WHERE (`ID`=40 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Riposo e relax contro la stanchezza e il freddo, questo è il nostro motto! Prego, siediti vicino al fuoco e riposa le tue ossa stanche.$B$BTi va un po\' del nostro cibo e delle nostre bevande?', `VerifiedBuild`=56288 WHERE (`ID`=37112 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Sei una benedizione, $n. Sei veramente $gun eroe:un\'eroina; dell\'Alleanza! Anche se la terra è stata incenerita e del vigneto sono rimaste solo cenere e macerie, forse riuscirò comunque a riprendermi. Giusto? Non può andare così male.', `VerifiedBuild`=56288 WHERE (`ID`=26391 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Credo che tu ora comprenda il potere della Luce. La Luce trasmette speranza, $gfratello:sorella;. E la Luce ci salva dall\'oscurità! SIA LODATA LA LUCE!', `VerifiedBuild`=56288 WHERE (`ID`=29082 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='È vero, ci hanno teso un\'imboscata. Non oso mandare altri soldati per timore di perderli. Mi serve $gun volontario:una volontaria;. Qualcuno disposto a rischiare la propria vita!', `VerifiedBuild`=56288 WHERE (`ID`=29080 AND `locale`='itIT');
UPDATE `quest_offer_reward_locale` SET `RewardText`='Eccellente, $n. Ti sei $grivelato:rivelata; una risorsa importante per la guarnigione.$B$BParla pure con qualsiasi istruttore all\'interno e nei dintorni dell\'abbazia se senti il bisogno di affinare le tue abilità di combattente.$B$BQuando sarai $gpronto:pronta; ho un altro incarico da affidarti...', `VerifiedBuild`=56288 WHERE (`ID`=29079 AND `locale`='itIT');

