UPDATE `quest_request_items_locale` SET `CompletionText`='Hai cancellato da questo mondo Vecchio Occhiobuio? È stato visto girare lungo la spiaggia delle Marche Occidentali.$b$bTorna da me quando avrai ucciso quella bestia.', `VerifiedBuild`=56311 WHERE (`ID`=26349 AND `locale`='itIT');
UPDATE `quest_request_items_locale` SET `CompletionText`='Buongiorno, $gsignore:signora;. Come posso aiutarla?', `VerifiedBuild`=56311 WHERE (`ID`=26266 AND `locale`='itIT');
UPDATE `quest_request_items_locale` SET `CompletionText`='Non abbiamo bisogno dell\'aiuto di civili, $gragazzino:ragazzina;. Lascia che se ne occupino i professionisti.', `VerifiedBuild`=56311 WHERE (`ID`=184 AND `locale`='itIT');
UPDATE `quest_request_items_locale` SET `VerifiedBuild`=56288 WHERE (`locale`='itIT' AND `ID` IN (11,83,46,71,26152,114,112,107,47,87,84,106,54,26389));
UPDATE `quest_request_items_locale` SET `CompletionText`='Hai trovato il Collezionista? Sei $griuscito:riuscita; a scoprire per chi lavora?', `VerifiedBuild`=56288 WHERE (`ID`=147 AND `locale`='itIT');
UPDATE `quest_request_items_locale` SET `CompletionText`='Ho ricevuto l\'ordine dall\'Esercito di Roccavento di rifornire gli abitanti della città con armature di stoffa e di cuoio.$B$BSe hai un buono da darmi, sarò felice di realizzare qualcosa per te.', `VerifiedBuild`=56288 WHERE (`ID`=59 AND `locale`='itIT');
UPDATE `quest_request_items_locale` SET `CompletionText`='Manca poco alla scadenza, $C. Fa\' presto, ti prego, e recupera quei ciocchi di legno.', `VerifiedBuild`=56288 WHERE (`ID`=5545 AND `locale`='itIT');
UPDATE `quest_request_items_locale` SET `CompletionText`='Cosa?!? Sono mesi che la nostra gente non lavora nelle miniere di Elwynn!$B$BFammi vedere questa nota...', `VerifiedBuild`=56288 WHERE (`ID`=123 AND `locale`='itIT');
UPDATE `quest_request_items_locale` SET `CompletionText`='Ti sei $gprocurato:procurata; le candele che ti ho chiesto?', `VerifiedBuild`=56288 WHERE (`ID`=60 AND `locale`='itIT');
UPDATE `quest_request_items_locale` SET `CompletionText`='Non credo sia giusto dar da mangiare al ragazzo che mi ha rubato la collana, ma se serve per riavere indietro ciò che è mio, lo farò!$B$BHai trovato la carne di cinghiale?', `VerifiedBuild`=56288 WHERE (`ID`=86 AND `locale`='itIT');
