INSERT INTO `quest_offer_reward` (`ID`, `Emote1`, `Emote2`, `Emote3`, `Emote4`, `EmoteDelay1`, `EmoteDelay2`, `EmoteDelay3`, `EmoteDelay4`, `RewardText`, `VerifiedBuild`) VALUES
(79219, 6, 0, 0, 0, 0, 0, 0, 0, 'Dispensing rewards. Thank you, champion. This should be sufficient remuneration for your efforts.', 65560), -- Renowned with the Council of Dornogal
(87308, 1, 0, 0, 0, 0, 0, 0, 0, 'They deserved no less.', 65655), -- Twilight's Dawn
(90768, 1, 0, 0, 0, 0, 0, 0, 0, 'Their nefarious alliance with Xal\'atath is clear. Good work. Now we take them down.', 65614), -- Cult It Out
(90767, 1, 0, 0, 0, 0, 0, 0, 0, 'I suppose aligning with yet another being hellbent on ending the world is only fitting for the Cult of Twilight.', 65614), -- More Doom
(90766, 1, 0, 0, 0, 0, 0, 0, 0, 'Excellent. You have the bearing of a true acolyte of the Twilight\'s Blade.', 65614), -- Xal'atath's Proven Faithful
(90765, 1, 0, 0, 0, 0, 0, 0, 0, 'You hardly seem prepared to serve Xal\'atath. We shall fix that.', 65614), -- Midnight Dress
(91795, 1, 0, 0, 0, 0, 0, 0, 0, 'These champions of the Twilight\'s Blade are just as foolhardy as the other members of the cult. We will cut them all down, in time.', 65655), -- Disrupt the Call
(90763, 1, 0, 0, 0, 0, 0, 0, 0, 'Good, you\'ve arrived. \n\nKeep an eye on our allies. We may be working with them to stop the Twilight\'s Blade, but the Void is insidious. \n\nThey cannot be fully trusted.', 65614), -- The Twilight Highlands
(90761, 1, 0, 0, 0, 0, 0, 0, 0, 'The Radiant Song casts a long, dark shadow on Azeroth. The Twilight\'s Blade are taking advantage of it.\n\nWe have work to do.', 65560), -- Avoiding Blame
(90764, 1, 0, 0, 0, 0, 0, 0, 0, 'Good, you\'re here. We cannot let the Twilight\'s Blade gain ground in the city.', 65560); -- The Cult Within
INSERT INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `EmoteOnCompleteDelay`, `EmoteOnIncompleteDelay`, `CompletionText`, `VerifiedBuild`) VALUES
(91795, 0, 25, 0, 0, 'There is much to do. Do not dawdle.', 65560), -- Disrupt the Call
(87308, 0, 25, 0, 0, 'There is much to do. Do not dawdle.', 65560), -- Twilight's Dawn
(89514, 0, 6, 0, 0, 'What was it like? I hear you went back and entered someone\'s nightmare?', 65560), -- Worldsoul: Horrific Visions Revisited
(90768, 0, 1, 0, 0, '\"Twilight\'s Blade.\" I suppose that\'s a reference to Xal\'atath\'s imprisonment? Imbecilic. But I would expect nothing less from them.', 65560), -- Cult It Out
(90767, 1, 0, 0, 0, 'Have you discovered more about the cult\'s plans?', 0), -- More Doom
(90766, 0, 1, 0, 0, 'Return when you have a true understanding of the Twilight\'s Blade. I should be able to see your all-encompassing devotion to Xal\'atath in the way you ambulate.', 65560), -- Xal'atath's Proven Faithful
(90765, 1, 0, 0, 0, 'You look lost, fledgling. Isn\'t there somewhere you should be?', 0), -- Midnight Dress
(90761, 0, 1, 0, 0, 'The calm and comfort the Void offers is a lie. Any who say otherwise are already lost.', 65560); -- Avoiding Blame
INSERT INTO `quest_offer_reward_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(87308, 134204, 237504, 'enUS', 'One day you will be the one we send heroes after, $c. We both know it.', 0, 65655), -- Twilight's Dawn
(90763, 134204, 237504, 'enUS', 'You may be working with my magisters to end this threat, but I will not let my guard down for a moment. No practitioners of the Void can be trusted.', 0, 65614), -- The Twilight Highlands
(90764, 134204, 246158, 'enUS', 'At least you are not so void-addled that you can still respond to a summons.\n\nCome. We cannot let the Twilight\'s Blade gain ground in the city.', 0, 65560); -- The Cult Within
INSERT INTO `quest_request_items_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(90761, 134204, 246158, 'enUS', '<Rommath sneers at you.>\n\nThe calm and comfort the Void offers is a lie. You would do well to abandon it.', 0, 65560); -- Avoiding Blame
