(91835, 0, 6, 0, 0, 'Are the prisoners safe?', 66337), -- Send Dem Home
(93766, 0, 1005, 0, 0, 'With your aid, will can bring all our people closer together.', 66337), -- Midnight: World Quests
(91826, 0, 0, 0, 0, 'Easy does it.', 66337), -- Tripwire Tango
(91825, 0, 0, 0, 0, 'You made that look easy.', 66337), -- Dead Men Keep No Secrets
(91824, 0, 0, 0, 0, 'Those artifacts should never have fallen into the wrong hands.', 66337), -- The Thieves' Trail
(91823, 0, 0, 0, 0, 'Yes?', 66337), -- Lines Cut, Tongues Silenced
(93754, 0, 1, 0, 0, 'The Vilebranch usage of magic reeks of undead teachings... and I know that never ends well.', 66337), -- Maisara Caverns
(93734, 0, 0, 0, 0, 'Whatever Groffa had is bad. Right?', 66337), -- Precious Trinkets
(91750, 0, 0, 0, 0, '<Fleeg howls mournfully.>\n\nKill them for what they did to Furgh!', 66337), -- Perils of Trust
