INSERT INTO `quest_offer_reward` (`ID`, `Emote1`, `Emote2`, `Emote3`, `Emote4`, `EmoteDelay1`, `EmoteDelay2`, `EmoteDelay3`, `EmoteDelay4`, `RewardText`, `VerifiedBuild`) VALUES
(90843, 1, 0, 0, 0, 0, 0, 0, 0, 'How are you? We could use more hands to help us explore the Dragon Isles!', 66102), -- Aiding the Dragon Isles
(90842, 1, 0, 0, 0, 0, 0, 0, 0, 'If you ever find yourself lost, use your Hearthstone to get yourself back to where you should be.', 66102), -- Home Is Where the Hearth Is
(90840, 1, 0, 0, 0, 0, 0, 0, 0, 'Excellent choice! I\'m looking forward to what you do next.\n\nTake this riding mount. It\'ll help you get around here faster.', 66102), -- What's Your Specialty?
(85679, 0, 0, 0, 0, 0, 0, 0, 0, 'You\'ll want to keep your gear repaired if you want to earn honor and glory amongst the Horde!', 66102), -- Repair Yourself
(88945, 1, 66, 0, 0, 0, 0, 0, 0, 'Your actions down in Azj-Kahet should buy the defenders at the Aegis Wall a small moments respite.\n\nMay your bravery inspire all those who answer the Flame\'s Radiance call.', 66102); -- Radiant Incursion: Rak-Zakaz
INSERT INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `EmoteOnCompleteDelay`, `EmoteOnIncompleteDelay`, `CompletionText`, `VerifiedBuild`) VALUES
(59970, 0, 0, 0, 0, 'I see you have the grimoire that enacted the binding ritual.', 0), -- A Warlock's Bargain
(59929, 0, 0, 0, 0, 'The murlocs are carrying our first aid kits. Slay them and bring all of the kits to me.', 0), -- Murloc Mania
(59981, 0, 0, 0, 0, 'These were the ward stones used to bind me? Perhaps even the ogres have heard tale of my strength!', 0); -- Controlling their Stones
INSERT INTO `quest_offer_reward_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(88945, 0, 241100, 'enUS', 'We\'re lucky to have you down here. \n\nNot so long ago, we Arathi dared not delve this far into Azj-Kahet. Yet, here we are.\n\nYour actions in Rak-Zakaz should buy us a reprieve, and hopefully delay their next assault on the Aegis Wall.', 0, 66102), -- Radiant Incursion: Rak-Zakaz
(88916, 0, 241100, 'enUS', 'Many Lamplighters and soldiers have been lost in the graveyard they call \"Arathi\'s End\".\n\nOn behalf of those lost in the dark, and those here on the front, I thank you.', 0, 66102), -- Radiant Incursion: Sureki's End
(87480, 0, 241093, 'enUS', 'The people of Dunelle\'s Kindness thank you, $n.\n\nWe will continue to hold Lothar\'s Landing with our earthen allies and fortify the town below. \n\nMay the light of the Sacred Flame remain with you, friend.', 0, 66102); -- Sureki Incursion: The Eastern Assault
