(251035, 1, 254150, 0, 0, 0, 0, 0, 0, 0, 0, 66384), -- Ariani
(251388, 1, 182566, 0, 0, 0, 0, 0, 0, 0, 0, 66384), -- Devout Pilgrim
(254549, 1, 33990, 0, 0, 33990, 0, 0, 0, 0, 0, 66384), -- Avatar of Halazzi
(254884, 1, 246209, 0, 0, 246189, 0, 0, 0, 0, 0, 66384), -- Arator
(254893, 1, 61305, 0, 0, 0, 0, 0, 0, 0, 0, 66384), -- Avatar of Akil'zon
(255171, 1, 235237, 0, 0, 235237, 0, 0, 0, 0, 0, 66384), -- Nalorakk's Chosen
(255232, 1, 235237, 0, 0, 235237, 0, 0, 0, 0, 0, 66384), -- Halazzi's Chosen
(255289, 1, 235242, 0, 0, 235231, 0, 0, 0, 0, 0, 66384), -- Nalorakk's Chosen
(259261, 1, 246209, 0, 0, 246189, 0, 0, 0, 0, 0, 66384), -- Arator
