INSERT INTO `quest_template_locale` (`ID`, `locale`, `LogTitle`, `LogDescription`, `QuestDescription`, `AreaDescription`, `PortraitGiverText`, `PortraitGiverName`, `PortraitTurnInText`, `PortraitTurnInName`, `QuestCompletionLog`, `VerifiedBuild`) VALUES
(92162, 'deDE', 'Ein erlesener Toffelgaumen', '', '', '', '', '', '', '', '', 66263),
(94425, 'deDE', 'Die Spitze bluten lassen', '', '', '', '', '', '', '', '', 66263),
(92141, 'deDE', 'Alte Gefahren', '', '', '', '', '', '', '', '', 66263),
(92566, 'deDE', 'Armeen der Finsternis', '', '', '', '', '', '', '', '', 66263),
(93712, 'deDE', 'Finesse und Fertigkeiten', 'Sammelt $1oa Schnitzzähne und $2oa unvergleichliche Gefieder und bringt sie zu Tyn in Silbermond.', 'Im Kampf ist die Erscheinung beinahe so wichtig wie die rohe Fertigkeit. Wenn Ihr den Gegner einschüchtert, bevor Ihr das Schwert überhaupt gezogen habt, seid Ihr dem Sieg bereits näher.\n\nUnsere Pfeilmacher gehen noch einen Schritt weiter und behaupten, schöne Federn würden die Pfeile unserer Weltenwanderer stärker machen. Ich... bin mir da nicht so sicher, aber die Ästhetik weiß ich zu schätzen.\n\nHier ist eine Liste dessen, was sie für die Pfeile diese Woche brauchen. Liefert, was Ihr könnt, und ich erledige den Rest.', '', '', '', '', '', '', 66263),
(91390, 'deDE', 'Spezialauftrag: Was von einem zerstörten Tempel bleibt', '', '', '', '', '', '', '', '', 66263),
(95439, 'deDE', 'Vermisste Tiere', 'Findet Kara in Eurer Nachbarschaft.', '$n, ich bin so froh, Euch zu sehen.\n\nEine gute Freundin hat mir in einem Brief von einem Problem in der Nachbarschaft berichtet, das vor allem mit ihrer großen Sammlung an Haustieren zu tun hat.\n\nSie wirkte sehr angespannt und in Sorge. Ich an Eurer Stelle würde sie unverzüglich aufzusuchen und ihr helfen!', '', '', '', '', '', '', 66263),
(91490, 'deDE', 'Teldrassil löschen', '', '', '', '', '', '', '', '', 66263),
(93573, 'deDE', 'Die Dunkelheit entschlüsseln', '', '', '', '', '', '', '', '', 66263),
(93425, 'deDE', 'Funken des Krieges: Harandar', 'Sammelt bei aktivem Kriegsmodus $1oa Funken des Krieges in Harandar.', 'Mächtige Kreaturen sind in ganz Harandar gewachsen. Kümmert Euch darum.', '', '', '', '', '', 'Sprecht mit Zerella in Silbermond.', 66263),
(92140, 'deDE', 'An die Wurzeln', '', '', '', '', '', '', '', '', 66263),
(91799, 'deDE', 'Flugprüfung', '', '', '', '', '', '', '', '', 66263),
(92549, 'deDE', 'Die Leere von oben', '', '', '', '', '', '', '', '', 66263),
(92152, 'deDE', 'Kampf gegen die Blüte', '', '', '', '', '', '', '', '', 66263),
(91806, 'deDE', 'Großwildjagd', '', '', '', '', '', '', '', '', 66263),
(91937, 'deDE', 'Porträts im Tal', '', '', '', '', '', '', '', '', 66263),
(95482, 'deDE', 'Vermisste Tiere', 'Findet Kara in Eurer Nachbarschaft.', '$n, Ich bin so froh, Euch zu sehen.\n\nEine gute Freundin hat mir in einem Brief von einem Problem in der Nachbarschaft berichtet, das vor allem mit ihrer großen Sammlung an Haustieren zu tun hat.\n\nSie wirkte sehr angespannt und in Sorge. Ich an Eurer Stelle würde sie unverzüglich aufzusuchen und ihr helfen!', '', '', '', '', '', '', 66263),
(92120, 'deDE', 'Das Verständnis der Magie', '', '', '', '', '', '', '', '', 66263),
(92105, 'deDE', 'Papiere bitte!', '', '', '', '', '', '', '', '', 66263),
(93524, 'deDE', 'Grabenlauf', '', '', '', '', '', '', '', '', 66263),
(93708, 'deDE', 'Leitende Metalle', 'Sammelt $1oa Einheiten Umbralzinnerz und $2oa Einheiten brillantes Silbererz und bringt sie zu Belil in Silbermond.', 'Unsere arkanen Konstrukte mögen rein magisch wirken, aber unter der Oberfläche verbergen sich eine Menge fortgeschrittener Leitungen. Silbermonds Ingenieure sind in gewisser Weise selbst Zauberwirkende.\n\nSie haben ihre Produktion hochgefahren, um unsere Verteidigung zu stärken. Natürlich wenden sie sich für die Versorgung an uns. Das meiste Material ihrer Bestellung habe ich, aber Zinn und Silber sind etwas knapp.\n\nKönnt Ihr mir helfen, die Bestellung zu erfüllen?', '', '', '', '', '', '', 66263),
(86951, 'deDE', 'Abstieg der Aufgestiegenen', '', '', '', '', '', '', '', '', 66192),
(91779, 'deDE', 'Kampfausbildung für Kultisten', '', '', '', '', '', '', '', '', 66192),
(86957, 'deDE', 'Drakgors Rache', '', '', '', '', '', '', '', '', 66017);
INSERT INTO `quest_offer_reward_locale` (`ID`, `locale`, `RewardText`, `VerifiedBuild`) VALUES
(90822, 'deDE', 'Da es niemanden mehr gibt, der sie leiten kann, hat sich diese Teufelsmagieoperation wohl erledigt... zumindest für den Moment.\n\nEs war mir eine Ehre, mit Euch zusammenzuarbeiten, $n.', 66384),
(93754, 'deDE', 'Ich hätte nie gedacht, dass ich mal froh darüber sein würde, Trolle gerettet zu haben. Die Bleichborken behalten diese Tat besser gut in Erinnerung.', 66384),
(94835, 'deDE', 'Reife Leistung. Kommt nächste Woche wieder, um Euer Training fortzusetzen.', 66384),
(93910, 'deDE', 'Astalor dient der Sache Silbermonds, auch wenn sein Weg dorthin selten gerade verläuft.', 66384),
(91222, 'deDE', 'Eure Gliedmaßen scheinen unversehrt zu sein und Ihr habt kein Messer im Rücken stecken. Gut gemacht, $p.', 66384),
(91224, 'deDE', 'Lebt durch die Phasenklinge, sterbt durch... was auch immer Ihr ihm gerade angetan habt.', 66384),
(91232, 'deDE', 'Ihr scheint ihr die Flügel gestutzt zu haben. Ich bin beeindruckt.', 66384),
(92002, 'deDE', 'Gute Arbeit. Immersang ist dank Eures Heldenmuts ein wenig sicherer und ich um das ein oder andere Goldstück reicher. So schlägt man zwei Fliegen mit einer Klappe.', 66384),
(91989, 'deDE', 'Welch Freude! Die werden bei Hofe für viel Aufregung und auch Zähneknirschen sorgen.\n\nVielen Dank! Ach, und $n... wascht Euch unbedingt die Hände, bevor Ihr Euch die Augen reibt. Oder sonst irgendetwas. Das habe ich auf die harte Tour gelernt.', 66384),
(91974, 'deDE', 'Anar\'anel belore! Das hört man doch gern. Diese Neuigkeiten werden gewiss ein paar Herzen für unsere Sachen erwärmen.', 66384),
(94816, 'deDE', 'Danke für Eure Unterstützung. Bitte nehmt dies als Zeichen meiner Dankbarkeit.', 66384),
(93930, 'deDE', 'Fast hätte ich erwartet, dass Ihr heulend nach Hause rennt! Ich hoffe, Ihr hattet eine tolle Zeit.', 66384),
(90573, 'deDE', 'Eure Stärke wird nur noch von Eurem Scharfsinn übertroffen. Ich werde dafür sorgen, dass alle erfahren, wie fabelhaft Ihr Euch heute geschlagen habt.', 66384),
(91693, 'deDE', 'Wunderbar.\n\nIch hoffe sehr, dass Ihr auch etwas Zeit findet, Euch zu vergnügen, während der Hof tagt. Ich kann den schmallippigen, ergebnisorientierten Typ zwar gut gebrauchen, aber ein Lächeln würde Euch keinen Zacken aus der Krone brechen.', 66384),
(91629, 'deDE', 'Ich lasse meinen Diener sofort die Einladung überbringen.', 66384),
(91628, 'deDE', 'Ah, Eure vermeintliche Effizienz ist also nicht nur ein Gerücht.\n\nHervorragend. Jetzt kann das Spiel beginnen.', 66384),
(93942, 'deDE', 'Das ist ein Funke der Strahlen.\n\nJede Woche wird Euch einer dieser Funken auf Euren Abenteuern begegnen. In seinem jetzigen Zustand ist er ziemlich nutzlos, aber wenn Ihr mehr sammelt, könnt ihr mächtige Gegenstände herstellen. Solche Reagenzien sind formbar, robust und bei vielen Handwerkern sehr begehrt.\n\nDies ist ein einzigartiges Herstellungsmaterial, mit dem Ihr einem Gegenstand zu einer Expertise verhelfen könnt, die die Fähigkeiten von Sterblichen übersteigt.', 66384),
(95175, 'deDE', 'Wir haben zahlreiche Anomalien neutralisiert, doch es verweilen noch weitere. Wir machen uns auf weitere Aktivierungen gefasst.', 66384),
(91700, 'deDE', 'Nachdem die Gefahren eliminiert wurden, fühle ich mich viel sicherer.', 66384),
(88706, 'deDE', 'Welche Schuld und Reue ich für meine Taten auch empfinden mag, ich kann mich erst damit auseinandersetzen, wenn die Schlacht gewonnen ist.\n\nWir müssen jetzt konzentriert bleiben.', 66384),
(88705, 'deDE', 'Gute Arbeit, $n. Macht Euch ihretwegen keine Sorgen. Ich werde sicherstellen, dass sie heil nach Hause kommt.', 66384),
(88704, 'deDE', 'Oh, dem Licht sei Dank! Ich dachte schon, ich würde als Futter enden!\n\nKönnt Ihr mich von diesem Ding befreien?', 66384),
(88703, 'deDE', 'Ich hoffe, Ihr seid auf die Jagd vorbereitet, $n. Diese Beute ist schwieriger zu erwischen als die meisten anderen.', 66384),
(91426, 'deDE', 'Wir haben da draußen gute Arbeit geleistet, $n. Das ist das Einzige, worauf wir hoffen können.', 66384),
(88702, 'deDE', 'Wir konnten nur so wenige Leute retten, $n.\n\nIch bin zwar froh über die Arbeit, die wir geleistet haben, aber dennoch wünschte ich, wir hätten mehr tun können.', 66384),
(88701, 'deDE', 'Keine angenehme Aufgabe, $n, doch vielleicht spendet Ihr damit den Überlebenden etwas Trost.', 66384),
(86810, 'deDE', 'Ich bin mir recht sicher, dass diese Proben nicht reichen werden, aber immerhin sind sie ein guter Anfang! Kommt später wieder, dann habe ich vielleicht mehr Aufgaben.', 66384),
(91417, 'deDE', 'Diese Leute kämpfen so tapfer für uns. Wir müssen alles tun, was in unserer Macht steht, um sie zu beschützen.', 66384),
(88700, 'deDE', 'Das sollte sie etwas schwächen und uns den bevorstehenden Angriff erleichtern.', 66384),
(88698, 'deDE', 'Danke, $n. Die Astralen werden jetzt ein Weilchen mit ihren eigenen Angelegenheiten beschäftigt sein. Damit ist der Weg für uns frei.', 66384),
(88699, 'deDE', 'Mein Volk dankt Euch. Bestimmt wird Turalyon gleich den Angriff starten wollen.', 66384),
(88697, 'deDE', 'Jetzt seht Ihr, wogegen wir zu kämpfen haben. Wir müssen diese Geschütze ausschalten und die Leerenelfen retten, die an diese Maschinen gefesselt sind. Diese beiden Ziele haben oberste Priorität, wenn wir mit unseren Kriegspanzerungen abheben wollen.', 66384),
(88696, 'deDE', 'Ihr seid gekommen. Das ist gut. Wie Ihr sehen könnt, war der Feind bereits auf unsere Ankunft vorbereitet, auch wenn wir es nicht waren.', 66384),
(90777, 'deDE', 'Wir haben bis jetzt durchgehalten, $n. Je schneller wir uns Xal\'atath an der Leerenspitze stellen, desto schneller können wir das alles hinter uns bringen.', 66384),
(91627, 'deDE', 'Ah, $n. Willkommen in meinem Hafen. Einer Zuflucht, in der man seit den Tagen Anasterians den Wirbel der Welt vergessen kann.\n\nEinige halten dies lediglich für eine frivole Party. Doch auf dieser güldenen Lichtung wurden bei Wein Entscheidungen getroffen, die die Geschicke ganzer Generationen geprägt haben.', 66263),
(91930, 'deDE', 'Es is\' an der Zeit, vom Meister selbst zu lernen.', 66263),
(91251, 'deDE', 'Ich hoffe, dass sie in ihren letzten Augenblicken wenigstens nicht leiden musste. Ruhet in Frieden, Neydra.', 66263),
(92178, 'deDE', 'So viele Jahre meines Lebens habe ich der Magie gewidmet.\n\nDas nächste Kapitel wird... bemerkenswert.', 66263),
(92177, 'deDE', 'Während Ihr mehr Pein sammelt, experimentiere ich mit dem ungeahnten Potenzial dieser Macht.', 66263),
(93850, 'deDE', 'Die Pein, die Angst... Ich kann fühlen, wie die Musik das alles fortwäscht.\n\nIch danke Euch.', 66263),
(91117, 'deDE', 'Ihr riecht wie eine Leiche und habt diesen entrückten Blick in den Augen, den man bekommt, wenn man zu viel Zeit mit Todesrittern verbringt. Ich nehme an, Eure Jagd war erfolgreich?', 66263),
(93086, 'deDE', 'Fangen wir an.', 66263),
(93043, 'deDE', 'Ich kann Euch versichern, dass es selten so einfach sein wird.', 66263),
(92945, 'deDE', 'Eines Narren Falle ist eines anderen Elfen Schatz.', 66263),
(92926, 'deDE', 'Wie ich sehe, habe ich Eure Neugier geweckt. \n\nHervorragend.', 66263),
(95114, 'deDE', 'Schaut Euch an... Ihr befolgt ja schon Anweisungen.\n\nAusgezeichnet.', 66263),
(93200, 'deDE', 'Wir sind dankbar für Eure Hilfe. Nehmt diese Vorräte als Zeichen unserer Dankbarkeit.', 66263),
(92407, 'deDE', 'Ausgezeichnete Arbeit. Bestimmt finden wir noch mehr Anomalien, aber mit Eurer Hilfe haben wir die unmittelbaren Gefahren ausgemerzt.', 66263),
(92365, 'deDE', 'Gut gemacht. Diese Sturmarionkerne vertraue ich Euch gerne an. Gebraucht sie klug!', 66263),
(91402, 'deDE', 'So was hab ich noch nie geseh\'n. Und ich will\'s auch nie wieder. Gut gemacht.', 66263),
(91400, 'deDE', 'Danke fürs Sammeln. Jetzt können uns\'re Gegner die hohe Kunst der Amani nich\' nutzen.', 66263),
(91399, 'deDE', 'Unsere Jäger könn\' das Pulver gut gebrauch\'n. Danke.', 66263),
(91401, 'deDE', 'Mit den Knochen hab ich was vor. Danke.', 66263),
(86522, 'deDE', 'Das war eine unmögliche Mission. Wir werden die Opfer nicht vergessen, die uns eine reelle Chance erkauft haben.\n\nTrotzdem weiß ich, dass nicht jeder Sieg ein Grund zum Feiern ist. Wenn der Krieg uns zwingt, zwischen Freundschaft und Pflicht zu wählen, wären viele von uns wie gelähmt.\n\nWir werden die Gelegenheit, die Ihr uns eröffnet habt, nicht verspielen. Jetzt beginnt unsere Gegenoffensive.', 66263),
(86521, 'deDE', 'Es ist vorbei. Wir können aufatmen, wenn auch nur für einen Moment.', 66263),
(86520, 'deDE', 'Er ist bereits hier. Wir müssen ihn aufhalten.', 66263),
(86519, 'deDE', 'Lothraxion wird die Nexuspunkte in Schutt und Asche legen, selbst wenn es uns Silbermond kostet!', 66263),
(86518, 'deDE', 'Geht es Euch gut? Ich muss etwas verpasst haben. Warum hat Decimus uns überhaupt geholfen? Er hätte uns jederzeit verraten können. Das ergibt alles keinen Sinn...', 66263),
(86516, 'deDE', 'Eine erfolgreiche Jagd. Jetzt, wo die Ultradons tot sind, müssen wir nur noch lebend hier rauskommen.', 66263),
(86515, 'deDE', 'Gut gemacht. Bald halten wir den Mantel der Prädation in unseren Händen und brauchen Decimus nicht mehr.\n\nVerwechselt seine Nützlichkeit nicht mit Loyalität, wie es Alleria getan hat.', 66263),
(86517, 'deDE', 'Das ist nicht gerecht. Hieron kam nicht hierher, um zu sterben. Das Licht sollte Leute beschützen und sie nicht in den Tod führen.\n\n<Arator scheint in Gedanken zu sein.>\n\nIch danke Euch. Ich werde dafür sorgen, dass die anderen sein Tagebuch erhalten.', 66263),
(86514, 'deDE', 'Ich habe Lothraxion noch nie so unvorsichtig erlebt. Er wirft Leben weg und prescht blind vor. Weiß er denn nicht, dass er hier keine Armee befehligt? \n\nNun, wenigstens habt Ihr Euren Teil getan. Wir werden versuchen, die Mission doch noch zu retten.', 66263),
(86512, 'deDE', 'Fühlt Ihr es auch? Jede einzelne Kreatur hier fürchtet Euch oder will Euch töten. Jetzt kann ihre Meisterin Euch nicht mehr ignorieren.', 66263),
(86513, 'deDE', 'Dagegen hat meine Mutter also all die Jahre angekämpft? Ich werde nicht zulassen, dass sie diese Bürde weiterhin allein trägt.', 66263),
(86511, 'deDE', 'Mir behagt es nicht, unsere Truppen aufzuteilen. Nicht, wenn so viel auf dem Spiel steht.\n\nWir werden nicht vorpreschen wie Lothraxion. Findet heraus, was Decimus weiß. Wenn man Jagd auf Domanaar macht, sollte man vorbereitet sein.', 66263),
(90571, 'deDE', 'Da habt Ihr es: Ihr müsst einfach nur Terminas den Mantel stehlen. Ich rate Euch, schnell zu handeln. Wer weiß, wann Terminas in die Obskurionzitadelle zurückkehrt.\n\nDie Sache mit Ciphus ist bedauerlich. Ich hatte vor, ihn nach ausreichender Mast selbst zu verschlingen.', 66263),
(86510, 'deDE', 'Habt Ihr es auch bequem? Ich freue mich, dass jemand meine Gastfreundschaft zu schätzen weiß.\n\nUnd jetzt sollten wir wohl besser zum Geschäftlichen kommen, bevor Euer leuchtender Freund hier wieder einen Wutanfall bekommt.', 66263),
(86509, 'deDE', 'Gäste sind für einen Domanaar eine seltene Freude. Ganz besonders solche, die aus freien Stücken kommen.', 66263),
(86545, 'deDE', 'Decimus ist ein weitaus fähigerer Domanaar, als er uns weismachen will.', 66263),
(86544, 'deDE', 'Was war das...?', 66263),
(89249, 'deDE', 'Sogar die Macht eines Naaru reichte nicht aus...', 66263),
(86542, 'deDE', 'Alle Kräfte, die ich aufbringen konnte, einfach... verschlungen.', 66263),
(86541, 'deDE', 'Ein sterbliches Wesen, das offen gegenüber Ideen von außen ist? Wahrlich vorbildhaft. Ihr braucht mir nicht zu danken.\n\nDoch vielleicht wollt Ihr mich ja von diesen Fesseln befreien? Das Licht wird langsam etwas unangenehm.\n\nNicht? Nun gut...', 66263),
(86540, 'deDE', 'Das dauert zu lange! Jeder verschwendete Augenblick bringt uns dem Verderben näher!', 66263),
(88768, 'deDE', 'Ich hoffe, Xal\'atath hat das gesehen. Sie ist als Nächstes dran.', 66263),
(86539, 'deDE', 'Ein gefangener Naaru! Das Licht wird diesen Monstern keine Gnade zeigen.', 66263),
(86538, 'deDE', 'Sehr mächtig. Ich kann die Energie spüren, die es ausstrahlt. Beeindruckend.', 66263),
(86537, 'deDE', 'Xal\'atath.\n\nSehen wir uns diese letzte Nachricht an.', 66263),
(86530, 'deDE', 'Gut. Dieses Modell kenne ich.\n\nUnd jetzt kommt der Katalysator.', 66263),
(86528, 'deDE', 'So etwas habe ich schon einmal gesehen. Die Astralen benutzen sie, um ihre Kommunikation zu verschlüsseln.\n\nEin wertvoller Fund, $n.', 66263),
(86531, 'deDE', 'Sie werden versuchen, alles wieder aufzubauen, aber so weit werden wir es nicht kommen lassen.', 66263),
(86536, 'deDE', 'Sollte Xal\'atath sterblich sein, dann macht sie das angesichts all ihrer Taten und dem, wozu sie geworden ist, nur umso abscheulicher.\n\nUnser langer Kampf endet in dieser Welt. Ich schwöre es.', 66263),
(86565, 'deDE', 'Ihr habt gute Arbeit geleistet, $n.', 66263),
(86561, 'deDE', '<Lothraxion zieht eine finstere Miene>.\n\nAbscheulich. Alleria hat mir ihren Plan erklärt, doch ich bin nicht sicher, ob ich ihr zustimme.', 66263),
(86562, 'deDE', 'Die Kreaturen hier scheinen sowohl tierischer als auch magischer Natur zu sein.\n\nGewalt zieht die Leere an. Ich habe schon unzählige Welten in ihr untergehen sehen.\n\nKönnte die Wildheit dieser Tiere die Leere hierhergelockt haben?', 66263),
(86559, 'deDE', 'Die übrigen Leerenelfen wurden ausgesandt, um Stützpunkte aufzubauen oder die Gegend auszukundschaften.\n\nIch habe... gemischte Gefühle, was Allerias Anwesenheit betrifft. Ihre Fähigkeiten und ihre Erfahrung sind von unschätzbarem Wert für uns, und trotzdem...\n\nDie Leere in ihr ist stark... das macht mir Sorgen. Behaltet sie im Auge.\n\nDer Leere kann man NIEMALS vertrauen.', 66263),
(86557, 'deDE', 'Finstere Kreaturen. Habt Ihr es auch gespürt?\n\nIhnen allen haftet der Gestank der Leere an.', 66263),
(86558, 'deDE', 'Die Leerenelfen riskieren zwar Verderbnis, aber sie können die Welt um uns herum besser verstehen als die meisten anderen. Wir brauchen ihr Wissen, aber wir können ihnen nicht trauen.\n\nDas ist mir ein Dorn im Auge, aber ich habe bereits mehr Späher angefordert.', 66263),
(86549, 'deDE', 'Diese... diese Macht! Noch nie konnte ich die Leere so fühlen. \n\nAbsolut überwältigend.', 66263),
(86543, 'deDE', 'Das hätte besser laufen können. \n\nAber andererseits hat Rommath mich am Leben gelassen, es hätte also auch schlimmer laufen können.', 66263),
(92061, 'deDE', 'Gut gemacht. Dieser Leerensturm löst in allen, die ihn sehen, Angst und Schrecken aus, auch in mir.\n\nAber ich habe mich dazu entschieden, mich dem Bösen zu stellen und ihm ins Gesicht zu spucken. Leider hatten nicht alle den Luxus, diese Entscheidung treffen zu können.', 66263),
(93691, 'deDE', 'Ihr habt unseren Dank, $C. Silbermond ist dank Eurer Fertigkeiten stärker.', 66263),
(91084, 'deDE', 'Als Halduron zum ersten Mal in einen Kriegsrat platzte und von versteckten Welten und uralten Kriegern redete, dachte ich, er wäre verrückt geworden. Aber jetzt, da ich die Haranir mit eigenen Augen gesehen habe...\n\nIch bin froh, sie als potentielle Verbündete zu haben. Und ich bin froh, dass Ihr den Kontakt zwischen uns hergestellt habt.\n\nWir haben noch viel zu tun. Ich habe keinen Zweifel daran, dass die Hara\'ti in Zukunft wichtige Verbündete für Silbermond sein werden.', 66263),
(95324, 'deDE', 'Die Haranir wollen sich dem Kampf gegen die Leere anschließen?\n\nNichts liegt mir ferner, als einem geschenkten Falkenschreiter ins Maul zu schauen. Halduron hat sich für ihre Stärke und Beharrlichkeit verbürgt. Von beidem werden wir in den bevorstehenden Schlachten viel brauchen.', 66263),
(86898, 'deDE', 'Zum ersten Mal seit Generationen wandeln die Haranir wieder auf der Oberfläche von Aln\'haras Schöpfung. Die Zeit wird zeigen, wie diese Schöpfung uns empfängt.\n\nDer Kampf ist noch lange nicht vorbei. Die Leere steht vor Euren Toren und bedroht Euer Volk. Doch wisset eines: Von diesem Tag an wird jede Bedrohung, die Aln\'haras Gaben zerstören will, zuerst an den Hara\'ti vorbeikommen müssen, egal ob hier oben oder tief unter der Erde.', 66263),
(86897, 'deDE', 'Es ist vorbei. Doch obwohl die Lichtblüte vielleicht niemals ganz zurückgehen wird, wurde der Drahtzieher hinter der Katastrophe zurück in den Wurzelpfad getrieben. Die Lichtwut wurde zurückgedrängt und die umliegenden Wälder gegen ihre Ausbreitung geschützt. Nun können wir sicher sein, dass Immersang nicht weiter unter der Lichtblüte leiden muss.\n\nWir haben es geschafft. Wir haben gewonnen!', 66263),
(86894, 'deDE', 'Die Haranir waren immer schon mächtig. Doch jetzt, wo wir von der Gabe der Göttin erleuchtet sind, kann uns nichts mehr aufhalten.', 66263),
(86896, 'deDE', 'Mit Euch und unseren neuen Verbündeten der Haranir haben meine Waldläufer viele Beispiele, denen sie folgen können. Vielleicht werde ich in Zukunft einige Eurer Techniken in der Zuflucht lehren.', 66263),
(86892, 'deDE', 'Ich... Ich kann es nicht fassen. Meine Brüder und Schwestern an der Oberfläche stehen Seite an Seite mit Oberflächenbewohnern und nutzen die Magie von Aln...\n\n<Orweyna beißt die Zähne zusammen und lächelt Euch kurz zu.>\n\nAber wir haben keine Zeit, sentimental zu werden. Wir müssen Ruia zur Rechenschaft ziehen und der Lichtwut ein Ende setzen.', 66263),
(86891, 'deDE', 'Wir haben getan, was wir konnten.\n\nNun bleibt uns nichts mehr anderes übrig, als die Magister zu beschützen und zu hoffen, dass das die Lichtwut aufhalten wird.', 66263),
(86887, 'deDE', 'Die meisten Weltenwanderer haben sich zu unserer Stellung zurückgezogen. Diejenigen, die noch verbleiben, sind bereit zu flüchten, sobald das Ritual beginnt.\n\nWir haben keine Zeit mehr; jetzt oder nie!', 66263),
(86885, 'deDE', 'Verdammt! Für jeden Wurzelpfad, den Ihr verbrennt, tauchen anderswo zwei neue auf. Es ist, als ob sie sich von selbst vermehren und in Sekundenschnelle ausbreiten würden.\n\nIch glaube, diesem Problem ist mit Pfeilen und Magie nicht beizukommen, nicht einmal mit Orweynas Hilfe. Wir haben weder genug Alnstaub noch genügend Haranir, um die Ausbreitung der Lichtwut zu verhindern.', 66263),
(86884, 'deDE', 'Es ist eine Schande, zu sehen, wie etwas aus Harandar solche Verwüstung anrichtet. Diese Wurzeln mögen nicht Aln\'haras Wiege sein, doch sie wachsen ihr dennoch entgegen.', 66263),
(91967, 'deDE', 'Danke für Eure Fürsprache. Obwohl ich mich rühme, alles für Silbermond und den Sonnenbrunnen zu tun, habe ich das Gefühl, dass meine Geduld am Ende gewesen wäre und ich etwas gesagt hätte, das wir alle bereut hätten.', 66263),
(91854, 'deDE', 'Gut gemacht. Dieser Leerensturm löst in allen, die ihn sehen, Angst und Schrecken aus, auch in mir.\n\nAber ich habe mich dazu entschieden, mich dem Bösen zu stellen und ihm ins Gesicht zu spucken. Leider hatten nicht alle den Luxus, diese Entscheidung treffen zu können.', 66263),
(94430, 'deDE', 'Dieses Ausrüstungsteil ist perfekt!\n\nIch kann es für Euch noch mächtiger machen, aber dafür brauchen wir Reagenzien.', 66263),
(91822, 'deDE', 'Das könnte interessant werden.', 66263),
(86883, 'deDE', 'Unfassbar, dass die Lichtblüte sich so rasant in Immersang verbreitet hat, während wir unten geschuftet haben.\n\nVerdammt sei das alles! Jeder Sieg enthüllt wachsende Gefahr.', 66263),
(86890, 'deDE', 'Azeroth braucht unsere Hilfe. Ich werde nicht tatenlos zusehen, während sie überrannt wird.\n\nUnd ich weiß, dass Ihr das auch nicht werdet.', 66263),
(86877, 'deDE', 'Ich wünschte, wir könnten alle retten, aber...\n\nEine grausame, aber notwendige Aufgabe.', 66263),
(86880, 'deDE', 'Diese Artefakte sind nicht annähernd so wichtig wie die Leben, die hier auf dem Spiel stehen... Aber es ist gut, sie wiederzuhaben.', 66263),
(86881, 'deDE', 'Ich bete, dass dies uns allen helfen wird.', 66263),
(86867, 'deDE', 'Nun können wir anfangen.', 66263),
(86882, 'deDE', 'Das ist viel mehr, als das, wovon der Wurzelhüter berichtet hat. Wie konnte sich die Lichtblüte so schnell und so stark ausbreiten?', 66263),
(86866, 'deDE', 'Der Alnstaub kann zwar vermutlich niemanden heilen, der der Lichtblüte schon völlig verfallen ist, aber bei den anderen sollte er verhindern, dass der Befall weiter voranschreitet. Das muss reichen.', 66263),
(94677, 'deDE', 'Das sind beunruhigende Neuigkeiten. Die Lichtblüte scheint bis jetzt keine Haranir befallen zu haben. Hat sie es irgendwie geschafft, den Wurzelhüter zu infizieren? Oder spricht da der Stolz aus ihm? Er war schon immer übereifrig, aber...\n\nWir müssen uns beeilen.', 66263),
(86865, 'deDE', 'Wir haben unser Zuhause verlassen. Doch wir werden zurückkehren.', 66263),
(92448, 'deDE', 'Ohhh... dieser Staub glitzert traumhaft schön!\n\nWenn Ihr mehr findet, bringt ihn zu mir! Im Austausch habe ich seltene und wunderbare Schätze für Euch!', 66263),
(93416, 'deDE', 'Danke, $n, dass Ihr das im Keim erstickt habt.', 66263),
(86862, 'deDE', 'Ich hätte nie gedacht, dass ich das mit eigenen Augen erblicken würde, aber... hier stehen wir nun.\n\nSorgt dafür, dass sich die Mühe lohnt.', 66263),
(86861, 'deDE', 'Das muss reichen.', 66263),
(86860, 'deDE', 'Gut gemacht.', 66263),
(86859, 'deDE', 'Vielleicht haben wir hiermit eine Chance. Ich kann damit meine Waffen bestreichen und ein starkes Gift herstellen.', 66263),
(86858, 'deDE', 'Wieder eine Seele gerettet.\n\nDeshalb tue ich das, $p. All mein Opfer, die Trennung von der Stimme der Göttin... All das lohnt sich für jede Seele, die ich aus dem Griff des Risses befreie.', 66263),
(86857, 'deDE', 'Diese Manifestation ist eine der reinsten Formen des Alnwahnsinns, die es hier gibt. Mein Zauberschutz wird sie nicht ewig ablenken. Wir müssen uns beeilen.', 66263),
(86856, 'deDE', 'Ich kann die Stimme der Göttin nicht hören.\n\nDas ertrage ich nicht.\n\nWie kann Amarakk so leben?', 66263),
(86851, 'deDE', 'Meine Hände prickeln, wo der Alnstaub sie berührt. Ein merkwürdiges... und nicht unbedingt unangenehmes Gefühl.\n\nDer verehrte Shul\'ka hat mir gesagt, wie man den Alnstaub bearbeitet, um Haranir im Riss zu schützen. Es schien mir recht schwer, aber nachdem nun seine Magie in mir anwächst, wirkt es machbar.', 66263),
(86855, 'deDE', 'Es ist ernüchternd, die Auswirkungen des Risses auf mein Volk zu sehen. Aber Amarakks Einmischung hat mir unerwartete Hoffnung geschenkt.\n\nIch muss in den Riss gehen, um eine Antwort für Hagar zu finden. Mit der Hilfe des Shul\'ka überlebe ich dieses Unterfangen vielleicht sogar.', 66263),
(86836, 'deDE', 'Ich habe mein Band mit der Göttin aufgegeben, um mein Volk vor den Gefahren des Risses von Aln zu schützen. Ich denke, dass niemand dort hingehen sollte, ohne das Risiko zu begreifen. Ohne Schutz würden die Haranir ihm erliegen und sterben.', 66263),
(86864, 'deDE', 'Letztlich müssen wir allein eine Lösung finden.', 66263),
(86930, 'deDE', 'Wir kehren zum Anfangspunkt zurück, aber dieses Mal tragt Ihr den Segen der Göttin und wir haben Beweise, dass man der Ausbreitung der Lichtblüte Einhalt gebieten kann!\n\nDie weiteren Schritte sind mir noch nicht klar, aber ich denke, wir sind ein Stück weiter.', 66263),
(86944, 'deDE', 'Die Lichtblüte hat keine Wirkung auf Eonka und ihre Samen. Unglaublich! Könnte der Riss etwas an sich haben, das die Lichtblüte in Schach hält?', 66263),
(86942, 'deDE', 'Dann ist es also getan. Es grämt mich, dass dies vonnöten war, doch diese Verderbnis musste zurückgestutzt werden, bevor sie sich weiter ausbreiten konnte.', 66263),
(86973, 'deDE', 'Eine harte, aber nötige Arbeit. Hoffentlich dämmt das die Ausbreitung ein, bis wir einen Weg finden, sie ganz aufzuhalten.', 66263),
(89034, 'deDE', 'Gut gemacht, $n. Möge Har\'mara wieder zu der friedlichen Oase werden, die es bei unserer Ankunft war.', 66263),
(86910, 'deDE', 'Koozat ist derzeit unsere geringste Sorge. Die Lichtblüte ist hier. Har\'mara wird angegriffen!', 66263),
(86914, 'deDE', 'Manchmal werden Harmonie und Freundschaft durch kleinere Dienste gefördert.\n\nIch hoffe, dass die Rutaani und Fungianer Euch jetzt als $gVerbündeten:Verbündete; ansehen.', 66263),
(86956, 'deDE', 'In ihren Dörfern gibt es also noch keine Anzeichen der Lichtblüte? Meeka scheint sich auch nicht verändert zu haben und behauptet, dass die Rutaani sich nie lichtwahnsinnig verhalten.\n\nDas ist vielversprechend und frustrierend zugleich.\n\nIch bin froh, dass sie sich noch nicht so weit ausgebreitet hat, vermute aber, dass wir schon bald mehr davon finden.', 66263),
(86913, 'deDE', 'Willkommen in Har\'mara. Ich bin froh, Euch nach den Prüfungen wohlbehalten zu sehen.\n\nIn diesem Dorf sind Hagar und viele andere zu Hause, die Harandar ihre Heimat nennen.', 66263),
(86912, 'deDE', 'Ihr seid wach, gut. Nun, da Ihr unsere Vergangenheit gesehen habt, habe ich Euch in meine Heimat gebracht, damit Ihr meine Hoffnung für die Zukunft sehen könnt.\n\nHier in Har\'mara leben wir in Harmonie mit zwei der einheimischen Völker: den Rutaani und den Fungianern. Es ist mein Traum, dass diese Partnerschaft auch im Rest von Harandar Anklang findet.\n\nIhr solltet sie ebenfalls kennenlernen und $gZeuge:Zeugin; des Friedens werden, den wir gemeinsam geschaffen haben.', 66263),
(93943, 'deDE', 'Euer Verständnis von Kuriositäten hat sich vertieft.', 66263),
(91087, 'deDE', '<Lor\'themar hebt eine Augenbraue und runzelt die Stirn. Man kann sehen, das er Verzweiflung und Wut zurückhält.>\n\nDas ist eine... wahrlich unerwartete Wendung der Ereignisse. Und noch sind nicht alle Würfel gefallen, dessen bin ich mir sicher.', 66263),
(93437, 'deDE', 'Danke, Hash\'ura. Wirklich.\n\nWir werd\'n die Echos weiter bekämpf\'n. Aber wie\'s aussieht, können sie ohne ihren Anführer nun nich\' mehr zurückkehr\'n, nachdem sie vernichtet wurd\'n.\n\nIn den vergangenen Tagen ham Erinnerungen mein Blut aufgewühlt. Nun können wir alle ruh\'n. Vielleicht sogar damit abschließ\'n?\n\nPah! Nur das Gebrabbel eines alten Kriegers. Achtet nicht auf mich.\n\nDoch ich steh\' in Eurer Schuld.', 66263),
(93435, 'deDE', 'Ich geb\'s zu, $n. Zu wiss\'n, dass Ihr die Anstifter getötet habt, wärmt meine alt\'n Knochen.\n\nHaltet Ihr dadurch weniger von mir?', 66263),
(93436, 'deDE', 'Die Echos flieh\'n vom Schlachtfeld wie ängstliche Eber, dank Eurer Arbeit!', 66263),
(93432, 'deDE', 'Seht Ihr? \'N endloser Ozean.\n\nVielleicht kann Doru etwas aus der Asche erfahr\'n.', 66263),
(93433, 'deDE', 'Hält die Barriere? Gut.\n\nJetz\' könn\' wir uns auf die Offensive konzentrier\'n.', 66263),
(93440, 'deDE', 'Zul\'jarra schickt Euch, Hash\'ura?\n\nHeh. Sie hat es wohl satt, auf uns zu wart\'n, um schneller voranzukommen.', 66263),
(92499, 'deDE', 'Ich steh\' zu meiner Entscheidung, aber ich sollt\' mich bei Pel\'na un\' Idago entschuldig\'n.\n\nSie geb\'n mir ihre Weisheit... un\' im Gegenzug werd\' ich ihnen durch diese schwierig\'n Zeit\'n helf\'n.', 66263),
(92496, 'deDE', 'Ihr habt dem Stamm große Ehre gebracht, indem Ihr der Zwielichtklinge den Speer zu spür\'n gegeb\'n habt.', 66263),
(92497, 'deDE', 'Vergess\'n wir die Torheit des Mädchens, ich schuld\' Euch mein Leb\'n.', 66263),
(92495, 'deDE', 'Bei Nalorakks Schlund, Ihr habt ihren Streitkräft\'n \'nen ganz schönen Dämpfer verpasst.', 66263),
(92493, 'deDE', 'Guckt mal! Da klebt frisches Blut an seinem Speer! Jemand hat die Waffe vor Kurz\'m benutzt!', 66263),
(92492, 'deDE', 'Bleibt unten, $n! Verratet mein Versteck nicht.', 66263),
(91750, 'deDE', 'Es war ein Monster der Zwielichtklinge! \n\nIch hoffe, Furgh und den anderen geht\'s gut, jetzt da es tot ist.', 66263),
(93734, 'deDE', 'Ihr hättet meine Sachen nicht verbrennen müssen...', 66263),
(91749, 'deDE', '<Furgh leckt sich die Lefzen. Sie triefen vor Sabber.>\n\nDie Tasche fühlt sich... verlockend an. Das gefällt mir nicht.\n\nGut, dass er die von anderen ferngehalten hat, aber auch sehr schlecht für ihn.', 66263),
(91747, 'deDE', 'Ich glaube, die Schmuckstücke waren auch verdorben.\n\nIch bin froh, dass die Schmuckstücke nicht mehr in meinem Stamm sind.', 66263),
(91748, 'deDE', 'Ich weiß nicht, was dieser falsche Bär plant.\n\nAber es ist besser, dass seine Leitsteine zerstört sind.', 66263),
(91813, 'deDE', 'Wir meinten\'s nich\' böse. Wir wollt\'n über Nalorakk sprech\'n.\n\nEin Bär is\' aufgetaucht, der sagt, er spreche für unser\'n Loa, aber da stimmt was nich\'.\n\nVielleicht können wir mit Eurer Hilfe \'ne Lösung erschnüffeln.', 66263),
(93261, 'deDE', 'Also ham die Zwielichtklingen nich\' nur den Bruchhauern geschadet, sondern auch unsrer Tierwelt. Wir müss\'n die Kultist\'n im Blick behalt\'n un\' Nalorakks Pirsch vor ihrer Verschmutzung schütz\'n!\n\nDie Gesundheit unsres Volkes und unsrer Krabb\'n is\' meine oberste Priorität.\n\nZu seh\'n, wie meine Leute unter meiner Aufsicht hungern müss\'n, erfüllt mich mit Zorn un\' Schuldgefühlen... als würd\' ich die Erinnerung meiner Mutter als oberste Flusswandlerin beschmutz\'n. Dank Euch bin ich zu der Anführerin geword\'n, die meine Flusswandler brauch\'n.\n\nDanke, $n. Ihr seid bei den Bruchhauern immer willkommen.', 66263),
(93259, 'deDE', 'Das is\' mehr Fleisch, als wir in \'ner ganz\'n Woche geseh\'n ham! Meine Leute werd\'n dankbar sein, \'ne richtige Mahlzeit zu bekommen. Habt Dank.', 66263),
(93260, 'deDE', 'Die Scherb\'n, die Ihr gefund\'n habt, müss\'n die Leerenverschmutzung verursacht ham, die unsre Fall\'n verstopften. Ich bin froh, dass Ihr sie entfernt habt. Der Fluss sieht viel sauberer aus un\' unsre Fall\'nzahl is\' wieder normal... vorerst.\n\nMög\'n die Körbe Nalorakks Seg\'n empfangen un\' den Bruchhauern wieder volle Bäuche bescher\'n.', 66263),
(93258, 'deDE', 'Von der Leere verunreinigte Körper un\' Körbe? Un\' einige verrückte Krabb\'n ham Euch überfall\'n? Das wird ja immer schlimmer.\n\nNak\'tek hat leerenverschmutzte Körbe flussaufwärts gefund\'n, genau wie das, was Ihr hier unt\'n am Seeufer entdeckt habt. Die Leere verbindet alle unsre Hinweise! Folg\'n wir der Spur.', 66263),
(93257, 'deDE', 'Also hat sich unser Hunger herumgesproch\'n?\n\n<Kahanea verzieht das Gesicht.>\n\nDas lässt sich nicht leugnen.', 66263),
(93182, 'deDE', 'Ich weiß nich\', was Ihr oder die Loa getan habt, aber ich hab meine Kanza wieder. Un\' noch viel mehr.\n\nSie spricht wieder wie zuvor. Sogar mehr. Sie hat nie viel geredet.\n\nUn\' ich werd ihr \'nen Ort schaffen, wo sie sich sicher genug fühlt, um weiterhin mit mir zu reden.', 66263),
(90568, 'deDE', 'Sucher Krikkasch meinte, er wolle auf Euer Eintreffen warten, bevor er mir seinen Fund zeigt.', 66263),
(93181, 'deDE', 'Ich musste sie einfach sehen.\n\nNur ein allerletztes Mal.', 66263),
(93180, 'deDE', '<Kanza klatscht in die Hände und hüpft aufgeregt auf und ab.\n\nAber sie zieht Euch am Ärmel und deutet mit einer ausladenden Geste in die Ferne.\n\nSie möchte, dass Ihr noch etwas anderes für sie erledigt.>', 66263),
(93179, 'deDE', '<Ihr wollt das Kind nicht dazu zwingen, heimzukehren. Aber vielleicht könnt Ihr sie davon überzeugen, auf Euch zu hören, indem Ihr ihr bei ihrem Vorhaben helft.\n\nDen Gegenständen nach zu schließen, die vor Filos Schrein aufgereiht sind, bereitet sie eine Art Ritual vor.\n\nWenn Ihr ihr bei dem Ritual helft, kommt sie möglicherweise mit Euch oder kehrt aus freien Stücken nach Hause zurück.>', 66263),
(90485, 'deDE', 'Meine Güte, was für ein interessanter Fund!\n\nWas man von so einem alten Topf nicht alles lernen kann: wie die Vorfahren der heutigen Amani möglicherweise Essen zubereitet haben, was sie gegessen haben und was ihnen an einer Mahlzeit am wichtigsten war.\n\nIch werde eine vollständige Analyse vornehmen. Die anderen Gegenstände könnt Ihr zur Seite räumen. Sie sind bedeutend jünger als diese Schönheit.', 66263),
(90486, 'deDE', 'Dann wir probieren das jetzt mal. Richtig, $p?', 66263),
(90482, 'deDE', 'Hervorragend. Jetzt zur Zubereitung.', 66263),
(90483, 'deDE', 'Verstehe. Immerhin führen sie genaue Aufzeichnungen über all diese Schlachten. Ihre Erzählweise ist recht eigenwillig.', 66263),
(90484, 'deDE', 'Steggi ist wieder da! Ihr seid wirklich antwortlich.', 66263),
(90481, 'deDE', 'Er hat bestätigt, dass er mir ein Genehmigungsschreiben geschickt hat? Gut! Ich bin froh, dass das geklärt ist.\n\nVielleicht können wir ja jetzt eine angenehmere Begrüßung in Zul\'Aman erhalten.', 66263),
(91410, 'deDE', 'Nun da Shadra sich mit uns geg\'n die Blutfratzen verbündet hat, werd\'n wir sie für ihre Schandtaten schwer bestraf\'n.', 66263),
(91412, 'deDE', 'Diese Reise war... \'ne Offenbarung.\n\nHättet Ihr mich zu Beginn gefragt, ob wir uns mit Shadra verbünden würden, hätt\' ich Euch ins Gesicht gelacht!', 66263),
(91411, 'deDE', 'Ich kann mir nich\' vorstell\'n, dass das leicht war. Halazzi muss Eure Jagd gesegnet ham.', 66263),
(91409, 'deDE', 'Das is\' die Shadra, wie ich sie von Shadra\'Alor in Erinnerung hab. Sie wird uns beisteh\'n, wenn wir ihr helf\'n.\n\nSie hält ihre Versprechen.', 66263),
(91630, 'deDE', 'Es sieht so aus, als wollt\'n sie uns un\' unsre Fähigkeit, mit Shadra zu kommunizieren, schwäch\'n.', 66263),
(91408, 'deDE', 'Wir sollten ihn anhör\'n, aber haltet die Hand an Eurer Waffe.', 66263),
(91405, 'deDE', 'Die Blutfratz\'n ham was mit Shadra vor?\n\nKönnten die Spinnen sich gegen die Bleichbork\'n gewendet haben? Das macht keinen Sinn.', 66263),
(91404, 'deDE', 'Hey, das is\' ja \'n Spinnenfangzahn. Das muss aber \'ne riesige Spinne gewesen sein!', 66263),
(91403, 'deDE', 'Seht euch all die Muster an, die Ihr gefund\'n habt. Der Häuptling wird sicher wiss\'n, wer daraus \'n Gegengift herstell\'n kann.', 66263),
(93178, 'deDE', 'Was hat sie hinter der Stammbrücke zu Such\'n gehabt? Ich hab ihr gesagt, sie soll nich\' dahin geh\'n.\n\nUn\' dann auch noch mit meinem Korb un\' unsrem best\'n Teekessel?\n\nOh... oh, nein. Das geht nich\'! Und auch noch allein?', 66263),
(93667, 'deDE', 'Wer seid Ihr? Was macht Ihr hier?\n\n<Amaxi wirkt angespannt, kann sich aber nach einem Moment entspannen.>\n\nSchattenbeck\'n schickt Euch. Ja, uns geht\'s gut. Aber diese Tortollaner sollt\'n nich\' hier sein!', 66263),
(93792, 'deDE', 'Euer Geist is\' von Stärke erfüllt!\n\nIhr könnt den Altar nutzen so oft Ihr möchtet. Aber Ihr könnt immer nur einen Segen auf einmal auf Euch haben.', 66263),
(92531, 'deDE', 'Das is\' wirklich \'ne Geistergeschichte!\n\nEs macht mich traurig, dass ich nich\' noch mal mit Sij\'ta sprech\'n kann un\' dass Kulzi seinen Loasprecher verlor\'n hat, aber es is\' schön, dass Sij\'ta endlich Fried\'n gefund\'n hat.\n\nIch werd\' mit Kulzi red\'n. Hoffentlich is\' er nich\' sauer.', 66263),
(93096, 'deDE', 'Das is\'n schändliches Schicksal für Kel\'vujo, aber eins, das er selbst gewählt hat.\n\nIhr, Hash\'ura, habt erneut Eure Stärke bewies\'n. \n\nHier, als Dank dafür, dass Ihr geholf\'n habt, die Schwachen un\' Unfähigen unter unser\'n Kriegern auszusortier\'n.', 66263),
(91563, 'deDE', 'Halazzi sagt, er hat Euch herbestellt, um zu helf\'n. Is\' das wahr, Hash\'ura?', 66263),
(91407, 'deDE', 'Die Spinnen ham die Flucht ergriff\'n? Ich hätt\' gedacht, sie würd\'n sich heftiger zur Wehr setz\'n. Un\' Ihr sagtet, sie wär\'n klein gewes\'n? Hm.\n\nTja, is\' ja auch egal. Halazzi hat uns jetzt auf diese Jagd geschickt. Wir müss\'n sie zu Ende bring\'n.', 66263),
(91406, 'deDE', 'All die Orte, die sie erwähnt ham, befind\'n sich in direkter Nachbarschaft zu Shadra\'Alor! Sie ham wahrscheinlich Shadra verehrt.\n\nWir dürf\'n ihnen nich\' trauen. Sie sin\' wie die Gifte, die sie verwend\'n. Sie werd\'n den Rest des Stammes gegen die Bruchhauer ausspiel\'n, gegen uns alle!', 66263),
(88989, 'deDE', 'Ihr habt dem Jungen das Leb\'n gerettet. Un\' vielleicht schaltet er jetz\' mal die Birne ein, bevor er losstürmt und \'ne Entscheidung trifft, die sein Leben beend\'n könnt\'.\n\nWenn wir das Oberhaupt des Sabotagerings ausschalt\'n, wird uns das Zeit verschaff\'n, um alle Waff\'n herzustell\'n, die wir brauch\'n.\n\nMeist\'ns fügt sich doch alles zum Best\'n, was? Sogar für Euch.\n\nHier is\' \'ne Kleinigkeit, die die Truppe un\' ich Euch geb\'n woll\'n.', 66263),
(88988, 'deDE', 'Hmm. Nicht schlecht. Für einen Neuling.', 66263),
(88987, 'deDE', 'Danke. Diese geborg\'nen Vorräte werd\'n uns dabei helf\'n, unsre Arbeit wieder in geregelte Bahnen zu bringen.\n\nAuch wenn dieser Elf immer noch in der Nähe is\'...', 66263),
(88986, 'deDE', 'Der Junge wirkt verwirrt.\n\nGut. Vielleicht bringt ihn das zum Nachdenk\'n.', 66263),
(88985, 'deDE', 'Noch\'n Fremdling, was?', 66263),
(93095, 'deDE', 'Ha! Hauerbrecher is\' tot!\n\nDie andern werd\'n uns jetz\' als wahre Amanikrieger seh\'n, wenn ich Ihnen sage, dass ich all die Trophä\'n mitgenommen hab, die Hauerbrecher getötet hat.', 66263),
(93094, 'deDE', 'Das sin\' mehr als genug!\n\nDie war\'n alle wirklich tot... wa?', 66263),
(93093, 'deDE', 'Das... das sin\' \'ne Menge Trophä\'n, Hash\'ura.', 66263),
(87317, 'deDE', 'Was is\' das für\'n Unsinn? Der Loasprecher darf weitermach\'n?\n\nDabei is\' alles seine Schuld!', 66263),
(87268, 'deDE', 'Ich wünschte, ich wüsst\', warum ich den Stab zerbroch\'n hab.\n\nIch glaub, es is\' an der Zeit, dass der Kriegsfürst sich seinen Erinnerungen stellt, so wie wir.\n\nAndernfalls bleib\'n wir für immer in dies\'m Fluch gefang\'n. Wir müss\'n uns erinnern, auch wenn wir nich\' woll\'n.', 66263),
(87267, 'deDE', 'Was bringt Ihr mir da?\n\n\'nen zerbroch\'nen Stab?', 66263),
(87256, 'deDE', 'Mit der Menge können wir den ganz\'n Kampftrupp heil\'n!', 66263),
(87254, 'deDE', 'Pah! Dieser Loa...\n\n<Loasprecher Sij\'ta spuckt auf den Boden.>\n\nNich\' mal das verbot\'ne Ritual heilt Akutu? Was für\'n Fluch is\' das?', 66263),
(91206, 'deDE', 'Was soll das heiß\'n, Ihr habt die Medizin nich\'? Ich hab Euch doch vor \'ner Ewigkeit losgeschickt!\n\nWir müss\'n ihm helf\'n... selbst wenn der Loa es nich\' tut!', 66263),
(93050, 'deDE', 'Meine Tage als Kämpfer lieg\'n hinter mir, aber ich freu\' mich, im Dorf helf\'n zu können.', 66263),
(91062, 'deDE', 'Gut, dass ich Euch sehe. Von Zul\'jarra weiß ich, dass Ihr hier nach Zul\'jan sucht. Allerdings ist mir die Gegend immer noch fremd...\n\nWenn Ihr ihn gefunden habt und genug von der Feier habt, sollten wir nach Silbermond zurückkehren.', 66263),
(86693, 'deDE', 'Es is\' mir gar nich\' in den Sinn gekommen, dass das, was wir feiern... ich sein würde.\n\nEs gab keinen Hash\'ey mehr unter den Amani seit dem Krieg zwischen Elfen und Menschen vor Tausenden von Jahr\'n.\n\nEs is\' \'ne große Ehre, aber ich bin nich\' sicher, ob ich sie mir bereits verdient hab.\n\nIch werde versuch\'n, ihr gerecht zu werd\'n.', 66263),
(86692, 'deDE', '<Zul\'jarra schnaubt und spuckt einen Schwall Blut aus. Ein abgebrochener Zahn ist auch dabei.>\n\nEs is\' so weit.', 66263),
(91001, 'deDE', 'Mor\'duun mag jetzt, versteckt im Sanktum, noch lachen können.\n\nAber nur wer zuletzt lacht, lacht am best\'n.', 66263),
(86686, 'deDE', 'Lor\'themar werden die Gesichtszüge entgleisen, wenn ich Bericht erstatte.\n\n<Ein leichtes Lächeln stiehlt sich auf Liadrins blutverschmiertes Gesicht.>\n\nDas allein wird meine Rüge wert sein.', 66263),
(86685, 'deDE', 'Das war gut.\n\nAber mich dürstet nach mehr.', 66263),
(86687, 'deDE', 'Der Anblick der Loa, die an ihrer Seite kämpf\'n, hat unsere Krieger mit Hoffnung erfüllt.\n\nSie erinnern sich daran, dass sie Amani sin\'!', 66263),
(86684, 'deDE', '<Zul\'jarras stechende Augen mustern das Schlachtfeld. Sie murmelt etwas vor sich hin, bei dem es sich wohl nur um Trollflüche handeln kann. Ihr hört unter anderem das Wort \"Jan\" herausstechen.>\n\nDas Schlachtfeld is\' voller Leichen. Denen meiner Leute. Aber es sin\' noch mehr von ihnen noch im Kampf!\n\nEs is\' noch Zeit, das Blatt zu wend\'n!', 66263),
(86683, 'deDE', 'Das wird \'nen Kampf!', 66263),
(91958, 'deDE', 'Ha.\n\nWir ham Nalorakk besiegt. Ham die letzte Prüfung bestand\'n.\n\nMein Stamm wird dies\'n Tag noch für viele Generationen besing\'n!', 66263),
(86682, 'deDE', 'Ich beneide Lilaju nich\'. Ich war ungefähr in ihrem Alter, als ich meinen Platz als Anführerin der Amani einnahm.\n\nIch bin stolz auf sie. Sie bleibt sich selbst und ihrem Stamm treu.\n\nSie gab uns, was wir brauchten. Und ich werde mein Versprechen ihr gegenüber nicht brechen und ihr weiter helf\'n.', 66263),
(86681, 'deDE', 'Ich liebe meinen Bruder. Wir sin\' wie Tag und Nacht. Aber als Kinder stand\'n wir uns sehr nah.\n\nZul\'jan is\' schlau, aber er versteht nich\'. Ein Sieg bedeutet nichts, wenn keiner mehr da is\', der ihn feiert.\n\nEr soll meine rechte Hand sein und keine Nervensäge.\n\nIch hoffe, Zul\'jan hat sich nich\' von mir abgewendet, weil ich ihn zu lange ohne Orientierung zurückgelass\'n hab.', 66263),
(86666, 'deDE', 'So viele Tote...', 66263),
(90772, 'deDE', 'Wir ham\'s geschafft, Hash\'ura.\n\nJan\'alai is\' wiedergebor\'n! Und wir ham ihren Seg\'n.\n\n<Zul\'jarra schließt die Augen und genießt für einen Moment die Hitze der Flamme auf ihrem Gesicht.>', 66263),
(86665, 'deDE', 'Wie passend. Beim letzten Test musste ich mich meinen Zweifeln stell\'n. Meiner Rolle als Anführerin und meinen Entscheidungen.\n\nEs fühlte sich gut an. Als ob die Zweifel hinwegschmelz\'n würd\'n.\n\nUn\' ich muss sagen... ich habe noch nie Flammen geseh\'n, die so fit und gutaussehend war\'n.\n\n<Zul\'jarra lacht trotz allem herzlich und klopft Euch auf die Schulter.>', 66263),
(86664, 'deDE', '<Zul\'jarra wischt sich Asche von der Schulter.>\n\nJan\'alais Flamme... Sie hat die Zweifel aus meinem Herzen genommen und ihnen \'ne Gestalt gegeb\'n.\n\nIch... war darauf nich\' vorbereitet.\n\nWas sie wohl sonst noch für mich bereithält?', 66263),
(86663, 'deDE', '<Zul\'jarra schaut zu, wie die Flammen in den Kohlen tanzen. Ein leichtes Lächeln stiehlt sich auf ihr Gesicht. Sie ballt die Fäuste und lässt ihre Muskeln spielen.>\n\nIch denke, diese Prüfung beginnt jetz\'.\n\nWas auch immer kommt... Ich bin bereit!', 66263),
(86808, 'deDE', '\"Reinige dich und es wird auferstehen.\"\n\n Ich hätt\' Zul\'jan mitbring\'n soll\'n. Er hatte es schon immer mit Rätseln.', 66263),
(86661, 'deDE', '\"Exzentrischer Loasprecher.\"\n\nHa. Das kommt mir bekannt vor. Die sin\' halt doch alle gleich.', 66263),
(92084, 'deDE', 'Halazzi sah zu, genau wie Akil\'zon, und wartete.\n\nEr hat die Bleichborken nie aufgegeb\'n.', 66263),
(86659, 'deDE', 'Die Suche nach Halazzi un\' den Schreinen der Hash\'ey hat mich Geduld gelehrt. Un\' mich gezwung\'n, meine Hürden mit Intelligenz zu überwind\'n, statt mir \'nen Weg durch sie hindurchzuschneid\'n.\n\nIch wünschte, Zul\'jan wär\' hier. Er wär\' stolz darauf, dass ich endlich etwas schlauer geword\'n bin. Ha.', 66263),
(86660, 'deDE', 'Deshalb also wollten die Blutfratzen die Bleichborken - um der Zwielichtklinge mehr Soldaten zu verschaff\'n.\n\nUntote Soldaten. Folgsame Soldaten.\n\nUnd wir ham schon zu viele verlor\'n.', 66263),
(86658, 'deDE', '<Zul\'jarra spuckt auf den Boden.>\n\nWiderwärtig. Sie verdienen es, noch hundertmal wiederbelebt un\' wieder getötet zu werd\'n.\n\nIch hoffe, dass der Loa, der sie im nächst\'n Leben erwartet, sie mit Haut un\' Haar verschlingt un\' zwischen seinen Backenzähnen zermahlt.', 66263),
(86657, 'deDE', 'Die Blutfratzen ham meinem Volk schon viel zu lang Leid zugefügt.\n\n<Zul\'jarra blickt zornig in Richtung des Blutfratzendorfs Maisara.>\n\nWir ham\'s lang genug hingenomm\'n. Jetz\' kommt die Abrechnung.', 66263),
(86809, 'deDE', '<Zul\'jarra hat die Augen geschlossen. Sie scheint in Gedanken versunken zu sein.>\n\nSie war\'n die ganze Zeit hier. Mein Großvater war schuld, dass sie nich\' geantwortet ham.\n\n<Sie nickt und seufzt.>\n\nMein Großvater hat das hier kaputt gemacht. Ich muss es reparier\'n. Es is\' der einzige Weg, mein Volk zu retten.', 66263),
(86656, 'deDE', 'Diese Stimme...\n\nIhr habt sie auch gehört, $n?', 66263),
(86654, 'deDE', 'Gut. Hoffentlich ist der Weg zu den Schreinen und zum Tempel damit für unsere Zwecke frei.', 66263),
(86655, 'deDE', 'Die Schreine sin\' erleuchtet.\n\nWas machen wir jetzt?', 66263),
(89334, 'deDE', '<Zul\'jarra packt einen der Köpfe am Schopf und bewundert Eure Handarbeit.>\n\nJetzt sprech\'n wir ihre Sprache. Jetzt wissen sie, dass die Amani stärker sin\'!\n\nFalls einige zurückbleiben, kümmern wir uns um sie, wenn wir die Zwielichtklinge besiegt ham.\n\nBehaltet die Köpfe. Ich habe später noch eine Verwendungsmöglichkeit für sie.', 66263),
(93049, 'deDE', 'Alles in perfektem Zustand!\n\nVielleicht solltet Ihr stattdess\'n Lehrling sein.', 66263),
(93048, 'deDE', 'Das Bürschchen muss noch viel üb\'n, aber Ihr habt ihm geholf\'n, mal den Kopf freizukrieg\'n un\' ein Gespür für den Rhythmus zu krieg\'n.', 66263),
(92167, 'deDE', 'Der Anführer war ein Kobyss? Was ist ein Kobyss?\n\nIch meine... gut gemacht, Champion! Ihr habt Eurem Loa gut gedient.\n\nJetzt, da diese Murlocs sicher sind, ist es Zeit für uns, zu gehen.', 66263),
(92166, 'deDE', 'Ihr habt sie gefunden! Danke! Ähm, ich meine... Ihr habt die Gunst des Loa der Murlocs, Champion.', 66263),
(92165, 'deDE', 'Werdet $uZeuge:Zeugin; der Macht meines Champions! Füllt Eure Mägen und lasst Euren Hunger hinter Euch!', 66263),
(92164, 'deDE', 'Seid Ihr fertig?\n\n<König Mrgl-Mrgl räuspert sich, als er sieht, wie einer seiner \"Anhänger\" ihn misstrauisch mustert.>\n\nIch meine, es ist erledigt. Die Tiefenflossen werden uns nicht mehr plagen!', 66263),
(91556, 'deDE', 'Ich hoffe, damit findet sein Geist Fried\'n. Un\' meiner.', 66263),
(91071, 'deDE', 'Ich hab geseh\'n, wie die Kleinen panisch davongerannt sin\'. Gut gemacht, $C.', 66263),
(91070, 'deDE', 'Gut. Das war alles.', 66263),
(91069, 'deDE', 'Hört Ihr das?\n\nEs ist ruhig.\n\nDas is\' der Klang der Rache.', 66263),
(94867, 'deDE', 'Vakala hat Euch geschickt? Sie hatte recht damit, dass dieser Ort gefährlich is\'.', 66263),
(92453, 'deDE', 'Hey, $n! Ich bin vom Wasserfall runtergesprung\'n un\' hab \'ne große Echse getötet!\n\nIch weiß, dass Ihr geholfen habt.\n\nJynx hat auch geholf\'n.\n\nDanke!', 66263),
(92452, 'deDE', 'Ich war nicht sicher, wie lange ich es noch hier draußen aushalten würde. Mir gingen die Steine aus!', 66263);
INSERT INTO `quest_offer_reward_locale` (`ID`, `locale`, `RewardText`, `VerifiedBuild`) VALUES
(92451, 'deDE', '<Anis Tasche mit liebgewonnenen Schmuckstücken liegt leer am Sumpfufer und sinkt bereits in den Schlamm ein.>', 66263),
(92450, 'deDE', 'Seht Ihr? Es ist ein weiter Weg bis ganz nach unten.', 66263),
(93047, 'deDE', 'Ihr seid $uein beeindruckender Jäger:\'ne beeindruckende Jägerin;, das is\' sicher. Danke, dass Ihr uns hier geholf\'n habt.', 66263),
(89560, 'deDE', 'Danke, dass Ihr uns auf dieser Reise beigestand\'n habt, $p.\n\nIch hatte nich\' gedacht, dass Iz\'ken kommen würde, un\' er dachte, er wär nich\' willkommen.\n\nIch glaub, Iz\'ken un\' mir is\' jetzt was klar geword\'n... Das schlimmste Vergeh\'n unsrer Mutter bestand darin, uns gegeneinander auszuspiel\'n.', 66263),
(89559, 'deDE', 'Die andern im Stamm verehr\'n Mutter noch un\' trauern über ihr\'n Tod.\n\nAber seit sie gestorb\'n is\', vermisse ich hauptsächlich Iz\'ken.\n\nSie hat meinen Bruder vertrieb\'n.\n\nAber... ihr Tod hat ihn zurückgebracht. Zumindest für dieses Ritual.', 66263),
(89513, 'deDE', 'Kan\'sha is\' \'ne alte Freundin, un\' ich verbring viele Nächte hier unter ihrem Geäst, wenn ich nich\' nach Hause kann.\n\nUnser Stamm warnt die Leute vor ihren fallenden Zweig\'n, aber mich hat nie einer getroff\'n. Keine Narbe oder Schramme stammt von ihr.', 66263),
(89506, 'deDE', 'Als Iz\'ken uns verlass\'n hat, dachte ich zuerst, es wär Mutter egal. Selbst auf ihrem Totenbett hat sie ihn nich\' einmal erwähnt.\n\nAber sie fühlte sich schuldig, als er ging. Ihre Wutausbrüche mir gegenüber war\'n Ausdruck dieser Scham, denke ich.\n\nIch wünschte, sie hätt\' sich das eingestand\'n, aber ich wusste, dass das nie passier\'n würde.\n\nUnser Stamm hält Mutter für unaufhaltbar... furchtlos.\n\nAber manchmal is\' es das, was in uns is\', was uns am meisten Angst macht.', 66263),
(89503, 'deDE', 'Ich hab Euch um Hilfe gebeten, ohne Euch zu sag\'n, wie meine Mutter meinen Bruder un\' mich behandelt hat. Ich red\' kaum über meine Familie. Hab ich mir abgewöhnt.\n\nIch versteh\' immer noch nich\', warum sie war, wie sie war. Vielleicht is\' ihr was zugestoß\'n. Etwas, das all dies\'n Schmerz verursacht hat... Vielleicht kannte sie selbst nur Schmerz un\' Chaos.\n\nSie hat viele im Stamm inspiriert... wenigstens für die kann sie \'ne Mutter bleib\'n.', 66263),
(89565, 'deDE', 'Mein junger Bruder hat uns verlass\'n, als ich gerad erwachs\'n wurde.\n\nEr hat gesagt, er kommt und hilft, aber... wir sin\' nich\' im Guten auseinandergegang\'n.\n\nAber er is\' da. Nach all der Zeit.', 66263),
(93051, 'deDE', 'Ihr habt gut gekämpft.\n\nEure eigne Stärke hat bewies\'n, dass Dar\'rak sich geg\'n weit stärkere Krieger behaupt\'n kann.\n\nIch hab nie erwartet, dass er Euch schlägt, $n. Aber dass er noch atmet, is\' schon \'ne beachtliche Leistung, was?', 66263),
(92398, 'deDE', 'Der Runenstein summt dank Euch wieder vor Macht. Ihr habt meine Anerkennung.', 66263),
(92397, 'deDE', 'Gute Arbeit. Jetzt kommt der schwere Teil.', 66263),
(92396, 'deDE', 'Ah, Ihr seid es, $gder:die; das Material gebracht hat. Habt Dank! Die Zauberschutze sind jetzt stabil. Allerdings gibt es da eine weitere Aufgabe, die Eure Aufmerksamkeit erfordert.', 66263),
(91385, 'deDE', 'Die Legenden sind wahr... Immersang muss mit uns zufrieden sein!', 66263),
(91383, 'deDE', 'Meine Waldläufer verdienen sich heute ihren Platz, so viel steht fest.', 66263),
(91384, 'deDE', 'Das ist ein guter Anfang. Es braucht nur eine Handvoll Leute, die sich ein wenig bemühen.', 66263),
(91350, 'deDE', 'Das passiert, wenn niemand fegt!\n\nAlle wollen Abenteuer erleben, aber niemand will fegen.', 66263),
(91137, 'deDE', 'Unsere Gäste zu quälen, ging einen Schritt zu weit.\n\nSie hat dem Sonnenbad geschadet und den Preis für ihre Taten bezahlt.\n\nIch danke Euch, $gneuer Freund:neue Freundin; der Familie Solaar!', 66263),
(91090, 'deDE', 'Das war doch gar nicht so schlimm, oder?\n\nVal ist immer so dramatisch, aber Ihr habt das wunderbar gemacht.', 66263),
(91328, 'deDE', 'Magie! Perfektion! Ihr könntet nicht talentierter sein, hätte ich Euch ins Leben gewünscht.\n\nDas ist ein interessanter Gedanke. Hätte ich das können?', 66263),
(91271, 'deDE', 'Gut gemacht, $n! Ihr habt einen perfekt pummelig proportionierten präferierten pescatarischen Preis beschafft!\n\nWelch freudiger Tag!', 66263),
(92025, 'deDE', 'Meine Güte! Das war beinahe ein großes Missverständnis. Ich bin froh, dass Ihr Eure Waffen lange genug stecken gelassen habt, um mich anzuhören.\n\nDie Geißel hat den Sin\'dorei viel genommen. Einigen von uns, wie Amalthea, hat sie alles und noch mehr genommen.\n\nEs versteht sich von selbst, dass meine Studien mir nicht gerade viele Freunde einbringen. Aber sie erlauben es mir hin und wieder, Amaltheas Qualen zu lindern. Dafür würde ich jede Demütigung ertragen.', 66263),
(92024, 'deDE', '<Eure Erkenntnisse lassen nur wenig Interpretationsspielraum. Welche offiziellen Unternehmungen Talandra angeblich auch immer verfolgt, ihre persönlichen Neigungen deuten auf eine deutlich zwielichtigere Tätigkeit hin.>', 66263),
(92023, 'deDE', 'Ihr tragt da einen interessanten Beutel voller Waren mit Euch herum. Ich hoffe mal, dass Ihr nicht im Auftrag der \"Apothekerin\" im Windläuferdorf Einkäufe tätigt?\n\nIhr solltet dieses Vorhaben möglicherweise noch einmal überdenken, wenn Euch Euer Wohlergehen am Herzen liegt.', 66263),
(92022, 'deDE', 'Das hätten wir. Seht Ihr? Ich wusste, dass ich mich auf Euch verlassen kann. Jetzt fehlen nur noch ein paar letzte Schritte.', 66263),
(92021, 'deDE', 'Da habt Ihr es! Acht Blumen. Ein Kinderspiel, möchte man meinen! Jetzt brauche ich nur noch ein paar Dinge...\n\nWas? Ich habe mit keinem Wort eine Einkaufsliste erwähnt? Na so was aber auch. Tja, da kann man jetzt wohl nichts mehr machen, hm? Ihr wirkt nicht wie jemand, der die Dinge nur halbherzig angeht.', 66263),
(91349, 'deDE', 'Diese armen Jungtiere... Sie haben nur dank der Gnade dieser seltsamen Magie überlebt!\n\nIch weiß es besser, als an die alten Märchen zu glauben... aber was könnte es sonst sein?', 66263),
(91463, 'deDE', 'I-Ich mache mir keine Sorgen. Das gehört zum Leben eines Weltenwanderers dazu!', 66263),
(91348, 'deDE', 'Schon wieder eine erfolgreiche Häutung... In ein paar Wochen kommen wir wieder, um beim nächsten Mal zu helfen!', 66263),
(91462, 'deDE', 'Es ist gut, dass wir gekommen sind. Hier gibt es mehr Manawyrms als gewöhnlich.', 66263),
(91347, 'deDE', 'Ich weiß nicht, was wir von diesen großen Blüten halten sollen... Aber was auch immer wir tun, das Land scheint zufrieden zu sein.', 66263),
(91345, 'deDE', 'Ich hoffe, Ihr habt nichts dagegen, Euch die Hände schmutzig zu machen.', 66263),
(91389, 'deDE', 'Es ist ein wunderschönes Stück. Ich bin froh, dass es jemandem gehört, der es so sehr liebt.', 66263),
(91388, 'deDE', 'Ah... wunderschöne, funkelnde Manaseide. So voller Potenzial.', 66263),
(92408, 'deDE', 'Es gibt keine Manaseide von besserer Qualität in ganz Immersang, oder irgendwo auf der Welt.', 66263),
(91301, 'deDE', 'Ah... der Junge hat sich also endlich entschieden. Er hat ein großes Herz. Zu groß vielleicht.\n\nJa. Wir werden das vermerken und ehren. Ihr habt mehr getan, als eine Nachricht zu überbringen. Ihr habt geholfen, ein Leben zu formen. Danke.', 66263),
(91284, 'deDE', 'Wow... ich kann kaum fassen, dass ich alle drei Empfehlungen bekommen habe. Sie haben alle so nette Dinge gesagt, aber jetzt bin ich noch mehr hin- und hergerissen!\n\nGlaubt Ihr... Ihr könntet mir helfen, mich zu entscheiden?', 66263),
(91292, 'deDE', 'Hmm, Ihr scheint doch talentierter zu sein, als ich erwartet hatte.\n\nDieser Stab ist angemessen aufgeladen. Gut gemacht. Obwohl ich sicher bin, dass Ihr kaum ins Schwitzen gekommen seid.\n\nNehmt diese Empfehlung, aber denkt immer daran: Das Arkane verlangt Respekt, nicht nur Macht.', 66263),
(91288, 'deDE', 'Seht Euch das an. Saubere Schnitte, keine Sauerei... Vielleicht steckt in dem Kleinen mehr Feuer, als ich dachte.\n\nHier, nehmt diese Empfehlung. Sagt ihm, ein Weltenwanderer vergisst niemanden, der sich seinen Platz verdient hat. Und er soll seine Klinge scharf halten. Wir beobachten ihn.', 66263),
(87002, 'deDE', 'Heute mögt Ihr mich geschlagen haben, doch seid gewarnt... Ich werde mich wieder erheben und Ihr werdet es bereuen, Euch mit mir angelegt zu haben. Ich bin Tytalor Goldklinge und diese Niederlage ist nur von kurzer Dauer!', 66263),
(86998, 'deDE', 'Ich muss gestehen, ich habe Euch unterschätzt. Ihr leistet wohl doch mehr als ziellos um Euch zu schlagen.', 66263),
(86997, 'deDE', 'Schockierend. Wahrlich schockierend. Vielleicht sind die Gerüchte um Euch doch wahr. Aber nur vielleicht.', 66263),
(94396, 'deDE', 'Was bin ich doch talentiert!\n\n<Tytalor scheint in Gedanken versunken zu sein.>', 66263),
(91291, 'deDE', 'Beeindruckend! In Euch steckt mehr, als ich erwartet hatte.\n\nIhr habt Eure Stärke, Ehre und Überzeugung unter Beweis gestellt. Qualitäten, die jeder Blutritter besitzen muss.\n\nNehmt diese Empfehlung und tragt sie mit Stolz. Der Orden ist immer auf der Suche nach würdigen Kandidaten.', 66263),
(94393, 'deDE', 'Ausbilder Thalendir hat Euch geschickt?! Ich werde mich wohl bei ihm entschuldigen müssen.\n\nAber ich bin froh, dass Ihr da seid. Würdet Ihr mir kurz zuhören?', 66263),
(90821, 'deDE', '\"Schwarzschauer\"? Zaens Operationsbasis vielleicht. \n\nAuf diesem Beleg steht etwas von Suramar. Sie müssen die Teufelsrelikte von den Verheerten Inseln plündern und dann über eine unverdächtige Handelsroute nach Silbermond schaffen.\n\nClever.', 66263),
(89208, 'deDE', 'Es war mir ein Vergnügen, mit Euch zusammenzuarbeiten, $n.', 66263),
(89207, 'deDE', 'Die Mördergasse wird immer in Gefahr sein, solange Silbermond wegschaut.\n\nAber fürs Erste sind wir ein wenig sicherer. Gut, dass wir ihn los sind.', 66263),
(89206, 'deDE', '<Jaeth sucht an Sarvis Hals nach einem Puls und seufzt dann wütend.>\n\nSie ist bereits tot. Ich kenne ihren Bruder. Ich werde dafür sorgen, dass sie zu ihm zurückgebracht wird.\n\nDoch zuerst lassen wir Aradis bluten.', 66263),
(89205, 'deDE', 'Ich wäre überrascht, wenn sich Aradis nicht längst hier verschanzt hat. Wir werden ihn sicher bald sehen.\n\nDerart aufwendige Zauberschutze haben immer Alarme.', 66263),
(89204, 'deDE', 'Sauber und ordentlich. Ich stehle schon seit meiner Kindheit, um über die Runden zu kommen, aber ich habe nicht oft Komplizen.', 66263),
(89203, 'deDE', 'Er hat letzte Woche auch versucht, mich zu erwischen. Ich habe ihm ein Messer in den Bauch gerammt, bevor er weggerannt ist.\n\nIch bin ihm nach, aber sein Unterschlupf unten am Hafen war mit Teufelsmagie geschützt. Wenn Morgenlohe einen Weg hinein kennt, erledige ich ihn nur zu gern.', 66220),
(89202, 'deDE', 'Ich nehme an, Ihr habt ein ganz bestimmtes Anliegen, wenn Ihr mich namentlich sucht. Also, raus mit der Sprache.', 66220),
(89201, 'deDE', 'Ihr solltet vorsichtiger sein, in welche Angelegenheiten Ihr Euch verwickeln lasst.', 66220),
(92870, 'deDE', 'Kleiner Ausreißer! Willkommen zurück, du pelziger Tunichtgut. Ich danke Euch, Champion. Ich werde ihn schnellstens zum Café zurückbringen.\n\nWas die Abrichtung angeht... Ich glaube, ich bleibe lieber beim hiesigen Luchs. Der hat weitaus bessere Manieren.', 66220),
(90819, 'deDE', 'Sie haben jemanden namens Zaen erwähnt?\n\nEr ist ein berüchtigter Gauner in der Gasse. Teufelsmagie über den Hafen von Silbermond einzuschmuggeln klingt ganz nach ihm. Er will nicht, dass ihn jemand beobachtet.\n\nGut, dass Ihr die Frachtliste an Euch gebracht habt.', 66220),
(89200, 'deDE', 'Wie erwartet, hat sich meine Theorie bestätigt.\n\nDie letzte Aufgabe besteht nun darin, den letzten Schutz zu brechen und Morgenlohe diese Dokumente abzunehmen.', 66220),
(89199, 'deDE', 'Sich nützlich zu machen, ist eine hochgeschätzte Eigenschaft in Silbermond. Ihr seid auf einem guten Weg.', 66220),
(90669, 'deDE', 'Ah, also war der Raufbold erfolgreich.\n\nIhr seht in der Tat fähig aus. Lasst uns reden, ja?', 66220),
(90837, 'deDE', 'Hm... Lumpen der Legion, Teufelsstaub und Hinweise, dass beides heimlich durch die Stadt transportiert wurde. Eine sanktionierte Handelsoperation mit Teufelsmagie würde nicht auf solche Maßnahmen zurückgreifen.\n\nDann sind da noch diese Manawyrmkerne, die wir beide gefunden haben. Ausgelaugt, aber immer noch teufelsberührt.', 66220),
(90818, 'deDE', '<Belaths Blick verfinstert sich stärker als üblich.>\n\nAngst verleitet die Leute zu verzweifelten Taten, aber Teufelsmagie ist keine Waffe, die man leichtfertig führen sollte.\n\nDiese Macht hat einen Preis. Doch sie können ihn weder verstehen, noch sind sie dafür ausgebildet, diesen Gefahren zu trotzen.', 66220),
(90835, 'deDE', 'Ihr kommt genau rechtzeitig.\n\nIch fasse mich kurz: Ich glaube, in Silbermond wird wieder vermehrt Teufelsmagie gebraucht. Und das muss aufhören.', 66220),
(91386, 'deDE', 'Na gut... aber nur, weil die Kunstfertigkeit mich neugierig macht.\n\nAber es wird mehr als etwas Höflichkeit brauchen, um meine Meinung über diese parasitären Paladine zu ändern.', 66220),
(92869, 'deDE', 'Eure Methoden waren... interessant, aber ich kann die Ergebnisse nicht leugnen. Die Sonnenbärte wurden einer Menge Stress ausgesetzt. Aber jetzt, wo sie wieder im Wasser sind, sollten sie sich schnell erholen. Ich danke Euch.', 66220),
(92868, 'deDE', 'Ein Hund? Ja, ich habe einen Hund gesehen. Schaut Euch doch nur mal an, was dieses Monster am Teich getan hat!', 66220),
(92728, 'deDE', 'Danke für Eure Hilfe! Um den Rest sollten sich meine Schüler nach ein paar schnellen Lektionen selbst kümmern können. Wir nennen es einfach eine Lernmöglichkeit.', 66220),
(92729, 'deDE', 'Ein Hund? Ja, ich habe einen Hund gesehen. Schaut Euch doch nur mal um! Seht, was er angerichtet hat!', 66220),
(87458, 'deDE', 'Danke, dass Ihr uns geholfen habt, das hier zum Abschluss zu bringen, $p. Der Wert dieser Halskette sollte unsere alte Zeche problemlos decken.\n\n<Tarenar wirft Gidwin einen Seitenblick zu.>\n\nGiddy hat Euch keine allzu großen Umstände bereitet, oder?', 66220),
(93372, 'deDE', 'Gute Arbeit und gute Reise.', 66192),
(87402, 'deDE', 'Was hinter diesen Türen lag, war der reinste Schrecken. Das Licht auf diese Weise zu missbrauchen...\n\nDanke. Wir werden diesen Ort mit Feuer reinigen, bevor er wieder genutzt wird.', 66192),
(87400, 'deDE', 'Ich sorge dafür, dass das hier einem Hauptmann zukommt. Und dass es ordnungsgemäß gelagert wird und sich nicht ausbreitet.', 66192),
(87401, 'deDE', 'Perfekt. So sollten wir ins Hauptgebäude gelangen.', 66192),
(87399, 'deDE', 'Es ist eine undankbare Aufgabe, aber diese Kreaturen gehören hier nicht hin. Sie hätten alle neuen Forscher in Gefahr gebracht.\n\nAber nun zum eigentlichen Problem.', 66192),
(91504, 'deDE', 'Der Leuchtturm selbst hat sich durch die zunehmenden arkanen Energien aufgelöst, sowohl ruhend als auch angesammelt. Wie ominös. Ich werde sofort einen Bericht für Lordregent Lor\'themar verfassen.\n\nDank Euch sind meine Waldläufer und auch die Stadt sicher. Trinkt darauf und gönnt Euch eine Pause.\n\n... der Zauberstab ist explodiert?! Jetzt wissen wir wohl, warum er weggeworfen wurde.\n\nWisst Ihr, ein Bogen würde nie spontan in Flammen aufgehen.', 66192),
(91494, 'deDE', 'Man könnte sagen, ich hatte eine Ahnung, was diesen Zauberstab angeht.\n\nAber seid vorsichtig. Er ist jetzt aufgeladen. Lasst ihn bloß nicht fallen.', 66192),
(91505, 'deDE', 'Ihr habt diese Wasserschlängler das Fürchten gelehrt! Gut gemacht.\n\nWir werden ihre Basis im Auge behalten und sie am Wiederaufbau hindern.', 66192),
(91495, 'deDE', 'Ich bin erleichtert, dass sie sicher und wohlauf sind. Ich hoffe, Varnis erholt sich bald. Ich habe gesehen, wie er zurückkam. Er war leichenblass und weigerte sich zu sprechen. Er hat seine sieben Sachen gepackt und ist gegangen.\n\nDanke, $p. Ich hoffe, es kommen nicht noch mehr Dorfbewohner auf die Idee, die Basis der Naga zu betreten!', 66192),
(91493, 'deDE', 'Lyssaras Verdacht war korrekt. Die Naga haben Arkanmagie aus Quellen im gesamten Immersangwald gesammelt. Wir müssen dem ein Ende machen, und zwar schnell.', 66192),
(87392, 'deDE', 'Ah, ein Vermerk über \"besondere Fracht\". Wie entzückend subtil. Etwa so unauffällig wie das Feuerwerk eines Goblins.\n\nEs scheint, dass die Spedition Tidentreib in diese Angelegenheit verstrickt ist. Uns bleibt kaum eine Wahl, als ihnen nachzuspüren. Wenn das bedeutet, in die Tiefen zu tauchen, dann sei es so.', 66192),
(86653, 'deDE', 'Dieser Pfad wimmelt vor Knardin.\n\n<Zul\'jarra grinst breit.>\n\nIch hoffe, sie versuchen uns aufzuhalt\'n. Ich kann meine Klinge an ihren Knochen schärfen.', 66192),
(86652, 'deDE', 'Hash\'ey? Hat Onkel den Verstand verlor\'n?\n\nDas is\' ein Märchen für Kinder. Vielleicht wenn das hier die alten Zeiten wären, vor Generationen, bevor die Elfen kamen...\n\nAber wenn es unsre letzte Chance is\', die Loa um Hilfe zu bitt\'n, dann versuch ich das.', 66192),
(86723, 'deDE', 'Es gibt... viel, was Ihr nich\' über uns un\' die Loa wisst.', 66192),
(86722, 'deDE', 'Tokobo\'ne na Amani\'zar, $n. Willkommen in Amani\'zar.\n\nDa Ihr meine Gäste seid, werd\'n meine Leute Euch nich\' angreif\'n. Außer ich befehle es.\n\nGebt mir keinen Grund dazu, ja?', 66192),
(86720, 'deDE', '<Zul\'jarra kocht vor Wut.>\n\nMor\'duun spielt mit uns. Er hätte bleiben und die Stadt vollständig zerstör\'n können.\n\nFalls Chaos zum Plan der Zwielichtklinge gehört, müssen wir vorbereitet sein.', 66192),
(86712, 'deDE', 'Die Truppen, die wir bewaffnet ham, töteten viele von der Zwielichtklinge.\n\nEinige ham überlebt und es hierher geschafft.\n\nWir ham ein paar verlor\'n, aber ich glaube, es war das Opfer wert.', 66192),
(86718, 'deDE', 'Als Nächstes wird Mor\'duun fallen.', 66192),
(86715, 'deDE', 'Das sollte sie zumindest kurzzeitig aufhalten.', 66192),
(86716, 'deDE', 'Gut.\n\nJetz\' ham wir Zähne, mit denen wir zurückbeißen können.', 66192),
(86721, 'deDE', 'Wir ham so viel davon verlor\'n...\n\nWir hätten den Himmel mit Ballistenbolz\'n verdunkeln können!\n\nAber das hier könnte dennoch ausreichen. Es muss einfach!', 66192),
(86719, 'deDE', 'Adler... Loa... Wir ham keine Zeit, uns mit den Geistern der Vergangenheit abzugeb\'n.', 66192),
(86717, 'deDE', 'Ihr habt den Weg freigemacht, aber Mor\'duun sorgt weiter dafür, dass wir abgelenkt un\' durcheinander bleib\'n.\n\nWir brauch\'n so viele Lichtholzwaffen wie möglich, um dem ein Ende zu mach\'n.', 66192),
(86868, 'deDE', 'Zul\'jarra ist Euer Kampfgeschick aufgefallen.\n\nGut.\n\nDemonstrieren wir weiterhin unsere Nützlichkeit. Wenn sie uns jetzt aus ihrem Land verjagen, haben wir keine Möglichkeit, die Zwielichtklinge weiter zu beobachten, bis sie sich durch die Tore nach Immersang ergießen.', 66192),
(86711, 'deDE', 'Viele Amani ham sich hier eingefund\'n, aber es gibt noch mehr, die Hilfe brauch\'n.\n\nUn\' sogar noch mehr Feinde zu töt\'n.', 66192),
(90749, 'deDE', 'Ich muss sagen, ich bin... überrascht, dass Zul\'jarra uns Zugang gewährt hat. Es ist viele Jahre her, seit ich oder jemand anderes aus Immersang einen Fuß auf diese Seite der Grenze gesetzt hat.\n\nBleibt wachsam. Diese Situation ist ein Pulverfass. Wir müssen möglicherweise mehr tun, um ihr Vertrauen zu gewinnen.\n\nAber dreht den Amani ja nicht den Rücken zu.', 66192),
(86710, 'deDE', 'Ich bin erleichtert ob der Feststellung, dass Zul\'jan nicht der Anführer der Amani ist.\n\nDoch diese \"Zul\'jarra\" könnte schlimmer sein.\n\nEgal. Wir müssen auf die andere Seite dieses Tores gelangen und herausfinden, welche Bedrohung die Zwielichtklinge für Immersang darstellt.', 66192),
(86708, 'deDE', 'Unser Waffenstillstand ist fragil, doch er hält an. Noch.', 66192),
(91787, 'deDE', 'Danke, $p, dass Ihr unsere Verteidiger am Sonnenbrunnen unterstützt habt.\n\nArator scheint seine Antworten gefunden zu haben und bereit für das zu sein, was kommen mag. Es ist gut, dass Ihr beide Euch erneut dem Kampf gegen die Leere widmet.\n\nArator ist ein guter Mann. Ich bin dankbar, dass wir ihn nicht an diesen Konflikt verloren haben.', 66192),
(86903, 'deDE', 'Was für eine Reise, $p.\n\nIch habe viel von Alonsus und den Söhnen Lothars gelernt...\n\nAber die wichtigste Erkenntnis war, was für eine Art von Paladin mein Vater war und welche Art von Paladin ich von jetzt an sein werde.', 66192),
(86833, 'deDE', '$p, das lief nicht so, wie ich mir das vorgestellt hatte.\n\nIch hatte gehofft, er würde zu der Einsicht kommen, dass er sich immer noch ändern kann.\n\nAber es sieht nicht so aus, als wäre er bereit dafür. Zumindest noch nicht.', 66192),
(86832, 'deDE', 'Wir haben auf jeden Fall etwas Gutes in der Brennenden Steppe bewirkt, $p. Und wir haben die Fragmente von Turalyons Schild bergen können.\n\nArator scheint sich darauf zu freuen, ihn neu zu schmieden.', 66192),
(91726, 'deDE', 'Es ist eine traurige Geschichte. Aber vielleicht lässt sich mit den Überresten von Turalyons Schild doch noch was Gutes daraus machen.\n\nVielleicht kann er neu geschmiedet werden, und vielleicht kann auch unser Freund geheilt werden.', 66192),
(86829, 'deDE', 'Gut möglich, dass diese Fragmente, die Ihr gesammelt habt, das Wertvollste an unserer gesamten Mission sind, $p.', 66192),
(86830, 'deDE', 'Ihr habt viele von ihnen getötet, und mehr noch haben die Flucht ergriffen.\n\nHoffen wir, dass sie nie wiederkommen.', 66192),
(86831, 'deDE', 'Ausgezeichnet, $p! Damit haben wir viele Leben in der Region gerettet. Ohne Kriegsherrin sollte die Dunkle Horde schnell zerfallen.', 66192),
(86828, 'deDE', '$p, Arator, gut, Euch zu sehen. Ich glaube, ich habe eine Lösung für unser Problem.', 66192),
(86826, 'deDE', 'Habt Ihr Faols Relikt?\n\nIch hoffe, dieser alte Priester weiß, was er tut.', 66192),
(91842, 'deDE', 'Habt Ihr die Waffenständer zerstört?\n\nSehr gut, das reicht. Wir haben allen in der Nähe einige Monate Frieden erkauft, während sie wieder aufstocken müssen.', 66192),
(86827, 'deDE', 'Das nenne ich einen ordentlichen Tritt in den Hintern!\n\nSchaut mal, ob nach dieser Blamage jetzt noch jemand bereit ist, seine Kriegsmeute anzuführen!', 66192),
(91391, 'deDE', 'Arator, $p, vielen Dank, dass Ihr gekommen seid. Da drinnen wimmelt es von Anhängern der Dunklen Horde.', 66192),
(86825, 'deDE', 'Mit jedem Anführer, den wir ausschalten, bröckelt der Einfluss der Dunklen Horde in der Brennenden Steppe weiter.\n\nMar\'kag war der Erste, der fiel. Es war ein guter erster Schritt.', 66192),
(86824, 'deDE', 'Ich hoffe, das wird zumindest einigen ihre törichte Treue zu einer verlorenen Sache austreiben.\n\nUnd selbst wenn nicht: Ich bin froh, dass diese Banner endlich nicht mehr wehen.', 66192),
(86823, 'deDE', 'Vielleicht bringt der Tod ihrer Kameraden die anderen zur Vernunft, so wie einst mich. Wenigstens können die, die du getötet hast, sich nun nicht länger selbst entehren.', 66192),
(86822, 'deDE', 'Wie mir scheint, gibt es hier mehr für uns zu tun als nur ein Relikt zu finden.\n\nDas Gebiet wird von einer Gruppe überrannt, die sich die \"Dunkle Horde\" nennt. Wir werden ihren Machenschaften ein Ende setzen.', 66192),
(89338, 'deDE', 'Hervorragend, $p. Wir werden die Waffen zu Werkzeugen umschmieden und an die Leute verteilen.', 66192),
(86846, 'deDE', 'Ausgezeichnet! Das wird den Leuten in Hammerfall eine große Hilfe sein.', 66192),
(91000, 'deDE', 'Gute Arbeit, $p. Hier sieht es allmählich wieder besser aus.', 66192),
(86845, 'deDE', 'An\'she hat Euch zu uns geführt, $p. Werdet Ihr uns bei unserer Arbeit unterstützen?', 66192),
(86902, 'deDE', 'Mit diesen Relikten sollten sie deutlich länger in der Lage sein, das Ritual aufrechtzuhalten.\n\nUnd wir können uns inzwischen anderen Dingen widmen.', 66192),
(92136, 'deDE', 'Schnell, $p. Beginnen wir mit der Verteilung!', 66192),
(86843, 'deDE', 'Hervorragende Arbeit.\n\nWer weiß, vielleicht wird das Scharlachrote Kloster eines Tages ein Ort sein, der dem Licht wahrhaftig dient. Doch momentan ist unsere Zeit knapp und unsere Aufmerksamkeit muss dem Sonnenbrunnen gelten.', 66192),
(86844, 'deDE', 'Diese Waffen des Lichts werden von diesem Tage an einem viel größeren Zweck dienen.\n\nIch hoffe, dass das auch für Aelyse gilt: diesem Champion des Scharlachroten Kreuzzugs, dem Arator Barmherzigkeit gewährt hat.\n\nIch sagte ihr, sie solle damit beginnen, sich Calia Menethil beim Sonnenbrunnen zu ergeben.', 66192),
(86842, 'deDE', 'Da wären wir. Kümmern wir uns um die Scharlachroten.', 66192),
(86841, 'deDE', 'Ich hoffe, Ihr habt gefunden, was Ihr sucht, $p?', 66192),
(86840, 'deDE', 'Danke, $p. Ihr habt ihre Reihen gelichtet, sodass wir die Verteidigung mithilfe unserer... Verbündeten aufrechterhalten können.\n\nFaol hat mir inzwischen erzählt, dass Ihr bestimmte Relikte benötigt.', 66192),
(86839, 'deDE', 'Willkommen in der Kapelle des Hoffnungsvollen Lichts, $p. \n\nDie meisten Paladine, die diesen Ort verteidigt haben, wurden vom Licht abberufen. Ich musste mich an die Schwarze Klinge wenden, sonst hätte die Geißel diesen heiligen Boden längst überrannt.', 66192),
(86838, 'deDE', 'Ich hatte gehofft, der Anblick der anderen, wie sie sich ganz auf das Ritual am Sonnenbrunnen konzentrieren, würde ihm vor Augen führen, dass es etwas Größeres gibt als seinen Schmerz... und ihn von seinem Zorn abbringen. Aber nein, er redet meine Lösung klein.\n\nDanke, $n, dass Ihr die Aufgabe für ihn übernommen habt. Anders hätten wir den Leerensturm nicht in Schach halten können.', 66192),
(86837, 'deDE', 'Argghh... Ist das hell hier!\n\nAh, Ihr konntet ihn überzeugen! Ich danke Euch.', 66192),
(89193, 'deDE', 'Danke, dass Ihr gekommen seid, $p. Ich benötige Eure Hilfe... und viele unserer Priester und Paladine ebenfalls.\n\nEin Paladin insbesondere.', 66192),
(86650, 'deDE', 'Ich wünschte, ich könnte mich Euch anschließen, aber hier in Silbermond gibt es noch zu viel zu tun. \n\nIhr habt Eure Ziele. Wir bleiben in Kontakt. \n\nWegen Arator... Ich hoffe, Ihr findet ihn bald. Anu belore dela\'na, $p.', 66192),
(86649, 'deDE', 'Das... hatte ich nicht erwartet.\n\n<Lor\'themar wirft einen Blick auf Turalyon.>\n\nVielleicht sind wir zu weit gegangen.', 66192),
(86648, 'deDE', 'Da ist er. Derjenige, der diesen Angriff anführt.', 66192),
(86647, 'deDE', 'Ich muss dem ein Ende machen.', 66192),
(86646, 'deDE', 'Das ist sinnlos. Wir müssen dem ein Ende machen!', 66192),
(86644, 'deDE', 'Bei Euch sieht das so leicht aus.', 66192),
(86643, 'deDE', 'Die Zwielichtklingen terrorisieren Zul\'Aman ebenfalls? Das kann kein Zufall sein!', 66192),
(86642, 'deDE', 'Was habt Ihr entdeckt?', 66192),
(86641, 'deDE', 'Egal, was ihre Gründe waren, die Amani werden diese Grenzüberschreitung bereuen.', 66192),
(86640, 'deDE', '<Lor\'themar verstummt und betrachtet die Küste vor Euch.>', 66192),
(86638, 'deDE', 'Wir haben getan, was wir konnten. Ich hoffe nur, dass es ausreicht.', 66192),
(86639, 'deDE', 'Ein paar von ihnen leben noch... Dafür bin ich dankbar und sie ebenso.', 66192),
(86637, 'deDE', 'Ich habe nicht so schnell mit Verstärkung gerechnet! Habt Ihr Eure Machenschaften mit Magister Umbric abgeschlossen?\n\nBrechen wir auf.', 66192),
(86636, 'deDE', 'Kasieas Notizen! Na endlich! Ich muss gehen!', 66192),
(86635, 'deDE', 'Es erfüllt mich mit Abscheu, wieder hier zu sein... doch es ist der einzige Weg.', 66192),
(86633, 'deDE', 'Nein! Nein... Ich war so nah dran.\n\n<Umbric sammelt sich und gibt damit ein Musterbeispiel der Entschlossenheit ab.>\n\nDann also die Todesfestung. Die Basis der Zwielichtklinge.', 66192),
(86634, 'deDE', 'Die Zwielichtklinge hat sich schon hier herumgetrieben... Gut, dass wir so schnell hergekommen sind.', 66192),
(86781, 'deDE', 'Anscheinend ist hier alles in Ordnung... Jedenfalls für den Moment.', 66192),
(90494, 'deDE', 'Eine Karte von Immersang? Mit mehreren von der Zwielichtklinge markierten Dörfern!', 66192),
(90493, 'deDE', 'Ihr seid in Sicherheit, und die erschöpften Einwohner von Tristessa ebenfalls. Dem Licht sei Dank.', 66192),
(90509, 'deDE', 'Es wird mehr brauchen, um den Schaden rückgängig zu machen, der hier angerichtet wurde, aber es war ein guter erster Schritt. Ich danke Euch.', 66192),
(86632, 'deDE', 'Ich fürchte, das hier ist noch lange nicht vorbei...', 66192),
(86626, 'deDE', 'Die Zwielichtklinge... Antenorian, was habt Ihr getan?!', 66192),
(86622, 'deDE', 'Verdammt... der Kult hat seine Ohren überall!', 66192),
(90907, 'deDE', 'Es ist eine Ehre, dass Ihr mit diesen ernsten Bedenken zu mir kommt.', 66192),
(86624, 'deDE', 'Anscheinend geht in Tristessa mehr vor sich, als es auf den ersten Blick scheint.', 66192),
(86623, 'deDE', 'Ich verstehe das nicht. Was wollte sie mit all diesen Informationen anfangen?', 66192),
(86621, 'deDE', '<Umbric sieht krank aus.>\n\nDas sind nicht die Nachrichten, die ich erwartet habe. Nein!', 66192),
(86745, 'deDE', 'Ich hasse es, das so stehen zu lassen... aber Silbermond sollte nun genug Informationen haben, um die Lichtblüte fernzuhalten, während wir auf Orweynas Untersuchung warten.\n\nBis dahin... können wir uns der Sache am Sonnenbrunnen ohne Umbric nicht annehmen.', 66192),
(86744, 'deDE', 'Die Rutaani wollen die Lichtblüte so weit verbreiten, wie sie nur können. Aber warum?', 66192),
(86742, 'deDE', 'So sind die Rutaani nicht! Jedenfalls nicht dort, wo ich herkomme. Irgendetwas beeinflusst sie. Ihr Verhalten ist nicht normal.', 66192),
(86743, 'deDE', 'Das sollte der Gegend wieder etwas Frieden bringen, jedenfalls zeitweise.', 66192),
(86741, 'deDE', 'Diese Kreaturen kommen alle von hier. Diese Lichtblüte... hierher wollte mich das Lied der Welt führen.', 66192),
(86738, 'deDE', 'Ein was? Riesenpflanzen? Und noch ein Problem... wenigstens sind wir es los. Danke Euch.', 66192),
(86740, 'deDE', 'Diese Lichtblüten - sie scheinen für jedes neue Problem, das sich hier zusammenbraut, verantwortlich zu sein.', 66192),
(86739, 'deDE', 'Ich danke Euch vielmals. Vielleicht kann ich jetzt wieder einen Hauch von Ordnung in dieses Dorf bringen!', 66192),
(86737, 'deDE', 'Vielen Dank... Es ist alles außer Kontrolle!', 66192),
(86736, 'deDE', 'Auch wenn die Anwesenheit der Allianz und der Vorhut beunruhigend sein könnte, tolerieren wir ihre Präsenz... für den Moment.', 66192),
(86734, 'deDE', 'Es gibt einige, die mit meiner Entscheidung nicht einverstanden sein werden. Doch ich werde nicht zulassen, dass wir unsere Heimat verlieren. Und wenn wir dafür zeitweise Gäste unterbringen müssen, dann sei es so.', 66192),
(86733, 'deDE', 'Ich bin froh, dass Ihr hier seid. Fangen wir an.', 66192),
(93726, 'deDE', 'Freut mich, Euch kennenzulernen. Aber wenn Ihr meine gute Zange verlegt, werfe ich Euch hochkant raus.', 66192),
(93723, 'deDE', 'Die Erfüllung dieser Aufträge ist für die Kriegsbemühungen unerlässlich. Eure Dienste werden sehr geschätzt.', 66192),
(86852, 'deDE', 'Möge das Licht Euch segnen und schützen, $n. Es war Eure Verteidigung der Kammer des Sonnenbrunnens, die dieses Wunder ermöglicht hat.\n\nZwar haben wir Xal\'atath nicht besiegt, aber wir haben die Invasion ihrer Verschlingenden Schar aufgehalten. Jetzt haben wir Zeit, uns zu erholen und herauszufinden, was wir tun müssen, um sie zu besiegen.', 66192),
(86850, 'deDE', 'Dem Licht sei Dank. Die Überlebenden der Vorhut sind in der Kammer des Sonnenbrunnens. Jetzt, da Ihr hier seid, können wir beginnen.', 66192),
(86849, 'deDE', 'Beim Licht! Wir können diesen Kampf nicht gewinnen. Der Sonnenbrunnen ist unsere einzige Hoffnung!', 66192),
(86848, 'deDE', 'Waren sie nur hier, um uns auszunehmen? Oder hatten sie einen Grund, Waffen des Lichts zu suchen?\n\nDiese Überlegung hebe ich mir lieber für später auf. Im Moment braucht die Vorhut diese Waffen. Mit ihnen werden wir diese Verschlingende Schar von Quel\'Danas vertreiben!', 66192),
(86811, 'deDE', 'Ausgezeichnete Arbeit, $n. Ich wusste, dass auf Euch Verlass ist.', 66192),
(86834, 'deDE', 'Aus unserer Formation auszubrechen, war leichtsinnig! War das Arators Idee? Er ist so eigensinnig in letzter Zeit. \n\nVerzeihung, $n. Ich sollte unsere Familienangelegenheiten nicht vor Euch ausbreiten. Ich muss zugeben, dass Eure Taten der Vorhut des Lichts in diesem Kampf geholfen haben.', 66192),
(91274, 'deDE', 'Jetzt, wo die Leerenpylonen zerstört sind, ist die Verschlingende Schar geschwächt. Vielleicht können wir doch noch gewinnen.', 66192),
(86807, 'deDE', 'Champion, ich bin froh zu hören, dass so viele Sin\'dorei überlebt haben. Auch wenn mein Befehl an die Vorhut anders lautete, steht Ihr nicht unter meinem Kommando. Ihr habt Eure Sache gut gemacht. Von Arator kann man das nicht behaupten.', 66192),
(86806, 'deDE', 'Die Schiffe haben die Meerenge erfolgreich durchquert und die Flüchtlinge haben es sicher nach Silbermond geschafft. Ich danke Euch, $n. Ihr habt meinem Volk sehr geholfen.', 66192),
(89012, 'deDE', 'Ich danke Euch, $n. Diese Rettungsmissionen sind selten so einfach, wie sie zuerst erscheinen. Es gibt immer eine weitere Bedrohung, mit der man nicht gerechnet hat.', 66192),
(86805, 'deDE', 'Die Bürger sind jetzt an Bord der Schiffe. Bald werden sie die Sicherheit Silbermonds erreichen.', 66192),
(89271, 'deDE', 'Ihr habt ihn gefunden? Dem Licht sei Dank!\n\nWir können uns keine Ablenkungen leisten. Ich brauche Arator hier bei den versammelten Streitkräften, damit wir uns voll und ganz auf den Angriff gegen Xal\'atath konzentrieren können.', 66192),
(86780, 'deDE', 'Ausgezeichnete Arbeit, $n. Ihre Reihen lichten sich, während unsere Zahl wächst. Wahrlich, das Licht hat diesem Schlachtfeld Hoffnung gebracht.', 66192),
(86770, 'deDE', 'Danke, $n. Mit dieser Streitmacht können wir die Überlebenden beschützen und sie zu den Schiffen geleiten.', 66192),
(86769, 'deDE', 'Wir müssen dieses Wunder nutzen, um das Blatt gegen das Chaos zu wenden. Wir dürfen nicht zögern.', 66192),
(88719, 'deDE', 'Das Licht hat Euch gerufen, $n. Unsere Hoffnung liegt in den Händen der Champions von Azeroth und der Vorhut des Lichts!', 66192),
(91281, 'deDE', 'Ich bin froh, dass Ihr gekommen seid, $p. Wir brauchen dringend Eure Hilfe.', 66192);
