INSERT INTO `quest_request_items_locale` (`ID`, `locale`, `CompletionText`, `VerifiedBuild`) VALUES
(90822, 'deDE', 'Etwas scheint sich seit unserem letzten Besuch in der Mördergasse getan zu haben. Hier herrscht auf einmal ein ganz schönes Gedränge.\n\nGeht vorsichtig vor. Ich bin an Eurer Seite.', 66384),
(93754, 'deDE', 'Die Magie, die die Blutfratzen nutzen, stinkt nach untoten Lehren... und ich weiß, dass so was nie gut ausgeht.', 66384),
(92002, 'deDE', 'Wenn noch etwas Blut dran klebt, ist das sogar noch besser.', 66384),
(91989, 'deDE', 'Wie läuft es mit der Ernte?', 66384),
(88706, 'deDE', 'Der Jagdinstinkt meiner Frau ist unübertroffen. Wenn sie dieses Ziel ausgewählt hat, dann ist es gewiss ein würdiges Ziel.', 66384),
(88702, 'deDE', 'Die Verschlingende Schar trägt ihren Namen zurecht. Alle, die sich ihr anschließen oder mit ihr kämpfen, werden früher oder später verschlungen.', 66384),
(88701, 'deDE', 'Habt Ihr die Andenken schon geborgen? Diese Erinnerungsstücke werden ihren Liebsten bestimmt Trost spenden.', 66384),
(95175, 'deDE', 'Konntet Ihr uns helfen, den Singularitätsanker zu aktivieren?', 66384),
(92365, 'deDE', 'Habt Ihr die Verteidigung aufgebaut?', 66263),
(91399, 'deDE', 'Keine Sorge, wir mach\'n diese Rituale seit Jahrhunderten.', 66263),
(91401, 'deDE', 'Warum grade die? Geht Euch nix an.', 66263),
(86515, 'deDE', 'Wenn wir nur die ganze Leerenbrut erschlagen könnten.', 66263),
(86517, 'deDE', 'Lothraxion hätte es besser wissen müssen.', 66263),
(86514, 'deDE', 'Habt Ihr Torentias Siegel an Euch genommen?', 66263),
(86541, 'deDE', '<Decimus wirft Euch einen Seitenblick zu.>', 66263),
(86538, 'deDE', 'Geht. Sammelt den Katalysator.', 66263),
(86537, 'deDE', 'Was habt Ihr herausgefunden?', 66263),
(86530, 'deDE', 'Genau wie zuvor.', 66263),
(86561, 'deDE', 'Das Metall an diesen Kreaturen scheint ein besonders guter Leiter für magische Energie zu sein. Interessant.', 66263),
(86562, 'deDE', 'Seid Ihr den größten der hiesigen Gegner schon begegnet? Ich frage mich, wie mächtig eine Kreatur werden kann, wenn sie eine Ewigkeit lang Leere vertilgt...', 66263),
(86894, 'deDE', 'Der Alnstaub ist nicht einfach irgendein Reagenz. Wir müssen ihn mit Bedacht einsetzen. Doch für mein Volk werde ich ohne zu zögern alles geben, was ich habe.', 66263),
(86884, 'deDE', 'Zögert nicht. Je länger wir warten, um den Wildwuchs zu bekämpfen, desto mehr von diesem Wald wird für die Sin\'dorei verlorengehen.', 66263),
(86880, 'deDE', 'Es wäre gut, wenn wir einige dieser Gegenstände zurückerlangen könnten.', 66263),
(86862, 'deDE', 'Die Macht des Risses von Aln liegt jenseits der Vorstellungskraft von uns Sterblichen. Wir borgen uns lediglich für einen kurzen Moment etwas davon.', 66263),
(86859, 'deDE', 'Jeder Vorteil, den wir uns im Kampf gegen die Manifestation verschaffen können, steigert unsere Überlebenschancen.', 66263),
(86856, 'deDE', 'Der Vorgang klang nicht kompliziert. Mein Können sollte mehr als ausreichen. Aber ich bin dankbar für Eure Anwesenheit, um mich zu erden.', 66263),
(86851, 'deDE', 'Ich werde Eure junge Begleiterin wissen lassen, was mit dem Alnstaub zu tun ist.', 66263),
(86944, 'deDE', 'Hoffen wir, dass Eonka nach wie vor unverändert ist.', 66263),
(86912, 'deDE', 'Ihr habt die Kluft der Erinnerungen überlebt. Willkommen in Har\'mara, $gFreund:Freundin;.', 66263),
(91854, 'deDE', 'Die Lage ist angespannt.', 66263),
(93432, 'deDE', 'Es is\' wie \'n Traum, aus dem man nich\' aufwach\'n kann.', 66263),
(92497, 'deDE', 'Reißt einfach \'n paar Seit\'n aus den Büchern und bringt sie her. Der Rest is\' einfach.', 66263),
(92496, 'deDE', 'Die Welt is\' besser dran, wenn Mish\'moshs Übel sie nich\' befleckt.', 66263),
(92493, 'deDE', 'Ich würd\' das nie vor meinen Leuten sag\'n, aber ich trauere jed\'n Tag um Idago.\n\nIch weiß nich\', wie ich ohne seinen Rat weitermach\'n soll.', 66263),
(93734, 'deDE', 'Was immer Groffa hatte, ist schlecht. Oder?', 66263),
(91749, 'deDE', 'Was hortet er in diesem Lager?', 66263),
(91747, 'deDE', 'Ich will sie nicht. Werfen wir sie ins Feuer.', 66263),
(93261, 'deDE', 'Ich weiß nich\', ob die Zwielichtklinge dieses Biest erschaff\'n hat oder nich\', aber es muss WEG!', 66263),
(93259, 'deDE', 'Meine Leute ham so viel durchgemacht. Jeder verdient \'n schönes Zuhause, zu dem man zurückkehr\'n kann, und \'ne ordentliche Mahlzeit, um wieder Kraft zu schöpf\'n un\' den Geist zu stärk\'n.', 66263),
(93260, 'deDE', 'Konntet Ihr einige der Fallen reinig\'n? Oder die Quelle der Verschmutzung find\'n, die sie verklebt?', 66263),
(93181, 'deDE', '<Kanza wirkt nervös und erwartungsvoll.>', 66263),
(93180, 'deDE', '<Kanza verlagert ihr Gewicht von einem Fuß auf den anderen und wippt dabei ungeduldig hin und her.>', 66263),
(90485, 'deDE', 'Habt Ihr schon was Spannendes gefunden?', 66263),
(90486, 'deDE', 'Was glaubt Ihr, wie das schmeckt? Amaxi meint, es sei absolut faszinierend und könnte einen Stegodon umhauen!', 66263),
(90482, 'deDE', 'Wir nehmen bestimmte Gifte zu uns, um eine Resistenz gegen potenzielle Gefahren zu entwickeln.\n\nEinige schmecken einfach gut oder sorgen für den richtigen Kick.', 66263),
(91411, 'deDE', 'Ich glaub, dass Shadra ihr Wort halt\'n wird.', 66263),
(91630, 'deDE', 'Ich kann versteh\'n, wieso sie Spinnengift sammeln, aber die Artefakte sin\' nur dafür da, um mit Shadra zu kommunizier\'n. Was woll\'n sie damit?', 66263),
(91408, 'deDE', 'Wir folg\'n dieser Spur, wohin sie auch führt.', 66263),
(91404, 'deDE', 'Habt Ihr nach dem groß\'n Fangzahn geschaut?', 66263),
(91403, 'deDE', 'Halazzi sagt, \"Angriffsgift\" is\' das, was krank macht, wenn einen was beißt oder sticht, un\' \"Abwehrgift\" erwischt einen nur, wenn man selbst reinbeißt! Is\' das nicht interessant?', 66263),
(88989, 'deDE', 'Dieser Kommandant hat unsre Leute getötet.\n\nSeine Trupp\'n ham höchstwahrscheinlich die Schwester des Jungen getötet.\n\nSelbst wenn sein Tod das Herstell\'n von Waff\'n und ihr\'n Versand nach Amani\'Zar leichter mach\'n würde, is\' es das Leben des Jungen nich\' wert.', 66263),
(88988, 'deDE', 'Die Arbeit mit Lichtholz is\' selbst für erfahrene Handwerker schwer.\n\nSeid geduldig. Seid präzise. Un\' tut alles, was ich sag\'.', 66263),
(88987, 'deDE', 'Das Chaos, das der Elf angerichtet hat, is\' nix im Vergleich zu dem, womit wir jed\'n Tag zu tun ham.\n\nWir müss\'n besonders vorsichtig sein, die Zwielichtklinge will jede unsrer Bewegungen sabotier\'n.', 66263),
(93094, 'deDE', 'Mit dies\'n Tafeln kann keiner unsre Stärke infrage stell\'n.', 66263),
(93093, 'deDE', 'Habt Ihr die Trophä\'n gekriegt? Die Knardin ham von all ihr\'n Kämpf\'n mehr als genug davon.', 66263),
(87317, 'deDE', 'Warum helft Ihr mir nich\'?!', 66263),
(87267, 'deDE', 'Kulzi darf uns nich\' länger ignorier\'n!', 66263),
(87256, 'deDE', 'Sie müss\'n so stink\'n, wenn sie wirk\'n soll\'n.', 66263),
(87254, 'deDE', 'Stellt sicher, dass die Größe stimmt.', 66263),
(86654, 'deDE', 'Die Knardin scheinen gegen uns kämpfen zu wollen. Erfüllen wir ihnen doch diesen Wunsch.', 66263),
(89334, 'deDE', 'Nehmt ihre Köpfe. Wie schmerzhaft die Methode is\', bleibt eine Sache zwischen Euch und Euren Göttern, oder wen Ihr sonst so verehrt.', 66263),
(93049, 'deDE', 'Habt Ihr sie alle gekriegt?', 66263),
(92165, 'deDE', 'Mein Königreich ist bereit für ein Festmahl! Seid Ihr bereit?', 66263),
(91070, 'deDE', 'Ja, $C?', 66263),
(93047, 'deDE', 'Die Kunst der Amanijagd liegt in der Disziplin. Man übt, bis es so natürlich wie das Atmen is\'.\n\nAber gerade bedeutet Disziplin, meine Befehle zu befolg\'n.', 66263),
(89559, 'deDE', 'Wir wissen beide, dass dieser Schrein unsre Mutter glücklich gemacht hat.\n\nIch glaube nich\', dass sie so viel über uns wusste.', 66263),
(89513, 'deDE', 'Macht Euch keine Sorg\'n um Kan\'sha. Sie hat schon viele Trollgenerationen überlebt, un\' die Druid\'n sag\'n, sie wird noch viele weitere überleb\'n.', 66263),
(89506, 'deDE', 'Die Sehnen von Bergriesen geb\'n robustes Baumaterial ab.\n\nAber wir benutz\'n sie nur für dies\'n einen Zweck, weil sie zu gefährlich zu beschaff\'n sin\' un\' es nich\' genug Riesen gibt.', 66263),
(89503, 'deDE', 'Sie heiß\'n Trauerspor\'n, weil sie einen zum Weinen bringen, wenn man sie verbrennt.\n\nDie Spor\'n liefern unser\'n Kriegern \'ne gute Ausrede, wenn sie am Scheiterhauf\'n zu feige sin\', sich ihre Gefühle einzugesteh\'n.', 66263),
(91384, 'deDE', 'Wenn wir dem Rest des Immersangwalds von Nutzen sein wollen, müssen wir zuerst hinter uns aufräumen.', 66263),
(91137, 'deDE', 'Haben sie es zurückgeschafft?', 66263),
(91328, 'deDE', 'Passt Ihr auf, was Ihr sammelt?', 66263),
(91271, 'deDE', 'Habt Ihr ihn geangelt?', 66263),
(92023, 'deDE', 'Puh. Wieso riecht Ihr nach Graberde?', 66263),
(92022, 'deDE', 'Streng genommen hätte ein stärkeres Gift einen umfangreicheren Effekt. Doch wir leben in strapaziösen Zeiten. Dieses Leerengedöns hat meine üblichen Versorgungslinien bei den Sonnensegeln vollständig vereinnahmt. Wir müssen mit Trauerseglergift auskommen. Geht jetzt.', 66263),
(92021, 'deDE', 'Oh, kommt schon. Während wir hier stehen und über das Wetter plaudern, leidet meine Mitarbeiterin unter den Strapazen ihres Leidens! Macht Euch an die Arbeit.\n\nEs ist übrigens bedeckt. Das Wetter. Wie üblich.', 66263),
(91349, 'deDE', 'Es ist schwere Arbeit, aber sie wird irgendwann Frieden bringen.', 66263),
(91348, 'deDE', 'Keine Sorge! Sie erholen sich schnell wieder.', 66263),
(91347, 'deDE', 'Es geht doch nichts über das Einpflanzen von Samen.', 66263),
(91388, 'deDE', 'Das ist selbstverständlich der leichte Teil.', 66263),
(91284, 'deDE', 'Ich hoffe wirklich, ich finde heraus, wo ich hingehöre...', 66263),
(91288, 'deDE', 'Habt Ihr die Felle oder gebt Ihr schon auf?', 66263),
(86997, 'deDE', 'Nun? Befinden sich die Seiten in Eurem Besitz oder gesteht Ihr Euren Schwindel?', 66263),
(91291, 'deDE', 'Also, was denkt Ihr?', 66263),
(90821, 'deDE', 'Zaen steckt hinter all dem, oder zumindest deutet alles darauf hin. Wir werden uns um ihn kümmern müssen, wenn wir diesem Komplott ein Ende machen wollen.\n\nWenn wir ihre Versorgungsrouten am Hafen ausschalten, können wir zumindest verhindern, dass sich die Situation verschlimmert, bis wir ihn haben.', 66263),
(89205, 'deDE', 'Der Stab sollte diesen Schutz jetzt durchbrechen können.', 66263),
(89204, 'deDE', 'Das ist der leichte Teil.', 66263),
(89201, 'deDE', 'Diese Dokumente nehme ich mal wieder an mich.', 66220),
(90819, 'deDE', 'Die Anwohner der Mördergasse sind verschwiegen, aber jede Information, die Ihr beschaffen könnt, ist wertvoll.', 66220),
(89199, 'deDE', 'Geht vorsichtig mit dem Schutzbrecher um. Beschädigungen dulde ich nicht.', 66220),
(87401, 'deDE', 'Ja?', 66192),
(91494, 'deDE', 'Vielleicht war der Zauberstab seinem ursprünglichen Besitzer zu schwach. So oder so, wir können ihn bestimmt gut gebrauchen.', 66192),
(91505, 'deDE', 'Wir müssen die Naga von Goldnebel fernhalten.', 66192),
(87392, 'deDE', 'Also, was hatten unsere feinen Hafenarbeiter zu sagen?', 66192),
(86716, 'deDE', 'Diese Waffen sin\' entscheidend dafür, ob mein Volk lebt oder stirbt.', 66192),
(86719, 'deDE', 'Tut, was nötig is\', um Kinduru zum Geh\'n zu überred\'n.\n\nEr is\' unser Onkel. Wir können ihn nich\' hier lass\'n.', 66192),
(86903, 'deDE', 'Ein wahrhaft beeindruckender Ort, nicht wahr, $p?', 66192),
(86831, 'deDE', 'Habt Ihr sie ausgeschaltet?', 66192),
(86826, 'deDE', 'Habt Ihr Nagosh zur Strecke gebracht?', 66192),
(86827, 'deDE', 'Habt Ihr die Abzeichen, $p?', 66192),
(86825, 'deDE', 'Konntet Ihr Mar\'kag besiegen, $p?', 66192),
(89338, 'deDE', 'Mit den Waffen, die wir sammeln, können wir Hammerfalls Zukunft neu schmieden, $p.', 66192),
(86844, 'deDE', 'Welche Artefakte habt Ihr gefunden, $p?', 66192),
(86841, 'deDE', 'Unter der Kapelle ruhen zahllose große Helden, $p.\n\nHoffentlich können ihre Relikte jenen am Sonnenbrunnen helfen.', 66192),
(86644, 'deDE', 'Es gibt einen Ausweg, ich weiß es genau.', 66192),
(86636, 'deDE', 'Bringen wir es zu Ende. Die Zwielichtklinge muss fallen.', 66192),
(90494, 'deDE', 'Ich werde nicht zulassen, dass sie damit davonkommen.', 66192),
(86622, 'deDE', 'Finden wir heraus, was hier vor sich geht.', 66192),
(86621, 'deDE', 'Was habt Ihr da?', 66192),
(86742, 'deDE', 'Das ergibt keinen Sinn.', 66192),
(93726, 'deDE', 'Die neuen Aufträge häufen sich bereits. Ich würde mich über etwas zusätzliche Hilfe freuen.', 66192);
