INSERT INTO `quest_description_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(79010, 54203, 0, 'deDE', 'Wenn es bei dieser Untersuchung um die Leere geht, wäre es weise, die Kinder der Leere, die Ren\'dorei, um Rat zu fragen. Wir müssen zum Telogrusriss reisen und über die Lage berichten.\n\nIch werde mit Umbric reden. Er wird die Risswanderer für unsere Sache mobilisieren können.', 0, 66384), -- Door to the Ren'dorei
(93693, 0, 243553, 'deDE', 'Willkommen zurück, $C. Wenn Ihr noch immer an einer Zusammenarbeit mit dem Handwerkerkonsortium interessiert seid, würden wir Eure Hilfe sehr schätzen. Bei der Herstellung von Handwerksutensilien für den Kriegseinsatz können wir immer ein weiteres Paar Hände gebrauchen.\n\nWenn Ihr dazu bereit seid, schaut hier bei meiner Werkbank ans Anschlagbrett und erfüllt jegliche öffentliche Handwerksaufträge, die Ihr findet. Ihr könnt auch Aufträge für Euch selbst, Eure Gildenmitglieder oder private Auftraggeber erfüllen.\n\nSprecht mit Hauptmann Fackelschwur, sobald Ihr einige Aufträge abgeschlossen habt. Er sorgt dafür, dass Ihr Euren Lohn erhaltet.', 0, 66384), -- Inscription Services Requested
(92630, 149795, 248153, 'deDE', 'Meine Schülerin Leona ist geradezu besessen davon, die Wege der Illidari zu erlernen.\n\nSie hat eine andere Dämonenjägerin gefunden, die bereit ist, sie auszubilden: Allari die Seelenfresserin. Doch zuerst muss Leona sich als würdig erweisen. Nach dem, was passiert ist, als sie sich das letzte Mal einen solchen Mentor ausgesucht hat, sorge ich mich um ihre Sicherheit.\n\nSchließt Euch Leona bei dieser Prüfung an. Sie darf sich auf nichts einlassen, dem sie nicht gewachsen ist.', 0, 66384), -- The Pursuit Continues
(72681, 923, 0, 'deDE', '<Das Funkeln eines entfernten Objekts zieht Eure Aufmerksamkeit auf sich. Ihr erinnert Euch plötzlich, dass Ihr Devisen für den Handelsposten Zen\'shiri sammeln müsst.>', 0, 66384), -- Report to the Trading Post
(90866, 139629, 241620, 'deDE', 'Ich muss mein Volk in unsere Welt zurückbringen. In Sicherheit. Im Untergrund haben wir einen Portalnexus aus dem zusammengebastelt, was wir von den Domanaar plündern konnten, aber wir konnten ihn noch nicht zum Laufen bringen.\n\nIch wurde allerdings Zeugin einer magischen Reaktion, als ein Streit zwischen zwei Krokul eskalierte. Kurz erwachte etwas zum Leben. Wie alles andere in der Leere scheint die Domanaarmagie auf Gewalt zu reagieren.\n\nBringt mir das Blut der Wildtiere im nördlichen Graben. Ich habe da eine Idee.\n\n<Sie bleckt ihre Zähne verspielt und macht dann einen Klauenhieb in die Luft.>\n\nWildtiere. Die gibt es auch dort, wo Ihr herkommt, oder?', 1, 66384), -- Universal Language
(90866, 67878, 241620, 'deDE', 'Ich muss mein Volk in unsere Welt zurückbringen. In Sicherheit. Im Untergrund haben wir einen Portalnexus aus dem zusammengebastelt, was wir von den Domanaar plündern konnten, aber wir konnten ihn noch nicht zum Laufen bringen.\n\nIch wurde allerdings Zeugin einer magischen Reaktion, als ein Streit zwischen zwei Krokul eskalierte. Kurz erwachte etwas zum Leben. Wie alles andere in der Leere scheint die Domanaarmagie auf Gewalt zu reagieren.\n\nBringt mir das Blut der Wildtiere im nördlichen Graben. Ich habe da eine Idee.\n\n<Sie bleckt ihre Zähne verspielt und macht dann einen Klauenhieb in die Luft.>\n\nWildtiere. Ihr kennt doch noch die von Argus, oder? Oder seid Ihr zu jung?', 0, 66384), -- Universal Language
(89205, 39987, 0, 'deDE', 'Ich habe Zanien alles erzählt. Er bildet schon seit langem Hexenmeister aus. Wenn also jemand was gegen Nachlässigkeit hat, dann er. Ihr könnt das bestimmt nachvollziehen.\n\nEr ist überzeugt, dass er den Schutzbrecher wiederaufladen kann. Folgt seinen Anweisungen, dann sollten wir bald aufbruchsbereit sein.', 0, 66384), -- Cutting a Key
(86204, 134732, 0, 'deDE', 'Gallywix ist eine Schande für Lorenhall, seitdem er vergessen hat, woher er kommt.\n\nGallywix hat schon immer den kleinen Mann als Fußabtreter benutzt. Gier und die stete Suche nach der \"nächsten großen Sache\" veranlassen ihn lediglich dazu, noch härter durchzugreifen. Auf der Suche nach Macht, einfach um der Macht willen? Nichts da! Die Macht liegt in den Händen des Volkes.\n\nSprecht mit Paks, wenn Ihr einen schnellen Weg in das Garbagio und wieder raus braucht.\n\nLegen wir Gallywix schnell das Handwerk, $n.', 0, 66384), -- Liberation of Undermine: The House Loses
(93695, 0, 243500, 'deDE', 'Willkommen zurück, $C. Wenn Ihr noch immer an einer Zusammenarbeit mit dem Handwerkerkonsortium interessiert seid, würden wir Eure Hilfe sehr schätzen. Bei der Herstellung von Handwerksutensilien für den Kriegseinsatz können wir immer ein weiteres Paar Hände gebrauchen.\n\nWenn Ihr dazu bereit seid, schaut hier bei meiner Werkbank ans Anschlagbrett und erfüllt jegliche öffentliche Handwerksaufträge, die Ihr findet. Ihr könnt auch Aufträge für Euch selbst, Eure Gildenmitglieder oder private Auftraggeber erfüllen.\n\nSprecht mit Hauptmann Fackelschwur, sobald Ihr einige Aufträge abgeschlossen habt. Er sorgt dafür, dass Ihr Euren Lohn erhaltet.', 0, 66384), -- Leatherworking Services Requested
(93696, 0, 243352, 'deDE', 'Willkommen zurück, $C. Wenn Ihr noch immer an einer Zusammenarbeit mit dem Handwerkerkonsortium interessiert seid, würden wir Eure Hilfe sehr schätzen. Bei der Herstellung von Handwerksutensilien für den Kriegseinsatz können wir immer ein weiteres Paar Hände gebrauchen.\n\nWenn Ihr dazu bereit seid, schaut hier bei meiner Werkbank ans Anschlagbrett und erfüllt jegliche öffentliche Handwerksaufträge, die Ihr findet. Ihr könnt auch Aufträge für Euch selbst, Eure Gildenmitglieder oder private Auftraggeber erfüllen.\n\nSprecht mit Hauptmann Fackelschwur, sobald Ihr einige Aufträge abgeschlossen habt. Er sorgt dafür, dass Ihr Euren Lohn erhaltet.', 0, 66384), -- Tailoring Services Requested
(93057, 923, 0, 'deDE', '<Ein leuchtendes Pergament mit einem Haussymbol auf der Vorderseite erscheint vor Euch.>\n\nSeid gegrüßt, $n!\n\nHabt Ihr jemals den Wunsch gehabt, ein eigenes Heim zu besitzen? Einen Ort, der nur Euch allein gehört? Jetzt ist das möglich!\n\nBesucht uns an der Klingenschluchtküste, der neuen Behausungsnachbarschaft, und holt Euch Euer eigenes Stückchen Azeroth!', 0, 66384), -- A House For You
(92603, 148574, 254012, 'deDE', 'Der Schemen ist mein Werk, mein Fehler. Die Leere hier ist so rein, so... lebendig, und ich war töricht. Ich habe zuvor bereits Schemen gesehen, Manifestationen der Ren\'dorei. Ich dachte, ich könnte meinen eigenen erschaffen.\n\nDoch er ist falsch. Gebrochen. Ich entkomme ihm genauso wenig wie meinen eigenen Gedanken.\n\nDarum bin ich hier. Ich habe in der Leere nach einer Lösung gesucht, und eine Stimme führte mich nach Norden. Sie hat mir ein Artefakt versprochen, das mich von diesem Versagen befreien wird.', 0, 66384), -- O Lonely Star
(92325, 23503, 250410, 'deDE', 'Meine Schwester Krenna war einst eine Eroberin der Armee der Horde. Skrupellos. Brutal. Einige bezeichneten sie als Tyrannin. Doch in unserer Jugend war sie anders. Voller Wärme gegenüber jener, die sie an sich heranließ. Verängstigt, aber immer freundlich zu mir. Hat die Macht sie verändert? \n\nUnd wenn diese sie verändert hat, hat sie auch Garrosh Höllschrei verändert? Ich weiß, wer Krenna war. Ich weiß nicht, wer Garrosh war.\n\nReist nach Nagrand und findet es heraus. Macht Euch keine Sorgen, dass Ihr in Hordegebiet eindringt. Die Magie des Portals wird Euch verbergen.', 0, 66384), -- Hellscream's Heritage
(91145, 147872, 245878, 'deDE', 'Ein Domanaar hat unsere hinteren Linien angegriffen. Er war... anders als die anderen Leerenbestien. Als hätte er gespielt, statt zu kämpfen. Callum, mein Gefährte, hat eine Truppe angeführt, um ihn zu jagen. Sie sind nicht zurückgekommen.\n\nCallum ist Arathi durch und durch. Er würde hier nicht fallen, das weiß ich.\n\nIch habe bereits nach ihm gesucht, als die Vorhut bei der Leerenspitze verloren ging. Dieser Ort hat mir meine Freunde und Kameraden genommen, ich werde Cal nicht auch noch verlieren. Ich weiß, welche Route seine Truppe genommen hat, aber allein schaffe ich das nicht.', 0, 66384), -- The Conquered Heroes
(90782, 122541, 242233, 'deDE', '<Der Mann ruft Euch etwas in Eurer Muttersprache zu. Seinen Akzent könnt Ihr nicht zuordnen.>\n\n$gEin Bruder:Eine Schwester; von Argus! Jemand aus der Familie! Jahrelang verloren, Ihr kommt sicher aus... Nein, meine Fragen können warten. Es gibt dringendere Angelegenheiten.\n\nDiese Domanaar haben uns aus unserer Welt entführt. Portale öffneten sich und sie ergossen sich aus dem Himmel. Sie zwingen uns, zu ihrer Unterhaltung in ihren Arenen bis zum Tod zu kämpfen. Ich konnte fliehen, wurde aber beim Versuch, meine Leute zu retten, erneut gefangen genommen.\n\nMeine große Schwester Tul\'amar hat einen Plan, wie wir alle heimkehren können. Befreit mich, dann bringe ich Euch zu ihr.', 0, 66384), -- The Nethersent
(94933, 151288, 257544, 'deDE', 'Ah, da seid Ihr ja.\n\nUnser werter Magister Umbric hat mich damit beauftragt, einen fähigen Champion davon zu überzeugen, ihm zu helfen. Einer seiner Lehrlinge, Leona Dunkelstreifer, untersucht die Techniken und Methoden der Illidari.\n\nIhre Nachforschungen scheinen sie wohl ein wenig in Schwierigkeiten gebracht zu haben.\n\nDer Magister kann Euch mehr sagen. Er ist gerade auf K\'aresh und hat mir erlaubt, den Weg für Euch zu öffnen, falls Ihr Euch teleportieren wollt.', 0, 66263), -- Lessons in the Void
(91627, 47452, 0, 'deDE', '$n, nehme ich an? Ausgezeichnet. Euer Ruf eilt Euch voraus.\n\nLord Saltheril entbietet seine aufrichtigsten Grüße und geruht, Euch auf seinen Wohnsitz im Süden Silbermonds einzuladen.\n\nEin Teil des Anwesens wurde umgestaltet, um all jenen als dekadente Zuflucht zu dienen, denen es nach pläsierlicher Plauderei und gebildeter Gesellschaft gelüstet. Eure reizvolle Präsenz ist ihm noch immer in Erinnerung, und er wäre erfreut, wenn Ihr ihn erneut mit Eurer Anwesenheit delektieren würdet.\n\nEine Einladung zu erhalten, ist eine wahre Ehre. Seine Lordschaft hofft, dass Ihr annehmt.', 0, 66263), -- Saltheril's Haven
(86558, 54203, 0, 'deDE', 'Diese Leere ist anders als alles andere. Ich weiß, dass Ihr sie auch spürt. Ich bin stolz, dass Ihr durchgehalten habt...\n\nWir müssen dieses Gebiet irgendwie stabilisieren. Ich kann kaum noch verhindern, dass unser Fluchtweg implodiert, und unsere verbleibenden Späher... Ich hoffe, sie halten durch.\n\nUnsere Ren\'dorei wissen, was zu tun ist. Sie werden Schattensternloci aufstellen, um das Gebiet zu schützen, aber sie werden Eure Hilfe bei ihrer Aktivierung brauchen.', 0, 66263), -- Save a Piece of Mind
(86543, 54203, 0, 'deDE', 'Durch das riesige Portal wissen wir, dass es innerhalb des Leerensturms eine Landmasse gibt. Wenn wir sie erreichen, könnten wir den Kampf zu Xal\'atath tragen.\n\nIch habe den Schlüssel gefunden; ein Relikt, das man als Anziehungspunkt des Zwielichts kennt. Es zeigt unerreichbare Wege zu unendlichen unbekannten Welten und stellt uns schon seit Äonen vor ein Rätsel.\n\nLaut meiner Forschung sollte ich mit seiner Hilfe einen Weg in den Sturm öffnen können.\n\nEs gibt nur ein Problem: Der Anziehungspunkt des Zwielichts befindet sich auf der Terrasse der Magister. Wie Ihr wisst, $p, stehen wir Ren\'dorei im Moment nicht gerade in ihrer Gunst.', 0, 66263), -- Magisters' Terrace: Homecoming
(93691, 0, 241450, 'deDE', 'Willkommen zurück, $C. Wenn Ihr noch immer an einer Zusammenarbeit mit dem Handwerkerkonsortium interessiert seid, würden wir Eure Hilfe sehr schätzen. Bei der Herstellung von Handwerksutensilien für den Kriegseinsatz können wir immer ein weiteres Paar Hände gebrauchen.\n\nWenn Ihr dazu bereit seid, schaut hier bei meiner Werkbank ans Anschlagbrett und erfüllt jegliche öffentliche Handwerksaufträge, die Ihr findet. Ihr könnt auch Aufträge für Euch selbst, Eure Gildenmitglieder oder private Auftraggeber erfüllen.\n\nSprecht mit Hauptmann Fackelschwur, sobald Ihr einige Aufträge abgeschlossen habt. Er sorgt dafür, dass Ihr Euren Lohn erhaltet.', 0, 66263), -- Blacksmithing Services Requested
(92496, 146074, 251669, 'deDE', 'Idago is\' dank Euch in Sicherheit, aber die Bedrohung durch die Zwielichtklinge bleibt!\n\nDie Kultist\'n sag\'n, sie befolg\'n die Befehle von Todesrufer Mish\'mosh. Dieser Kultist muss hinter all dem Tod un\' der Zerstörung steck\'n, die über unsre Segge gekommen sin\'.\n\nZur Ehre derer, die wir verlor\'n ham: Vertreibt diese Schlange aus uns\'rer Heimat!', 0, 66263), -- Spears Against de Shadow
(90484, 93757, 242393, 'deDE', '<Trishe schnappt nach Luft.>\n\nIhr seid so groß wie ich! Ihr müsst auch über fünfundelfzig Jahre alt sein! Das heißt, Ihr seid auch antwortungsvoll!\n\n<Trishe verzieht das Gesicht.>\n\nMeine Freundin Steggi ist verschwunden! Sie war bei mir, aber dann kamen all die schönen Farben und sie ist ihnen nachgerannt und ich war zu langsam, um ihr zu folgen.\n\nIch soll auf Steggi aufpassen. Ich bin antwortungsvoll! Und jetzt seid Ihr anwortlich, sie zu finden, ja?', 0, 66263), -- Sightseeing Stegadon
(86733, 23504, 236779, 'deDE', 'So viele sind nach Silbermond gekommen, um sich der Verteidigung der Stadt und des Sonnenbrunnens anzuschließen. Namen und Gesichter, die ich nicht erwartet hätte... und einige vertraute Gesichter, die ich mit Freude wiedersehe.\n\nMein Dank für Eure Hilfe ist Euch gewiss, $p.\n\nWir haben Xal\'ataths Streitkräfte vorerst aufgehalten, aber es ist noch lange nicht vorbei.\n\nIch würde Euch gerne bei unseren nächsten Schritten miteinbeziehen. Trefft mich beim Sanktum des Lichts.', 0, 66263), -- Silvermoon Negotiations
(90837, 41722, 0, 'deDE', 'Ich habe in ganz Silbermond mächtige Teufelsmagie gespürt, aber das ist der erste Ursprungspunkt, den ich ausmachen konnte. Die anderen waren zu schwach, oder vielleicht absichtlich verschleiert. Glücklicherweise können wir damit endlich das Suchgebiet eingrenzen.\n\nWir müssen weitere Beweise sammeln. Durchsucht das Gebiet nach weiteren versteckten Quellen von Teufelsmagie. Ich bin sicher, mit Eurer Sicht fällt Euch diese Aufgabe leicht, $ct.', 2, 66220), -- Murder Row: Traces of Fel
(90837, 139931, 0, 'deDE', 'Ich habe in ganz Silbermond mächtige Teufelsmagie gespürt, aber das ist der erste Ursprungspunkt, den ich ausmachen konnte. Die anderen waren zu schwach, oder vielleicht absichtlich verschleiert. Glücklicherweise können wir damit endlich das Suchgebiet eingrenzen.\n\nWir müssen weitere Beweise sammeln. Durchsucht das Gebiet nach weiteren versteckten Quellen von Teufelsmagie. Ich empfinde keine Sympathie für Euresgleichen, Dämon. Aber solange Ihr Eure Sinne für das Gute einsetzt, kann ich Euch tolerieren.', 1, 66220), -- Murder Row: Traces of Fel
(90837, 39987, 0, 'deDE', 'Ich habe in ganz Silbermond mächtige Teufelsmagie gespürt, aber das ist der erste Ursprungspunkt, den ich ausmachen konnte. Die anderen waren zu schwach, oder vielleicht absichtlich verschleiert. Glücklicherweise können wir damit endlich das Suchgebiet eingrenzen.\n\nWir müssen weitere Beweise sammeln. Durchsucht das Gebiet nach weiteren versteckten Quellen von Teufelsmagie. Ich bin sicher, Eure... Neigungen erleichtern Euch diese Aufgabe, $C.', 0, 66220), -- Murder Row: Traces of Fel
(90835, 95784, 0, 'deDE', 'Grüße, $ct $n. Ihr kommt wie immer gerade zur rechten Zeit.\n\nDie Illidari ermitteln in Silbermond. Über die Details kann ich nicht offen sprechen, aber Belath Dämmerklinge hat konkret nach Eurer Unterstützung in dieser Sache verlangt.\n\nSoweit ich weiß, hat er zuletzt die oberen Ebenen des Basars untersucht.\n\nSucht ihn auf, wenn Ihr Zeit habt.', 0, 66220), -- Murder Row: Rumors Abound
(90622, 144999, 243226, 'deDE', '$p, Pilzpakt jetzt stärker wirken! Vorbereiteter. Hoffe, sie nicht wieder wegrennen.\n\nNächster Kampf ist gegen Glimmwache. Glimmwache immer nie verlieren.\n\nHoffe, Euer Training Kampf besser machen, bevor Pilzpakt verlieren.\n\nWird Spaß zu sehen!', 3, 66220), -- Not-Yet Defeated Champions
(90622, 144998, 243226, 'deDE', '$p, Wolkenwache jetzt stärker wirken! Vorbereiteter. Hoffe, sie nicht wieder wegrennen.\n\nNächster Kampf ist gegen Glimmwache. Glimmwache immer nie verlieren.\n\nHoffe, Euer Training Kampf besser machen, bevor Wolkenwache verlieren.\n\nWird Spaß zu sehen!', 2, 66220), -- Not-Yet Defeated Champions
(90622, 144997, 243226, 'deDE', '$p, Eisgesporene jetzt stärker wirken! Vorbereiteter. Hoffe, sie nicht wieder wegrennen.\n\nNächster Kampf ist gegen Glimmwache. Glimmwache immer nie verlieren.\n\nHoffe, Euer Training Kampf besser machen, bevor Eidgesporene verlieren.\n\nWird Spaß zu sehen!', 1, 66220), -- Not-Yet Defeated Champions
(90622, 144996, 243226, 'deDE', '$p, Ringkappen jetzt stärker wirken! Vorbereiteter. Hoffe, sie nicht wieder wegrennen.\n\nNächster Kampf ist gegen Glimmwache. Glimmwache immer nie verlieren.\n\nHoffe, Euer Training Kampf besser machen, bevor Ringkappen verlieren.\n\nWird Spaß zu sehen!', 0, 66220), -- Not-Yet Defeated Champions
(92617, 144999, 0, 'deDE', 'Erst Tuktuk rennt, dann Brakko rennt. Darf nicht Einziger sein, der noch kämpft!\n\nAllein Ziny verliert. Kampf ist zu schwer, allein nicht stark genug.\n\nWill nicht verlieren. Darf Pilzpakt nicht enttäuschen!\n\nHatte die Wahl, scheitern oder wegrennen.\n\nAber wegrennen war auch verlieren. Ziny sehr, sehr traurig für $p.\n\nKönnen üben, große und gruselige Feinde zusammen bekämpfen?', 3, 66220), -- Mushrooming Resilience
(92617, 144998, 0, 'deDE', 'Erst Tuktuk rennt, dann Brakko rennt. Darf nicht Einziger sein, der noch kämpft!\n\nAllein Ziny verliert. Kampf ist zu schwer, allein nicht stark genug.\n\nWill nicht verlieren. Darf Wolkenwache nicht enttäuschen!\n\nHatte die Wahl, scheitern oder wegrennen.\n\nAber wegrennen war auch verlieren. Ziny sehr, sehr traurig für $p.\n\nKönnen üben, große und gruselige Feinde zusammen bekämpfen?', 2, 66220), -- Mushrooming Resilience
(92617, 144997, 0, 'deDE', 'Erst Tuktuk rennt, dann Brakko rennt. Darf nicht Einziger sein, der noch kämpft!\n\nAllein Ziny verliert. Kampf ist zu schwer, allein nicht stark genug.\n\nWill nicht verlieren. Darf Eidgesporene nicht enttäuschen!\n\nHatte die Wahl, scheitern oder wegrennen.\n\nAber wegrennen war auch verlieren. Ziny sehr, sehr traurig für $p.\n\nKönnen üben, große und gruselige Feinde zusammen bekämpfen?', 1, 66220), -- Mushrooming Resilience
(92617, 144996, 0, 'deDE', 'Erst Tuktuk rennt, dann Brakko rennt. Darf nicht Einziger sein, der noch kämpft!\n\nAllein Ziny verliert. Kampf ist zu schwer, allein nicht stark genug.\n\nWill nicht verlieren. Darf Ringkappen nicht enttäuschen!\n\nHatte die Wahl, scheitern oder wegrennen.\n\nAber wegrennen war auch verlieren. Ziny sehr, sehr traurig für $p.\n\nKönnen üben, große und gruselige Feinde zusammen bekämpfen?', 0, 66220), -- Mushrooming Resilience
(92616, 144999, 0, 'deDE', 'Brakko tut leid, dass Brakko $p und Pilzplakette enttäuscht hat.\n\nBrakko solche Angst vor Sporengleitern. Könnten hoch über Brakkos Kappe anschleichen, wo Brakko nicht sieht. Könnten Kappe ganz Aua machen!\n\nBrakko traurig, $p. Brakko denkt nicht, dass Brakko guter Tank für Team sein kann.\n\nAußer... $p übt mit Brakko?', 3, 66220), -- Mushrooming Courage
(92616, 144998, 0, 'deDE', 'Brakko tut leid, dass Brakko $p und Wolkenwache enttäuscht hat.\n\nBrakko solche Angst vor Sporengleitern. Könnten hoch über Brakkos Kappe anschleichen, wo Brakko nicht sieht. Könnten Kappe ganz Aua machen!\n\nBrakko traurig, $p. Brakko denkt nicht, dass Brakko guter Tank für Team sein kann.\n\nAußer... $p übt mit Brakko?', 2, 66220), -- Mushrooming Courage
(92616, 144997, 0, 'deDE', 'Brakko tut leid, dass Brakko $p und Eidgesporene enttäuscht hat.\n\nBrakko solche Angst vor Sporengleitern. Könnten hoch über Brakkos Kappe anschleichen, wo Brakko nicht sieht. Könnten Kappe ganz Aua machen!\n\nBrakko traurig, $p. Brakko denkt nicht, dass Brakko guter Tank für Team sein kann.\n\nAußer... $p übt mit Brakko?', 1, 66220), -- Mushrooming Courage
(92616, 144996, 0, 'deDE', 'Brakko tut leid, dass Brakko $p und Ringkappen enttäuscht hat.\n\nBrakko solche Angst vor Sporengleitern. Könnten hoch über Brakkos Kappe anschleichen, wo Brakko nicht sieht. Könnten Kappe ganz Aua machen!\n\nBrakko traurig, $p. Brakko denkt nicht, dass Brakko guter Tank für Team sein kann.\n\nAußer... $p übt mit Brakko?', 0, 66220), -- Mushrooming Courage
(90620, 144999, 243226, 'deDE', 'Pilz... pakt? Komischer Name. Wer ausgesucht?\n\nKeinen Kopf machen. Na gut, bereit?\n\nIhr und Pilzpakt gehen runter, wir sagen Wörter.\n\nIhr kämpft mit Sporensturm. Wenn Sieg, Ihr kämpft mit Kappenkampf.\n\nWenn Sieg, Ihr kämpft mit Pilzprüglern.\n\nGroßer Endsieger: Glimmwache. Ihr nicht besiegen könnt.\n\nNicht weglaufen! Weglaufen ist große, große Verlierung.', 3, 66220), -- To the Ring
(90620, 144998, 243226, 'deDE', 'Wolkenwache? Nicht schlecht. Mir gefallen.\n\nNa gut, bereit?\n\nIhr und Wolkenwache gehen runter, wir sagen Wörter.\n\nIhr kämpft mit Sporensturm. Wenn Sieg, Ihr kämpft mit Kappenkampf.\n\nWenn Sieg, Ihr kämpft mit Pilzprüglern.\n\nGroßer Endsieger: Glimmwache. Ihr nicht besiegen könnt.\n\nNicht weglaufen! Weglaufen ist große, große Verlierung.', 2, 66220), -- To the Ring
(90620, 144997, 243226, 'deDE', 'Eidgesporene? Nicht schlecht. Mir gefallen.\n\nNa gut, bereit?\n\nIhr und Eidgesporene gehen runter, wir sagen Wörter.\n\nIhr kämpft mit Sporensturm. Wenn Sieg, Ihr kämpft mit Kappenkampf.\n\nWenn Sieg, Ihr kämpft mit Pilzprüglern.\n\nGroßer Endsieger: Glimmwache. Ihr nicht besiegen könnt.\n\nNicht weglaufen! Weglaufen ist große, große Verlierung.', 1, 66220), -- To the Ring
(90620, 144996, 243226, 'deDE', 'Ringkappen? Nicht schlecht. Mir gefallen.\n\nNa gut, bereit?\n\nIhr und Ringkappen gehen runter, wir sagen Wörter.\n\nIhr kämpft mit Sporensturm. Wenn Sieg, Ihr kämpft mit Kappenkampf.\n\nWenn Sieg, Ihr kämpft mit Pilzprüglern.\n\nGroßer Endsieger: Glimmwache. Ihr nicht besiegen könnt.\n\nNicht weglaufen! Weglaufen ist große, große Verlierung.', 0, 66220), -- To the Ring
(86846, 136316, 238072, 'deDE', '$p, Etrigg hat mir erzählt, wie Ihr dazu beigetragen habt, Hammerfall zu retten und die Rote Dämmerung aufzuhalten.\n\nIch arbeite zusammen mit Sonnenläufer Malu und Sonnenläuferin Nadura daran, ihnen nach dem Angriff bei der Erholung und dem Neuaufbau zu helfen.\n\nSie sammeln zum Beispiel aus verschiedenen Quellen Materialien für die Handwerker Hammerfalls.\n\nWenn Ihr diese Vorräte überbringen könntet, wäre uns das eine große Hilfe.', 0, 66192), -- Resupplying Our Suppliers
(86841, 135389, 237594, 'deDE', 'Alonsus hat mir berichtet, dass Ihr Relikte heiliger Kraft sucht, Hochlord. Um jene zu unterstützen, die mit ihrem Ritual die Leere zurückhalten.\n\nNehmt, was Ihr braucht, um dem Licht zu dienen, und lasst mich wissen, falls Ihr noch etwas benötigt.', 0, 66192), -- Relics of Paladins Past
(86840, 135389, 237594, 'deDE', 'Hochlord $p! Fast alle unserer Paladine wurden in den Kampf gegen die Leere gerufen. Ich kann nur spekulieren, warum ich nicht dazugehörte.\n\nDoch infolgedessen hat sich eine recht große Streitmacht der Geißel rund um die Kapelle versammelt. Wenn Darion nicht Hilfe aus Acherus geschickt hätte, wären wir bereits überwältigt worden, aber sie können nur gerade so die Front halten.\n\nVerschafft uns eine Atempause, Hochlord. Besiegt so viele von ihnen, wie Ihr könnt.', 0, 66192), -- Flickering Hope
(87308, 134204, 237504, 'deDE', 'Die Überreste des Schattenhammers sammeln sich unter einem neuen Banner. Sie kriechen aus ihren Löchern, um der Zwielichtklinge und ihrer neuen Herrin Xal\'atath die Treue zu schwören.\n\nWir dürfen das nicht zulassen. Merzt sie aus.\n\n<Rommath hält inne und seine Augen verengen sich.>\n\nGlaubt nicht, dass mir Eure Besudelung entgangen ist oder dass Eure Taten das wettmachen, $n.\n\nIhr mögt alle anderen täuschen, vielleicht sogar Euch selbst, aber mit der Leere kann es keine Koexistenz, kein Übereinkommen geben.\n\nEs wäre gnädiger für Euch, auf demselben Scheiterhaufen wie sie zu enden.', 0, 66192), -- Twilight's Dawn
(90882, 0, 244642, 'deDE', 'Lok\'tar, $n.\n\nJaina und ich waren in der Gegend, als uns Berichte über einen massiven Gnollangriff auf Hammerfall erreichten.\n\nWir könnten Eure Hilfe dabei gebrauchen, die Gnolle hier zu eliminieren, während wir den Verwundeten helfen und unser weiteres Vorgehen planen.', 1, 66192), -- Gnoll Way
(90882, 0, 244643, 'deDE', 'Gut, dass Ihr da seid, $n.\n\nThrall und ich waren in der Gegend, als uns Berichte über einen massiven Gnollangriff auf Hammerfall erreichten.\n\nWir könnten Eure Hilfe dabei gebrauchen, die Gnolle hier zu eliminieren, während wir den Verwundeten helfen und unser weiteres Vorgehen planen.', 0, 66192), -- Gnoll Way
(72591, 40576, 202656, 'deDE', '$n, wie ich höre, habt Ihr ein gutes Verhältnis zu den Zentauren der Ebenen von Ohn\'ahra aufgebaut. Ich möchte Euch um einen Gefallen bitten.\n\nBaine ist vor ein paar Tagen zu den Ebenen aufgebrochen, um eine Gruppe vermisster Tauren zu suchen. Ich bot an, ihn zu begleiten, aber er bestand darauf, allein zu gehen.\n\nDie Tauren von Donnerfels verbindet eine blutige Geschichte mit den Zentauren von Kalimdor, wie Ihr wisst. Die Zentauren der Maruuk sind zwar nicht mit ihnen verwandt, aber ich mache mir dennoch Sorgen.\n\nEure Anwesenheit könnte dazu beitragen, die Spannungen zu verringern. Hoffe ich.', 0, 66017), -- A Debt That Must Be Paid
(90765, 134204, 237504, 'deDE', 'Die Aktivitäten des Kultes in der Gegend haben deutlich zugenommen. Während wir Truppen aufstellen, werdet Ihr Euch eine Kultistenverkleidung besorgen und ihr Ausbildungsgelände in der Nähe infiltrieren.\n\nFindet so viel wie möglich über die Zwielichtklinge und ihre Ziele heraus. Ich werde die Sicherheit hier überwachen.\n\nSolltet Ihr es wagen, Euch tatsächlich der Zwielichtklinge anzuschließen, dann seid gewiss, dass unsere Streitkräfte Euren Umtrieben mit der Leere ein dauerhaftes Ende bereiten werden.', 0, 66017); -- Midnight Dress
