INSERT INTO `quest_offer_reward_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(90822, 139932, 0, 'deDE', 'Da es niemanden mehr gibt, der sie leiten kann, hat sich diese Handelsoperation mit Teufelsmagie wohl erledigt... zumindest für den Moment.\n\nIch muss zugeben, dass ich mir Eurer Absichten nicht sicher war, aber Ihr habt Euch meinen Respekt verdient, $n.', 1, 66384), -- Murder Row: One Fel Swoop
(90822, 42788, 0, 'deDE', 'Da es niemanden mehr gibt, der sie leiten kann, hat sich diese Handelsoperation mit Teufelsmagie wohl erledigt... zumindest für den Moment.\n\nEs war mir eine Ehre, Zeuge Eurer Arbeit zu werden, $ct $n.', 0, 66384), -- Murder Row: One Fel Swoop
(88703, 42890, 239826, 'deDE', 'Wir müssen jagen und sie schicken mir $geinen Jäger:eine Jägerin;. Perfekt.', 0, 66384), -- The Night Before
(91627, 47452, 0, 'deDE', 'Ah, $n! Es ist lange her. Viel zu lange. Willkommen in meinem Hafen. Einer Zuflucht, in der man seit den Tagen Anasterians den Wirbel der Welt vergessen kann.\n\nEinige halten dies lediglich für eine frivole Party. Doch auf dieser güldenen Lichtung wurden bei Wein Entscheidungen getroffen, die die Geschicke ganzer Generationen geprägt haben.', 0, 66263), -- Saltheril's Haven
(86559, 54203, 0, 'deDE', 'Die übrigen Leerenelfen wurden ausgesandt, um Stützpunkte aufzubauen oder die Gegend auszukundschaften.\n\nIch habe... gemischte Gefühle, was Allerias Anwesenheit betrifft. Wie bei Euch sind ihre Fähigkeiten und Erfahrung von unschätzbarem Wert für uns, und trotzdem...\n\nDie Leere in ihr ist sogar noch stärker als in Euch... das macht mir Sorgen. Behaltet sie im Auge.\n\nDer Leere kann man NIEMALS vertrauen.', 0, 66263), -- The Far, Far Frontier
(86557, 54203, 0, 'deDE', 'Finstere Kreaturen. Habt Ihr es auch gespürt?\n\nIhnen allen haftet der Gestank der Leere an.\n\n<Lothraxion verzieht den Mund.> \n\nWie Euch auch.', 0, 66263), -- A Matter of Strife and Death
(86558, 54203, 0, 'deDE', 'Ihr Leerenelfen riskiert Verderbnis, aber Ihr könnt die Welt um uns herum noch am besten verstehen. Wir brauchen Euer Wissen, können Euch aber nicht vertrauen.\n\nEs behagt mir nicht, aber ich habe bereits mehr Späher angefordert.', 0, 66263), -- Save a Piece of Mind
(86549, 54203, 0, 'deDE', 'Diese... diese Macht! Noch nie konnte ich die Leere so fühlen. \n\nSie ist so überwältigend wie bei der Schlacht in Telogrus... \n\nAber Ihr habt es überstanden. Wir alle können das. Wir sind Ren\'dorei.', 0, 66263), -- No Fear of the Dark
(92496, 146074, 0, 'deDE', 'Ihr habt unser Land gegen die Zwielichtklinge verteidigt un\' uns\'rem Stamm große Ehre gebracht.\n\nAber Idago is\' nich\' erfreut darüber, dass ich zurück bin.', 0, 66263), -- Spears Against de Shadow
(92493, 148087, 251669, 'deDE', 'Idago wurde in die Gruft gebracht! Sie sag\'n, der große Boss Mish\'mosh hat was Übles für ihn geplant.', 0, 66263), -- What Remains of Idago
(89204, 42230, 0, 'deDE', 'Sauber und präzise. Ich habe seit meiner Kindheit gestohlen, um über die Runden zu kommen, aber ich habe nicht oft Komplizen.\n\nVielleicht kann ich mich eines Tages revanchieren. Ihr sehr aus, als hättet Ihr einige Tricks auf Lager.', 0, 66263), -- Five Finger Discount
(90669, 39987, 0, 'deDE', 'Ah, die Schurkin konnte also einen Hexenmeister auftreiben? Erfreut, Euch kennenzulernen. \n\nIhr seht recht fähig aus. Reden wir.', 1, 66220), -- Gold is Gold
(90669, 145390, 0, 'deDE', 'Ah, die Schurkin hat einen ihrer... Handlanger geschickt.\n\nIhr seht fähig genug aus, schätze ich. Reden wir.', 0, 66220), -- Gold is Gold
(90818, 140111, 0, 'deDE', '<Belaths Blick verfinstert sich stärker als üblich.>\n\nAngst verleitet die Leute zu verzweifelten Taten, aber Teufelsmagie ist keine Waffe, die man leichtfertig führen sollte.\n\nDiese Macht hat einen Preis. Doch sie können ihn weder verstehen, noch sind sie dafür ausgebildet, diesen Gefahren zu trotzen. Nicht so wie Ihr und ich.', 0, 66220), -- Murder Row: Loose Lips
(90835, 95784, 0, 'deDE', '$ct, Ihr kommt genau rechtzeitig.\n\nIch fasse mich kurz: Ich glaube, in Silbermond wird wieder vermehrt Teufelsmagie gebraucht. Und das muss aufhören.', 0, 66220), -- Murder Row: Rumors Abound
(86841, 135389, 237594, 'deDE', 'Ihr habt gefunden, was Ihr brauchtet, Hochlord $p?', 0, 66192), -- Relics of Paladins Past
(86839, 135389, 0, 'deDE', 'Hochlord $p!\n\nFast alle der Paladine hier wurden zum Sonnenbrunnen gerufen, um gegen die Leere zu kämpfen. Wir könnten also Eure Hilfe gebrauchen.', 0, 66192); -- Relics of Light's Hope
INSERT INTO `quest_request_items_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(92497, 146074, 251522, 'deDE', 'Ich danke Euch, $n. Für Eure Hilfe bei meiner Befreiung un\' dafür, dass Ihr auf sie hier aufgepasst habt.', 0, 66263), -- Simply Magical
(92493, 148087, 0, 'deDE', 'Bruchhauersegge wimmelt von dies\'n widerlich\'n Magiern. Ihr tut das Werk der Loa.', 0, 66263), -- What Remains of Idago
(87254, 141320, 0, 'deDE', 'Das Leberritual hat nich\' funktioniert?', 0, 66263), -- Curse Cleanse
(91271, 142157, 245745, 'deDE', 'Bei dem hab ich ein tolles Gefühl!', 0, 66263); -- A Fish!
