INSERT INTO `quest_template_locale` (`ID`, `locale`, `LogTitle`, `LogDescription`, `QuestDescription`, `AreaDescription`, `PortraitGiverText`, `PortraitGiverName`, `PortraitTurnInText`, `PortraitTurnInName`, `QuestCompletionLog`, `VerifiedBuild`) VALUES
(86853, 'deDE', 'Funken des Krieges: Lorenhall', 'Sammelt bei aktivem Kriegsmodus $1oa Funken des Krieges in Lorenhall.', 'Untersucht Lorenhall! Berichten zufolge gibt es im Gebiet einen wachsenden Konflikt. Geht da raus und schaut Euch die Sache an.', '', '', '', '', '', 'Sprecht mit Grobius in Dornogal.', 65727),
(86945, 'deDE', 'Schattenvorräte', '', '', '', '', '', '', '', '', 65727),
(53250, 'deDE', 'Spenden für das Arathihochland: Kriegsrolle der Seelenstärke', '', '', '', '', '', '', '', '', 65512);
INSERT INTO `quest_offer_reward_locale` (`ID`, `locale`, `RewardText`, `VerifiedBuild`) VALUES
(84713, 'deDE', 'Ich glaube, wir haben herausgefunden, wo sich die Rote Dämmerung versteckt hat.', 65727),
(84712, 'deDE', 'Es ist entschieden.\n\nWenn wir den Krieg verhindern wollen, müssen wir die Allianz über die Lage informieren und Danath so schnell wie möglich retten.', 65727),
(84711, 'deDE', 'Dies war keine Schlacht. Es war ein Hinterhalt und ein Massaker.', 65727),
(84710, 'deDE', 'Joseph ist erneut entkommen und diesmal war seine Warnung noch viel unheilvoller. Er hat Dunkelheit in seinem Geist... und in seiner Seele.\n\nIch bin... verwirrt. Wie kann er behaupten, dem Licht zu folgen?', 65727),
(84709, 'deDE', 'Gut. Hammerfall gehört wieder uns, und das Syndikat hat eine wichtige Lektion gelernt.', 65727),
(85451, 'deDE', 'Hah! So stark wie Orcs!\n\nSo wie wir!', 65727),
(84708, 'deDE', 'Ich hätte hier sein sollen. Ich hätte etwas tun können.\n\n<Glühendheiße Wut und Zorn gehen von Geya\'rahs angespannter Haltung und ihren geballten Fäusten aus.>', 65727),
(84705, 'deDE', 'Bah.\n\nDas wird sie sicherlich einschüchtern. Es würde mich wundern, wenn ich in nächster Zukunft einen von ihnen außerhalb ihres Dorfes sehen würde.', 65727),
(84706, 'deDE', 'Barclay hat Glück, dass Ihr seine Brüder rechtzeitig erreicht habt.', 65727),
(84707, 'deDE', 'Faerin hat mich von Danaths Verschwinden unterrichtet. Obwohl das... beunruhigend ist... können wir noch nicht nach Hammerfall zurückkehren.', 65727),
(84704, 'deDE', 'Ich habe nie wirklich erkannt, wie viel mein Volk mit den Orcs gemein hat. Wir sind beide fern der Heimat, wir sind beide autark, wir sind beide Völker, die in den Krieg hineingeboren wurden...\n\nUnd vor allem ihr Sinn für Pflicht und Ehre ist dem unseren ebenbürtig.\n\nIch fühle mich hier... fast mehr zu Hause als in Stromgarde.', 65727),
(84656, 'deDE', 'Wenn Danath nicht hier ist... Wo ist er dann?', 65727),
(84652, 'deDE', 'Gut, $n.\n\nIch hoffe, Stromgarde nimmt es uns nicht übel, dass wir diese Vorräte für ihre Flüchtlinge \"borgen\".\n\nHeh.', 65727),
(84651, 'deDE', 'Er ist entkommen?\n\n<Karga spuckt auf den Boden.>', 65727),
(84650, 'deDE', 'Noch ein Banditenangriff? Und sie tragen das gleiche Emblem wie die Halunken bei Neuhof?\n\nWenn das mit der Roten Dämmerung und Marran zu tun hat...', 65727),
(84649, 'deDE', 'Marran mag nun im Gefängnis sitzen, aber ihre Unterstützer verbreiten ihre hasserfüllten Ansichten weiter im ganzen Hochland.\n\nWas immer sie behaupten mag, ich glaube nicht, dass sie Anführerin dieser \"Roten Dämmerung\" ist, von der Ihr beide sprecht.\n\nIch behalte im Blick, wer kommt und geht. Sie bekommt keine Besucher von außerhalb.', 65727),
(84643, 'deDE', 'Es ist wirklich entsetzlich. Sie versuchen, rechtschaffene Bürger einzuschüchtern und zu vertreiben, bloß weil sie keine Menschen sind. Und wenn jemand widerspricht, wird er vom Mob niedergebrüllt.\n\nViele versuchen, ihnen aus dem Weg zu gehen, aber sie postieren sich mit Absicht dort, wo man ihnen nicht entgehen kann.', 65727),
(84645, 'deDE', 'Ihr habt meinen Dank und den Dank von Stromgarde.\n\nEs tut mir leid, dass Ihr Euch Josephs Gemecker anhören musstet, aber wenigstens hat er friedlich das Feld geräumt.\n\nAuch wenn es nicht den Anschein erweckt, ist die Stadt Lord Trollbann weiterhin treu ergeben. Größtenteils.\n\nMarrans Anhänger sind bloß eine laute und wütende Minderheit.', 65727),
(84641, 'deDE', 'Es ist viel schlimmer, als ich dachte. Nach den Angriffen auf unsere Versorgungslinien sind die Leute wütend und hungrig... und sie suchen nach einem Schuldigen. Unsere Nachbarn in Hammerfall sind da leider die naheliegende Wahl.\n\nWir dürfen nicht zulassen, dass diese Unruhen weitergehen. Ich muss mit Nials und meinen Beratern sprechen.\n\nWie ich sehe, hat Faerin ihre und Eure Hilfe angeboten, um die Not in Stromgarde zu lindern. Ich mute Euch nur ungern zu, was im Grunde eine diplomatische Mission ist, aber wenn Ihr Bräustein helfen würdet, während ich mit Nials spreche, hätte ich eine Sorge weniger.', 65727),
(84658, 'deDE', 'Ihr habt sie gefunden! Ihr habt sie wirklich gefunden! Habt tausend Dank!\n\n<Maggie schließt Ellie fest in ihre Arme.>', 65727),
(84639, 'deDE', 'Vielen Dank, $n.\n\nDamit habt Ihr hoffentlich im Keim erstickt, was sie vorhatten.', 65727),
(84640, 'deDE', 'Ich erkenne das Emblem nicht. Einer der Defias trug es an sich, sagt Ihr?\n\nHm. Seltsam.\n\n<Danath dreht und wendet das Abzeichen in seiner vom Kampf gezeichneten Hand, während sich seine Mine verfinstert.>\n\nIch frage mich, was es bedeutet.', 65727),
(84638, 'deDE', 'Mich hatten schon Berichte erreicht, wonach Banditen im Hochland ihr Unwesen treiben, aber... ich wusste nicht, dass es so übel ist.\n\nDass wir mitten in diese Attacke hineingerierten, macht die Sache nun auch nicht mehr schlimmer.\n\nWenn wir der Sache auf den Grund gehen wollen, können wir genauso gut hier beginnen.\n\nIch... wünschte nur, Faerin wäre nicht hier, um es mitanzusehen.', 65727),
(83139, 'deDE', 'Vielleicht will derjenige, der die Mauer gesprengt hat, auch hier unsere Aufmerksamkeit. Wir müssen tiefer graben.', 65727),
(83137, 'deDE', 'Das ist... eine Mautstelle?\n\nSoll das ein Scherz sein?\n\n<Monte Gazlowe verdreht die Augen und lacht leise.>\n\nIch schätze, man kann mit allem Geld machen.', 65727),
(82365, 'deDE', 'Ihr seid eine geschätzte Bereicherung für den Rat, $n. Bitte nehmt dieses Zeichen unserer Dankbarkeit an, auf dass Ihr jetzt und immerdar als Ehrenratsmitglied bekannt sein möget.', 65727),
(83043, 'deDE', 'Dankbarkeit wird ausgedrückt. Bitte nehmt dies als Belohnung für all Eure harte Arbeit.', 65727),
(82383, 'deDE', 'Dankbarkeit wird ausgedrückt. Bitte nehmt dies als Belohnung für all Eure harte Arbeit.', 65727),
(82375, 'deDE', 'Dankbarkeit wird ausgedrückt. Bitte nehmt dies als Belohnung für all Eure harte Arbeit.', 65727),
(85539, 'deDE', 'Dankbarkeit wird ausgedrückt. Bitte nehmt dies als Belohnung für all Eure harte Arbeit.', 65727),
(82333, 'deDE', 'Aufgabe abgeschlossen. Der Rat belohnt Euch für Eure Hilfe bei der Wiedervereinigung der Irdenen.', 65727),
(91795, 'deDE', 'Diese Kämpfer der Zwielichtklinge sind genauso töricht wie die anderen Mitglieder des Kultes. Mit der Zeit werden wir sie alle vernichten.', 65727),
(87308, 'deDE', 'Sie haben nichts anderes verdient.', 65727),
(90768, 'deDE', 'Dass sie eine schändliche Allianz mit Xal\'atath eingegangen sind, ist nun klar. Jetzt schalten wir sie aus.', 65560),
(90767, 'deDE', 'Irgendwie passend, dass sich der Schattenhammerkult erneut mit einem Wesen verbündet, das es auf den Weltuntergang abgesehen hat.', 65560),
(90766, 'deDE', 'Ausgezeichnet. Jetzt seht Ihr aus wie $gein wahrer Akolyth:eine wahre Akolythin; der Zwielichtklinge.', 65560),
(90765, 'deDE', 'Ihr seht nicht aus, als wärt Ihr bereit, Xal\'atath zu dienen. Das werden wir beheben.', 65560),
(90763, 'deDE', 'Gut, Ihr seid da. \n\nBehaltet unsere Verbündeten im Auge. Wir mögen zwar gemeinsame Sache machen, um die Zwielichtklinge aufzuhalten, doch die Leere kann heimtückisch sein. \n\nMan kann ihnen nicht völlig vertrauen.', 65560),
(90761, 'deDE', 'Der strahlende Gesang wirft einen langen, dunklen Schatten auf Azeroth. Und die Zwielichtklinge nutzt dies zu ihrem Vorteil.\n\nWir haben viel zu tun.', 65560),
(90764, 'deDE', 'Da seid Ihr ja. Sehr gut. Wir dürfen nicht zulassen, dass die Zwielichtklinge in der Stadt Fuß fasst.', 65560),
(90972, 'deDE', 'Adarus schickt Euch? \n\nSein mangelndes Vertrauen in meine Fähigkeiten und seine Unfähigkeit, Aufgaben zu delegieren, sprechen Bände.', 65512),
(94933, 'deDE', 'Es freut mich, dass Ihr Euch entschieden habt, hier zu mir zu stoßen, $n.', 65512),
(85002, 'deDE', 'Danke, dass Ihr mich begleitet habt, $n. Ich weiß, dass ich noch viel zu lernen habe. Ich möchte nur meinem Namen gerecht werden.\n\nNun müssen wir nur noch meine Mutter auf dieser zersplitterten Welt finden.', 65512),
(84998, 'deDE', 'Der Schmerz lässt ein wenig nach, aber einen Moment brauche ich noch.', 65512),
(85001, 'deDE', 'Ich bin nicht sicher, wieso diese Kultisten es auf meine Familie abgesehen haben, aber sie werden scheitern!', 65512);
INSERT INTO `quest_objectives_locale` (`ID`, `locale`, `QuestId`, `StorageIndex`, `Description`, `VerifiedBuild`) VALUES
(457610, 'deDE', 86945, 0, 'Vorräte der Zwielichtklinge zerstört', 65727);
INSERT INTO `quest_request_items_locale` (`ID`, `locale`, `CompletionText`, `VerifiedBuild`) VALUES
(90767, 'deDE', 'Habt Ihr mehr über die Pläne des Kults herausgefunden?', 65727),
(90765, 'deDE', 'Ihr wirkt verloren, Schlüpfling. Solltet Ihr nicht irgendwo sein?', 65727),
(84650, 'deDE', 'Es ist schön zu erleben, wie Menschen und Orcs zusammenkommen, um einander zu helfen.\n\nWenn bloß die Arathi hier hätten sehen können, was ich in Khaz Algar gemacht habe.', 65727),
(84643, 'deDE', 'Ich sehe ein, dass Ausgangssperren unbeliebt sind, aber wir brauchen sie gerade wirklich.', 65727),
(84658, 'deDE', 'Ellie muss so verängstigt sein!', 65727),
(84639, 'deDE', 'Ich hoffe, was immer sie im Schilde führen, hat nichts mit meinen Nachbarn zu tun. Oder mit Stromgarde!', 65727),
(85001, 'deDE', 'Diese armen Seelen sind ohne eigenes Verschulden in Gefahr geraten!', 65512);
