INSERT INTO `quest_description_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(85011, 130863, 231266, 'deDE', 'Während Ihr unterwegs wart, war ich so frei, mich umzuhören. Diese Mittler scheinen ja recht freundlich zu sein, aber wir müssen vorsichtig sein. Die Stadt wird von einer Gruppe Astraler angegriffen, die sich die Schattenwache nennt.\n\nIch konnte einen Hinweis auf einige Händler bekommen, die Mutter möglicherweise vor Kurzem begegnet sind.\n\nWir sollten aufbrechen, bevor sich ihre Spur verliert.', 0, 65727), -- Where in K'aresh is Alleria Windrunner?
(76113, 923, 0, 'deDE', '<Das Funkeln eines entfernten Objekts zieht Eure Aufmerksamkeit auf sich. Ihr erinnert Euch plötzlich, dass Ihr Devisen für den Handelsposten Zen\'shiri sammeln müsst.>', 0, 65727), -- Report to the Trading Post
(90763, 134204, 246158, 'deDE', 'Ich habe Nachricht von Magister Umbric erhalten. Er hat ähnliche Anzeichen dafür gefunden, dass die Zwielichtklinge auch in Sturmwind rekrutiert.\n\nDie Leere stellt für ganz Azeroth eine existenzielle Bedrohung dar, ob Ihr es wahrhaben wollt oder nicht.\n\nDer Kult versammelt sich im Schattenhochland. Trefft mich und Magister Umbric dort, damit wir unsere Untersuchungen fortsetzen können.', 0, 65560), -- The Twilight Highlands
(90761, 134204, 246158, 'deDE', 'Der Zwielichtkult versucht schon lange, Azeroths Untergang herbeizuführen. Es überrascht mich nicht, dass sie mit Xal\'atath im Bund stehen.\n\nWenn die Zwielichtklinge die Stadtbewohner indoktriniert, müssen wir sie aufhalten. Spürt Kultisten in der Kluft der Schatten auf und macht ihnen ein Ende.\n\nDie Rhetorik des Kultes könnte Euch zusagen. Lasst von Eurer Verbrüderung mit der Leere ab, bis wir Xal\'atath und ihre Zwielichtklinge vernichtet haben.', 0, 65560); -- Avoiding Blame
INSERT INTO `quest_completion_log_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(84714, 129844, 231836, 'deDE', 'Trefft Oberanführerin Geya\'rah im Gefängnis von Ar\'gorok unterhalb der Kaserne.', 0, 65727), -- From Ironforge With Love
(84715, 129844, 231835, 'deDE', 'Trefft Etrigg im Gefängnis von Ar\'gorok unterhalb der Kaserne.', 0, 65727), -- The Search for Danath
(84710, 129545, 231802, 'deDE', 'Trefft Faerin Lothar am Hintertor von Hammerfall.', 0, 65727), -- Once Bitten Twice Shy
(84709, 129545, 231801, 'deDE', 'Trefft Etrigg am Hintertor von Hammerfall.', 0, 65727), -- Hammerfall Down
(85451, 129545, 231803, 'deDE', 'Trefft Oberanführerin Geya\'rah am Hintertor von Hammerfall.', 0, 65727), -- The Burning of Hammerfall
(83142, 125495, 225597, 'deDE', 'Bringt die Bestellungen zu Gazlowe im nordwestlichen Lager der Venture Company.', 0, 65727); -- Order of Magnitude
INSERT INTO `quest_offer_reward_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(90763, 134204, 237504, 'deDE', 'Ihr mögt gemeinsam mit meinen Magistern gegen diese Bedrohung ankämpfen, aber meine Wachsamkeit wird nicht nachlassen. Anhängern der Leere kann man nicht vertrauen.', 0, 65727), -- The Twilight Highlands
(90764, 134204, 246158, 'deDE', 'Wenigstens seid Ihr noch nicht so leerenverwirrt, dass Ihr einer Vorladung nicht Folge leisten würdet.\n\nKommt. Wir dürfen nicht zulassen, dass die Zwielichtklinge in der Stadt an Boden gewinnt.', 0, 65727), -- The Cult Within
(84709, 0, 0, 'deDE', 'Es sind noch einige Versprengte des Syndikats in der Umgebung, doch Hammerfall gehört wieder der Horde!', 0, 65727), -- Hammerfall Down
(87308, 134204, 237504, 'deDE', 'Eines Tages werdet Ihr es sein, auf $gden:die; wir Helden ansetzen, $C. Das wissen wir beide.', 0, 65727); -- Twilight's Dawn
