INSERT INTO `quest_offer_reward_locale` (`ID`, `locale`, `RewardText`, `VerifiedBuild`) VALUES
(64871, 'deDE', 'Wir räumen den Schutt und das Geröll beiseite und stellen sicher, dass kein Dracthyr zurückbleibt.\n\nDoch zuerst müssen wir das Gebiet sichern.', 56461),
(64866, 'deDE', 'Ihr habt unsere Leute geheilt. Gut gemacht.\n\nNun müssen wir uns um den Drachen kümmern.', 56461),
(64865, 'deDE', 'Diese Ausrüstung ist uralt und das Essen zu Staub zerfallen.\n\nDas ergibt keinen Sinn... Diese Rationen hätten eigentlich ein Leben lang halten sollen.\n\nNa ja, wir machen das Beste aus dem, was wir haben.', 56461),
(64863, 'deDE', 'Diese Konstrukte wurden durch die Magie des blauen Drachenschwarms belebt.\n\nDer Erdwächter hätte das nie zugelassen!', 56461),
(64864, 'deDE', '<Azurathel hört sich Euren Bericht an.>\n\nMeine Erinnerungen sind genauso zerrüttet wie die Euren, $n. Aber dafür bleibt jetzt keine Zeit.\n\nWir müssen die Situation einschätzen und einen Plan schmieden.', 56461);
INSERT INTO `quest_request_items_locale` (`ID`, `locale`, `CompletionText`, `VerifiedBuild`) VALUES
(64865, 'deDE', 'Wenn Euer Gedächtnis Euch im Stich lässt, dann greift auf Euer Training zurück.', 56461);
