(214765, 1, 0, 0, 0, 0, 0, 0, 165350, 0, 0, 56311), -- Galenori
(214776, 1, 191716, 0, 0, 0, 0, 0, 0, 0, 0, 56311), -- General Shycura
(214887, 1, 208762, 0, 0, 0, 0, 0, 0, 0, 0, 56311), -- Amirdrassil Sentinel
(216257, 1, 72827, 0, 0, 0, 0, 0, 0, 0, 0, 56311), -- Cylania
