(216423, 1, 0, 0, 0, 0, 0, 0, 178402, 0, 0, 56311), -- Priestess of the Moon
(216759, 1, 20412, 0, 0, 0, 0, 0, 0, 0, 0, 56311), -- Commander Mar'alith
(216951, 1, 197918, 0, 0, 197919, 0, 0, 0, 0, 0, 56311), -- Kalecgos
(217150, 1, 94830, 0, 0, 0, 0, 0, 0, 0, 0, 56311), -- Neltharion Spirit
(217153, 1, 192109, 0, 0, 0, 0, 0, 0, 0, 0, 56311), -- Djaradin Ancestor
