INSERT INTO `quest_template_locale` (`ID`, `locale`, `LogTitle`, `LogDescription`, `QuestDescription`, `AreaDescription`, `PortraitGiverText`, `PortraitGiverName`, `PortraitTurnInText`, `PortraitTurnInName`, `QuestCompletionLog`, `VerifiedBuild`) VALUES
(43609, 'itIT', 'RICERCATO: Signore della Rovina Kazrok', '', '', '', '', '', '', '', '', 56647),
(53278, 'itIT', 'Baccello Fluviale Rigoglioso', '', '', '', '', '', '', '', '', 56647),
(54365, 'itIT', 'Donazioni per Rivafosca: Minerale di Argento della Tempesta', 'Raccogli $1oa Bandiere di Guerra - Spirito della Libertà per Faella al Porto di Boralus.', '', '', '', '', '', '', '', 56647),
(54371, 'itIT', 'Donazioni per Rivafosca: Spargipiaga Termoaccelerato', 'Raccogli $1oa Bardature di Cuoio Grezzo per Charlane al Porto di Boralus.', 'In battaglia non dobbiamo proteggere solo i nostri alleati, ma anche i nostri amici a quattro zampe!\n\nPuoi assicurarti che le nostre cavalcature ricevano le migliori bardature possibili?', '', '', '', '', '', '', 56647),
(53292, 'itIT', 'Pruno di Sirena Germogliante', '', '', '', '', '', '', '', '', 56819),
(53271, 'itIT', 'Muschio Stellare Germogliante', '', '', '', '', '', '', '', '', 56647);
INSERT INTO `quest_offer_reward_locale` (`ID`, `locale`, `RewardText`, `VerifiedBuild`) VALUES
(26229, 'itIT', 'Quanto è DOLCE il sapore della giustizia! La morte di quei Coboldi non mi farà camminare di nuovo come una volta e sicuramente non mi aiuterà a trovare un lavoro, ma dannazione, ora mi sento molto meglio.$b$b<Jimb prende qualcosa da una vecchia sacca.>$b$bEcco qualcosa che ho preso quando andavo a caccia di Coboldi. Magari ti tornerà utile.', 56311),
(176, 'itIT', 'COSA ha fatto?!?$B$BMagnifico, ora abbiamo una bestia assetata di sangue proprio sotto le strade di Roccavento, con un intero esercito di Gnoll ai suoi ordini. Davvero un bel passo avanti... mi sento già molto più sicuro.$B$BEcco la tua ricompensa, $n. Promettimi però che andrai a controllare le Guardie delle Segrete a Roccavento, giusto per essere sicuri che non ci siano problemi.', 56288),
(16, 'itIT', 'Grazie, $n! Torna se vuoi fare un altro scambio.', 56288),
(65795, 'itIT', 'Abbiamo molto di cui discutere, noi due.', 56513),
(65794, 'itIT', 'Le Pozze della Vita sono nuovamente piene, soprattutto grazie a te.\n\nOra che abbiamo portato a termine la nostra missione, la Pietra del Giuramento risplende ancora una volta come simbolo della nostra vocazione.', 56513),
(65791, 'itIT', 'Il futuro di tutti gli stormi è ora al sicuro.', 56513),
(66788, 'itIT', 'Grazie, $n. Sento che abbiamo nuovamente un futuro.', 56513),
(66785, 'itIT', 'Riesci a crederci?', 56513),
(65793, 'itIT', 'Hai servito in modo ammirevole, $R.', 56513),
(66779, 'itIT', 'Spero tu capisca, adesso.', 56513),
(66780, 'itIT', 'Di sicuro sei d\'accordo con me, non è così, $n?', 56513),
(66057, 'itIT', 'Questo complica le cose, ma non mi verrà negato ciò che mi spetta di diritto!', 56513),
(72135, 'itIT', 'Questi oggetti sono magnifici, c\'è una miniera di informazioni che aspettano di essere studiate!', 56513),
(66354, 'itIT', 'I pezzi danneggiati della Pietra del Giuramento sono stati riparati! Questo è solo l\'inizio di quello che possiamo fare.\n\nCon la forgia nuovamente accesa, posso iniziare a creare nuove armi e armature per contribuire ai nostri sforzi.', 56513),
(66056, 'itIT', 'Molto bene. Ora, con l\'arrivo del principe, possiamo iniziare.', 56513),
(66055, 'itIT', 'Dovrebbe esserci tutto. Penso che possiamo fare le riparazioni!', 56513),
(66049, 'itIT', 'È un contrattempo, ma con il tuo aiuto potremo sicuramente riparare la Pietra del Giuramento. Lavora con Bazentus... fai in modo avvenga.', 56513),
(66044, 'itIT', 'Ben fatto, $n. Sabellian e le sue forze respingeranno i Djaradin, mentre io attiverò la Pietra del Giuramento per ripristinare il potere.', 56513),
(65939, 'itIT', 'Eccellente, $n! Le forze dei Djaradin sono in rotta! Abbiamo il controllo del cortile superiore della cittadella. Conquistare le cripte al di sotto potrebbe richiedere molto più tempo.', 56513),
(65956, 'itIT', 'La nostra avanzata li sta respingendo! Non rimane che fare breccia nei cancelli.', 56513),
(65957, 'itIT', 'Hai dimostrato di essere $gil vero eroe:la vera eroina; della giornata, $n.', 56513),
(66078, 'itIT', 'Credo che i Grinfianera siano pronti a tutto.', 56513),
(66048, 'itIT', 'Capisco. Ovviamente, esaminerò attentamente la tua valutazione.', 56513),
(66559, 'itIT', 'Sembra che tu sia $griuscito:riuscita; a riportarci il nostro Nano. E tutto intero, poi. A nome della nostra squadra e della Spedizione delle Scaglie di Drago, ti ringrazio.\n\nDaremo qualcosa da bere a Mordigan e poi inizieremo a fare i bagagli.\n\nIn queste colline non c\'è altro che sangue e sale.', 56647),
(66187, 'itIT', 'Una soluzione inelegante, ma apprezzo il tuo modo di pensare e la tua... intraprendenza.', 56647),
(66177, 'itIT', 'Ti sei $gdato:data; da fare. Anch\'io.', 56647),
(66232, 'itIT', 'Questi ci saranno molto utili. Potremmo anche permettere ai tuoi amici di stare nei paraggi...', 56647),
(66175, 'itIT', 'Dicono di aspettarsi l\'inaspettato, ma caspita! Mai visto nulla del genere.', 56647),
(66147, 'itIT', 'Ottimo lavoro! Lo porterò da LOU-C e vedremo cosa potrà ricavarne il suo aggeggio.', 56647),
(66154, 'itIT', 'Be\', chi l\'avrebbe detto. Qualcuno qui ha concluso effettivamente qualcosa. Com\'è che si dice? Due per te, uno per me?\n\n<Rowe prende un sorsetto dall\'ampolla.>\n\nAh, ora sì che si ragiona.', 56647),
(66164, 'itIT', 'Rieccoti qui! Inizierò a riconfigurare il Geoscansionatore 289-07, per farlo funzionare al meglio possibile. Le attuali condizioni del mare non sono esattamente ideali.', 56647),
(70129, 'itIT', 'Santo cielo, che cosa gli hai detto? Non ho mai visto Rowie così grintoso!\n\nGrazie per averlo riportato a casa. Farò del mio meglio per occuparmi di lui al posto di Kaqiata.', 56647),
(66558, 'itIT', 'Grazie per avermi dato una mano, sei gentile.', 56647),
(70871, 'itIT', 'Ecco la tua Rete da Pesca di Iskaara. Fanne buon uso e non prendere dal cerchio della vita mai più di ciò che ti serve per sopravvivere.', 56647),
(66223, 'itIT', 'A Zerbino piaceranno un sacco, e diventeremo migliori amici!', 56647),
(66218, 'itIT', 'Papà dice che tutti gli Gnoll sono pericolosi e cattivi. Ma questo è ancora piccolo!\n\nMamma dice sempre che devo prendermi cura di Nau, e anche lei è piccola.', 56647),
(66217, 'itIT', 'È il ciclo della vita marina. Alcuni li lasciamo stare, per perpetuare la specie. Di altri regoliamo il numero, altri li mangiamo. Tutto in equilibrio.', 56647),
(66210, 'itIT', 'Il tuo amico è un tipo molto curioso! Non si prende mai un attimo per rilassarsi?', 56647),
(66781, 'itIT', 'Perfetto! Preparati ad assistere alla più straordinaria dimostrazione di geologia che tu abbia mai visto!', 56647),
(71234, 'itIT', 'Ancora?\n\nChe gioia.', 56647),
(72435, 'itIT', 'Ti auguro un piacevole soggiorno a Iskaara.\n\nCome puoi vedere, molti di noi sono ottimi artigiani e mercanti, ti consiglio di chiedere in giro e scoprire ciò che la mia gente ha da offrire.', 56647),
(66213, 'itIT', 'Grazie al cielo, una nuova storia.\n\nSentiamo!', 56647),
(70939, 'itIT', 'Anche tu vuoi acquisire la maestria della zuppa, come me?\n\nNon vedo l\'ora di poter guardare oltre il bordo del pentolone! Allora, sarò finalmente abbastanza grande da dirigere un banchetto!\n\nTieni, questo è per te, ti aiuterà nei tuoi viaggi inzuppati! Fammi sapere se vuoi acquistare altro!', 56647),
(65849, 'itIT', 'Sono felice che tu abbia deciso di unirti a noi.\n\nDevo però chiederti di pazientare. C\'è ancora molto da preparare per la cerimonia.', 56647),
(65847, 'itIT', 'Ce l\'abbiamo fatta. Ottimo lavoro, $n. Ora puoi respirare nuovamente aria fresca!\n\nCon la linea di faglia ripristinata e Khadgar che sta per venire a capo del problema alla torre, la Pietra del Giuramento dovrebbe ormai essere alla nostra portata. Devo tornare subito agli Archivi Azzurri.', 56647),
(65848, 'itIT', 'Ben fatto, $geroe:eroina;. Grazie.\n\nQuell\'albero probabilmente non era la loro unica pozza di decadimento, ma era la più pericolosa per i Tuskarr e per questa linea di faglia. Ora che non c\'è più, quest\'area dovrebbe riuscire a riprendersi. Ci vorrà del tempo, ma tornerà com\'era.\n\nSono felice che siamo riusciti a dare un po\' di pace agli spiriti di quei Tuskarr.', 56647),
(65846, 'itIT', 'Cosa ci stavano facendo? Li stavano usando come gratta-schiena?!?\n\n<Kalecgos si stringe l\'attaccatura del naso con le dita.>\n\nImmagino che dovremmo essere semplicemente felici che non abbiano scoperto il loro vero potenziale.', 56647),
(65844, 'itIT', 'Gli Gnoll hanno anche degli aspetti affascinanti! Non sono creature malvagie, solo selvagge. E molto stupide.\n\nÈ un peccato doverli uccidere, ma la decomposizione è un male per tutti quanti. E poi, non possiamo permettere che facciano del male alla nostra famiglia.', 56647),
(65845, 'itIT', 'Quindi tutti hanno deciso di infondere il loro potere nel mio totem?\n\n<Brena chiude gli occhi in preda alla tristezza.>\n\nGrazie, amici miei. Farò buon uso della forza dei vostri spiriti. Gli Gnoll non arriveranno a Iskaara.', 56647),
(66839, 'itIT', 'Oh, questi sono fan-ta-sti-ci! Questo è speziato e quello mi ricorda il bulboterro! Oh, sento già il dolce sapore dell\'idromele.\n\nGrazie di cuore, $gamico mio:amica mia;! Ci hai salvato il pomeriggio!', 56647),
(66838, 'itIT', 'Oh! Queste sono fantastiche. Così lussuose e morbide...\n\nOra, se solo Valdo fosse qui a ripulirle!', 56647),
(66837, 'itIT', 'Grazie a te, e non grazie a Valdo, posso sfamare tutti questi viaggiatori affamati!\n\nMmm... Stai per caso cercando lavoro? Avrei una posizione aperta...\n\nNon ti posso pagare molto, ma puoi avere il posto di Valdo! No? Oh, be\', non biasimarmi per averci provato.', 56647),
(66844, 'itIT', 'Oh, è stato un momento triste per me, ma doveva essere fatto.\n\nEcco, prendi uno dei cuccioli di Shokhari; non posso tenerli tutti. Prenderci cura di loro è il minimo che possiamo fare.\n\nAllevalo con cura.', 56647),
(66843, 'itIT', 'Grazie per averlo trovato. Scommetto che la smetterà di allontanarsi!\n\nEcco un piccolo segno di gratitudine.', 56647),
(71017, 'itIT', '<Difficile dirlo, ma credi di vedere Zannatetra sorridere leggermente, ma si ricompone rapidamente.>\n\nAndrà bene.', 56647),
(71012, 'itIT', 'Ecco Varsek. Avrà risolto il suo enigma?', 56647),
(70936, 'itIT', 'Tu laggiù, giovane! I nostri guerrieri portano con sé degli speciali totem quando si avventurano nelle Isole dei Draghi, per cui i nostri nemici si dilettano nel prenderli come trofei. Non possiamo accettarlo! Ti prego, riportaci tutti i totem che riesci a trovare.', 56647),
(70926, 'itIT', 'Ah! I nostri totem sono molto importanti per noi. Giovane, hai la nostra gratitudine per averceli restituiti!', 56647),
(71016, 'itIT', 'Ma guarda un po\' che nuovo pesciolino ha portato la corrente!\n\nCos\'è quella? Una lettera di Zannatetra?', 56647),
(77097, 'itIT', 'Una donazione alle taverne sulle Isole dei Draghi per coprire il conto!', 56647),
(66270, 'itIT', 'Continueranno a combattere finché non troveranno un nuovo capo? E sia. Se devo stabilire una base operativa qui, vorrà dire che dovremo ucciderli tutti.\n\nIl piano è...\n\nAspetta, te ne stai andando? Non vuoi prendere parte al mio piano? E cosa dovrei fare io? Non posso lasciare questo lago dopo essermi inimicato gli Gnoll!\n\nE va bene! Schierati dalla parte di quei disgraziati sacchi di pulci!\n\nPrendi quello che ti avevo promesso e vattene. Non sei l\'$gunico \"campione\":unica \"campionessa\"; in questi boschi! Troverò qualcun altro che mi aiuti!', 56647),
(66269, 'itIT', 'Avrà funzionato di sicuro, vero?', 56647),
(66268, 'itIT', 'Finalmente! Dev\'essere l\'ultimo. Giusto?', 56647),
(66267, 'itIT', 'Così imparano, quei bruti!', 56647),
(66266, 'itIT', 'Sì, fingetevi morti!', 56647),
(66265, 'itIT', 'Ah! Forse la prossima volta ci penseranno due volte prima di nominare un nuovo capo!', 56647),
(66264, 'itIT', 'Oh, quelle? Mettile pure dove vuoi. Di certo agli elementali non dispiacerà.', 56647),
(66263, 'itIT', 'Quanto saranno disperati!', 56647),
(66262, 'itIT', 'Sento già la differenza!', 56647),
(66261, 'itIT', 'Ora, al lavoro!', 56647),
(71009, 'itIT', 'Oh, cielo... a dirla tutta, $n, questo non è il mio momento più brillante.', 56647),
(71015, 'itIT', 'È un piacere conoscerti ma... Come vedi, ho un po\' da fare con questo enigma.', 56647),
(70550, 'itIT', 'Quando avremo più controllo sull\'Adunanza di Cobalto, potremo fornire maggiore supporto ai nostri alleati nella battaglia contro la Fiamma Frammentata.', 56647),
(72547, 'itIT', 'Niente male come inizio, $n.\n\nMa me ne serviranno molti di più se vogliamo sperare di tenere una conversazione!', 56647),
(77251, 'itIT', 'Grazie, $n. Questo ci aiuterà a capire a quali meraviglie stiamo assistendo.', 56647),
(79321, 'itIT', 'Ogni due settimane il catalizzatore ti fornirà abbastanza potere da infondere un pezzo di equipaggiamento.\n\nIl guardiano Tyr probabilmente ci sta guardando. Ovunque si trovi, questa non può essere una coincidenza.', 56647),
(76422, 'itIT', 'Oggi abbiamo imparato tutti qualcosa di nuovo.\n\nAnch\'io.\n\nIl tempo non smette mai di insegnare. Tutti noi dobbiamo continuare ad ascoltare e imparare sempre.', 56647),
(76421, 'itIT', 'Moraidormi. Il draghetto. Ora capisco.', 56647),
(76420, 'itIT', 'Non è andata meglio.\n\nAnzi, è andata perfino peggio.\n\nSto cercando di non perdere la concentrazione. Se ci attaccassero di nuovo, o...', 56647),
(76419, 'itIT', 'Non è andata... come avevo previsto.\n\nMa non mi arrenderò! Possiamo continuare a riavvolgere il tempo finché non funzionerà.', 56647),
(76407, 'itIT', 'È forse possibile aiutare Moraidormi? Apparentemente, sembra di sì.\n\nMa sento che c\'è qualcosa... di strano, qui. Perché Vexemia la stava inseguendo? Cosa succederà se Vexemia non deciderà di voltare pagina?\n\nMi sembra che ci stia sfuggendo qualcosa.', 56647),
(77417, 'itIT', 'Quindi la perdita di sua sorella, Moraidormi, è alla base di tutto...', 56647),
(76423, 'itIT', 'Sarà un... incontro delicato. Lascia parlare me.', 56647),
(76356, 'itIT', 'Grazie ai flussi temporali, hai recuperato Shalamarina prima che quei mostri ardenti potessero farle dei danni duraturi! La lama è un po\' bruciata, ma niente che non possa martellare via.\n\nSono felice che anche tu sia ancora $gtutt\'intero:tutt\'intera;. Qualche bruciatura, vedo, ma niente di grave.\n\nMostra quella fuliggine con orgoglio.', 56647),
(76258, 'itIT', '<Ferrus si stringe il petto, sollevato e con un sorriso raggiante.>\n\nC\'è mancato poco! Te lo immagini, il Confine degli Eoni che brucia poco dopo il mio arrivo? Che imbarazzo.\n\nGuarda, sembra che uno di quei piccoli elementali della mia forgia ti abbia preso in simpatia! Puoi tenerlo.\n\nAnzi, insisto. Tienilo. Non lo voglio.', 56647),
(76355, 'itIT', 'Be\', è andato tutto secondo i piani, non trovi? Spezzato senza una neanche un graffio o un\'oscillazione alla linea temporale! Non avevo dubbi.\n\nPurtroppo, sembra che quegli elementali fossero un tantino inquieti e se ne sono andati alla prima occasione!\n\nUn problema spento e una dozzina accesi!', 56647),
(76354, 'itIT', 'Oh, grazie ai flussi temporali. Hai trovato le mie cose!\n\n<Ferrus esamina rapidamente i propri averi.>\n\nA qualcuno queste reliquie potrebbero sembrare spazzatura, ma per me? Per me sono tutti dei tesori.\n\nOh, non preoccuparti per il resto delle casse. Una volta che ci saremo occupati delle Fenditure del Tempo, andrò da solo e le riporterò nella cripta.', 56647),
(76352, 'itIT', 'Cos\'è che hai visto uscire dalle Fenditure del Tempo? Non va bene!\n\nMi assicurerò di dirlo subito a Tempo. Tremo al solo pensiero di che cosa potrebbe succedere, se lasciassimo che quelle creature scorrazzino libere nella nostra linea temporale!\n\nPer fortuna c\'eri tu a occupartene! Riesco a sentire le energie temporali del martello già da qui!', 56647),
(76350, 'itIT', 'Come puoi vedere, sono in una situazione difficile. Non solo la mia forgia è sigillata con un blocco temporale, ma è piena fino all\'orlo di Elementali del Fuoco!\n\nPer peggiorare le cose, il giovane Pinnduin qui è in cerca di un talentuoso cronofabbro che ripari la sua lama, Shalamarina. E non posso fare molto se la mia forgia è...\n\n<Ferrus gesticola frustrato.>\n\nTi sarei molto grato se potessi aiutarmi.', 56647),
(75991, 'itIT', 'Oh, bene, ce l\'avete fatta. Sono felice di vedere che le vostre differenze sono state messe da parte.', 56647),
(75986, 'itIT', 'Ah, eccoti qui. Grazie per il tuo aiuto con le nostre fatiche temporali.\n\nOra, dovrò parlare con Pedgi in persona! Davvero, che onore. È stato difficile trattenermi, la prima volta che mi si è avvicinato. Ma ora ho molto tempo per parlare con lui.', 56647),
(76552, 'itIT', 'A quanto pare, il metronografo ha funzionato!\n\nÈ interessante che le energie temporali siano così simili alla musica. Mi chiedo se lo Stormo dei Draghi di Bronzo abbia mai condotto delle ricerche su questo aspetto...\n\nScusa, bando alle ciance. Torniamo ad aiutare Tempo. La mia prossima paga dipende da questo.', 56647),
(74942, 'itIT', 'Ottimo! Li consegnerò a Melly. Insieme al mio elenco di irresistibili rime sulla melma.', 56647),
(74476, 'itIT', 'Ho registrato i suoni di te che uccidevi le melme. Spero non sia un problema.', 56647),
(72189, 'itIT', 'Oh, lode ai Titani, finalmente dell\'aiuto!', 56647),
(70883, 'itIT', 'I Protettori del Giardino hanno bisogno delle loro armi. Lascia che ti equipaggi per scendere in battaglia.\n\nSe ne hai bisogno, ho anche altri attrezzi da guerra. Apprezzo il tuo aiuto nel domare questa natura selvaggia!', 56647),
(66299, 'itIT', 'Le cose non sono andate esattamente come previsto, ma d\'altra parte nessuno stratagemma dei Goblin va mai come ci si aspetta! Ottimo lavoro!\n\nLe Strillastormo non se ne andranno tanto presto, ma saranno più facili da abbattere senza la loro Matriarca a pianificarne le mosse. E i Piumablu avranno una possibilità di sopravvivere.\n\nLe Arpie e i draghi non sono poi così diversi. Tralasciando il loro tentativo di digerire in blocco tutta la fauna, sarebbero anche in grado di costituire una civiltà tutta loro. Forse là fuori c\'è una nidiata pacifica?\n\nOh, e tieni pure il travestimento. Ti dona.', 56647),
(65778, 'itIT', 'Sei $gstato grande:stata grande; e quel costume ti sta benissimo!\n\nSiamo finalmente pronti a spuntare le ali di questa terrificante minaccia.', 56647),
(65374, 'itIT', 'Queste piume sono più che sufficienti! E tutto quanto è stato raccolto senza che lo Spiumatore esplodesse... dico bene?', 56647),
(65371, 'itIT', 'Perfetto! E anche un po\' disgustoso. Proprio come avevo previsto.\n\nÈ ora di fabbricare un travestimento e spennare questa Matriarca!', 56647),
(65287, 'itIT', 'Questo è più di quanto immaginavo potessi recuperare!\n\nForse non sei poi così terribile, dopotutto. Non che lo pensassi, eh!', 56647),
(65373, 'itIT', 'Oh, sia lode agli stormi!\n\nOrmai mi sono affezionata alla professoressa e questo avrebbe potuto mettere la parola fine alla nostra nuova amicizia!', 56647),
(65490, 'itIT', 'Oh, sì! Roba di qualità!!\n\nHai mai pensato di farlo come professione, $n?', 56647),
(65475, 'itIT', 'Oh, ma dai! Non è certo il menu della cena quello che stai trasportando!\n\nO forse sì...', 56647),
(65313, 'itIT', 'I miei acuti sensi da volatile mi dicono che queste Strillastormo non sono qui solo per fare uno spuntino...\n\nMa hai fatto un ottimo lavoro, $n! Fammi decifrare questa pergamena e scopriremo cosa stanno cercando queste Arpie.', 56647),
(66071, 'itIT', 'Un lavoro ben fatto, $n!\n\nTi avrei dato una mano a curare e uccidere, ma di questi tempi mi piace definirmi una Goblin pensatrice.', 56647),
(65267, 'itIT', 'Grazie, $n!\n\nHo aiutato la cara professoressa mentre eri via. Temo di aver solo peggiorato le cose...', 56647),
(71239, 'itIT', 'La vecchia Levafrizza è preoccupata, eh? Dovrò pagarle da bere una volta finito qui.', 56647),
(66472, 'itIT', '<Thadezus si ferma per un periodo di tempo assurdamente lungo.>\n\nIo e Allis avevamo scommesso su di te, $C,\n\nsono felice che tu abbia avuto successo!', 56647),
(66473, 'itIT', 'Grazie per tutto ciò che hai fatto per noi, $C.', 56647),
(66471, 'itIT', 'Proprio ciò di cui avevamo bisogno.', 56647),
(66470, 'itIT', 'Vedo che sei $gtornato sano e salvo:tornata sana e salva;.', 56647),
(66468, 'itIT', '<Sharnax inizia a squadrarti.>\n\nMmm... sembra che tu sia più in gamba di quanto pensasse il comandante.\n\nC\'è ancora molto da fare prima che il giorno giunga al termine.', 56647),
(66467, 'itIT', 'Grazie, $n. Ora che i Dentebrace sono stati privati della loro fonte primaria di approvvigionamento, potranno scordarsi di raccogliere altro veleno.\n\nOra capisco che non devo essere per forza un Vigilante per fare la differenza nel mondo. Darò le dimissioni dal mio incarico per dedicarmi alla mia arte. Spero che un giorno avrò l\'occasione di rappresentare i panorami più belli delle Isole dei Draghi, così che tutto il mondo possa ammirarli.\n\nSpero solo che mia sorella capisca.', 56647),
(66465, 'itIT', 'Il Passaggio sarà un luogo molto più sicuro senza quelle lance avvelenate di cui preoccuparsi.\n\nOggi hai contribuito alla salvaguardia di molte persone con le tue azioni, $n. I Vigilanti e io siamo in debito con te.', 56647),
(66457, 'itIT', 'Ora che Scagliablu è sistemato, dubito che a breve ci ritroveremo ad affrontare un attacco organizzato da parte dei Tarasek.\n\nOra non resta che occuparci del veleno.', 56647),
(66456, 'itIT', '<Alvi prende le lance che le hai procurato. Sfrega delicatamente il pugnale su una delle lame, rimuovendo uno strato di linfa appiccicosa.>\n\nProprio come pensavo. Grazie, $n. Dovrebbe bastare per un antidoto, inoltre credo di sapere da dove proviene il veleno.', 56647),
(66230, 'itIT', 'Ah... alla fine l\'hai trovato.\n\nA dire il vero è più una raccolta di disegni che un libro mastro. Da che ricordo, sono sempre stata più incline all\'arte piuttosto che all\'esplorazione.\n\n<Alvi fa un lungo e mesto sospiro.>\n\nSe avessi fatto bene il mio lavoro, forse Nori non si sarebbe fatta male.\n\nDevo sistemare le cose... ma non so se potrò farlo senza aiuto.', 56647),
(66100, 'itIT', 'Grazie, $n, ora abbiamo cose più importanti di cui preoccuparci.', 56647),
(66834, 'itIT', 'Rellen ha contribuito allo stabilirsi dei Centauri in queste pianure. Non saremmo mai sopravvissuti senza i suoi insegnamenti.', 56513),
(70374, 'itIT', 'Così hai visto Himia, la Benedetta.', 56513),
(66687, 'itIT', 'Hai fatto ritorno senza nemmeno un graffio. Bene. Non sottovalutare mai gli animali.', 56513),
(66688, 'itIT', '<Nel contenitore di ferro ci sono resti inceneriti di precedenti pegni del vento.>\n\n<Metti in cima ciò che hai raccolto.>', 56513),
(66658, 'itIT', 'Non avrei mai pensato di ricevere un tale aiuto da $guno straniero:una straniera;. Hai i miei più sentiti ringraziamenti.', 56513),
(72117, 'itIT', 'Ti stai dimostrando utile. Che questa consapevolezza possa scaldarti nelle notti più fredde. In quei momenti, ricordati che siamo amici.\n\n<Huseng sorride.>\n\nSento che farai grandi cose per il nostro popolo, $n.', 56513),
(70928, 'itIT', 'Il Clan Shikaar sa riconoscere uno straordinario trofeo di caccia quando ne vede uno. Questo ti farà guadagnare la nostra stima.', 56513),
(66676, 'itIT', 'Sei $gtornato:tornata;! Guarda. Lizi si rimetterà!', 56513),
(65711, 'itIT', '<Radiya è insolitamente silenziosa e trema leggermente mentre guarda la bestia torturata.>', 56513),
(65761, 'itIT', '$p!', 56513),
(65770, 'itIT', '<L\'ohuna di Togotseng ti fissa.>', 56513),
(65907, 'itIT', 'Sembra che tu gli piaccia! O gli piace la frutta. Va bene anche così.<Radiya fa l\'occhiolino.>', 56513),
(65901, 'itIT', 'Fiuuu, grazie! Libertà!', 56513),
(65906, 'itIT', 'Chi sei tu? Ti manda Ordven? Legge davvero le mie lettere?!?\n\n<Radiya ridacchia di sorpresa e piacere.> Grazie a Ohn\'ahra!', 56513),
(66657, 'itIT', 'A differenza di mia madre e dei nostri antenati, nessuno vorrà mai che Arban possa vivere di nuovo. Grazie per avermi aiutato a vendicarli.', 56513),
(66656, 'itIT', 'Sono felice che mia madre riposi di nuovo in pace. Grazie, $n!', 56513),
(69936, 'itIT', 'Un iniziato non deve trarre gioia dalla morte di un altro Maruuk. Ma Zambul rende questo principio arduo da applicare.', 56513),
(66655, 'itIT', 'Perfetto! Dovrei riuscire a usarli per liberare tutti dagli Ukhel. Così, potranno tornare al riposo che meritano.', 56513),
(66654, 'itIT', 'È un buon inizio. Ora potrò usare queste armi per liberare i loro proprietari... Spero.', 56513),
(66652, 'itIT', 'Questa lancia... apparteneva a mia madre, Cathan. Era una grande cacciatrice. Quando si è ammalata, io... non ho potuto salvarla.\n\nCome tutti i grandi Centauri Maruuk, è stata sepolta con la sua arma. Questo significa che gli Ukhel stanno usando queste armi per rianimare gli spiriti e vincolarli al loro volere, inclusa mia madre!', 56513),
(66651, 'itIT', 'Il Clan Ukhel si disonora, ricorrendo alla magia oscura. Ora si sono spostati nei kurgan con i loro alleati Nokhud. Nessun clan dovrebbe stare qui! Li ho osservati da qui, dove loro non possono vedermi.', 56513),
(66011, 'itIT', '<Theramus osserva in silenzio il santuario restaurato.>', 56513),
(65904, 'itIT', 'Credo abbia funzionato! Ha lasciato la grotta!', 56513),
(65905, 'itIT', 'Grazie, $R.', 56513),
(65937, 'itIT', 'Sei $gtornato:tornata;!', 56513),
(65902, 'itIT', 'Oh cielo. Abbiamo sentito la sua sfuriata. Tutto bene?', 56513),
(65903, 'itIT', 'Quanti salterini! Coccoliamoli tutti!', 56513),
(65900, 'itIT', 'L\'equilibrio tra la carne e le spezie è semplicemente perfetto.', 56513),
(70070, 'itIT', 'Era stato ingoiato da...!\n\nFuocotroccolo ha tanto da imparare.\n\nPilota si è affezionata a te. È la più intelligente della nidiata e sarà la prima a spiccare il volo.\n\nGrazie per tutto quello che hai fatto! Prenditi cura del mio dolce anatroccolo!', 56513),
(65899, 'itIT', 'L\'hai trovato! Sembra che sia davvero giù di morale, oggi.', 56513),
(70069, 'itIT', 'I miei bellissimi anatroccoli! Come siete diventati forti!\n\nPilota, vieni. Ora basta giocare.\n\n<Pilota si rifiuta di lasciarti e si nasconde dietro le tue gambe, fino a quando Gracus la solleva di peso.>\n\nSembra che tu le piaccia!', 56513),
(70062, 'itIT', 'Oh! Già di ritorno? Sembrano passati solo pochi istanti.\n\nHai preso le parti migliori!\n\nFuocotroccolo e Pilota ameranno la chitina.', 56513),
(66684, 'itIT', 'Sei $gtornato:tornata;! Ho sentito la distruzione della fonte fin da qui.', 56513),
(65836, 'itIT', 'No!', 56513),
(66683, 'itIT', '<Watu fissa sconvolto la sua gamba, perforata dalla scheggia, da cui comincia a sgorgare sangue.>', 56513),
(66689, 'itIT', '<Watu non reagisce alla tua presenza. Resta seduto per non affaticare la gamba ferita, con gli occhi chiusi.>', 56513),
(66681, 'itIT', 'Ora i pini dovrebbero essere un po\' più sicuri.', 56513),
(66680, 'itIT', 'Così le nostre argali sono salve. Dai a Desiderino una pacca extra da parte mia, va bene? Lo farei io stesso, ma non posso muovermi. <Watu sospira.>', 56513),
(65837, 'itIT', 'Tirren? Fa sempre il corno che vuole, eh?\n\nTi ringrazio di essere qui, avremo bisogno di tutto l\'aiuto possibile.', 56513),
(66464, 'itIT', 'Sei $gun:una; combattente impressionante e temibile. I Centauri ti guardano con ammirazione. Gurgthock è furioso di non aver scommesso la sua fattoria su di te invece che su Amaa. Hai vinto il premio finale.', 56513),
(66700, 'itIT', 'È stato trovato alle Rovine di Nelthazan? Affascinante. \n\nI segni che porta sono antichi, ma hanno una somiglianza con gli altri manufatti che abbiamo scoperto intorno alle antiche macchinazioni di Alamorte.\n\nSono necessari ulteriori studi.', 56513),
(65898, 'itIT', 'Grazie, $p.\n\nSei $gstato:stata; molto utile.', 56513),
(65895, 'itIT', 'Ho già visto una malattia come questa... Speravo di non vederla mai più.', 56513),
(65893, 'itIT', 'Stanno ancora cercando qualcosa? Allora perché mi hai portato questa spazzatura?\n\nDobbiamo batterli sul tempo!', 56513),
(65891, 'itIT', 'Raccoglieremo tutto a tempo debito.', 56513),
(65890, 'itIT', 'Ovvio che sto urlando! Questo libro non mi dà ascolto! Cos\'altro posso fare?', 56513),
(66025, 'itIT', 'La linfa vitale del Maruuk è in pericolo.', 56513),
(66024, 'itIT', 'Balakar era un bersaglio facile per l\'influenza corruttrice di Koroleth.\n\nLa tempesta è arrivata.', 56513),
(66023, 'itIT', 'La via che hanno scelto è macchiata dal sangue.\n\nL\'Esploratrice Tomul ha cercato di avvertirci... Potrebbe avere altri sospetti.', 56513),
(66022, 'itIT', 'Quello sciocco traditore.\n\n<Akato sputa a terra.>', 56513),
(70337, 'itIT', 'Cos\'è?\n\nAffascinante. Dev\'essere un antico manufatto di grande importanza.\n\nCi servirà del tempo per studiarlo.', 56513),
(70721, 'itIT', 'Grazie, $p.\n\nDawa ed io ricorderemo sempre ciò che hai fatto per noi.', 56513),
(70730, 'itIT', 'Corna di Arbhog? Andranno bene.\n\nArbhog, un tempo, era il più possente dei musken delle pianure. Queste sono un dono adatto al più forte dei cacciatori. Sono sicuro che Narman le apprezzerà molto.\n\nForse un giorno mi insegnerà a cacciare. Un cacciatore Ohn\'ir. Ah! Te lo immagini?', 56513),
(70739, 'itIT', 'Preferirei chiedere a tutte le stelle del cielo notturno di ricambiare la mia ammirazione, piuttosto che illudermi di essere degno dell\'amore di Dawa.\n\nNondimeno, troverò il coraggio di procedere. Quando verrà il momento, mi aiuterai con una proposta stupefacente?', 56513),
(66948, 'itIT', 'Altri volti amichevoli sono i benvenuti.', 56513),
(66969, 'itIT', '<Okir traduce i segni della Khan Sansok in voce.>\n\nAnche se ci sono molti clan di varie dimensioni nelle pianure, gli Shikaar, i Teerai, gli Ohn\'ir e i Nokhud sono i più potenti.', 56513),
(66463, 'itIT', 'Ora capisco le voci che avevo sentito su di te e i tuoi amici. Sei $garrivato:arrivata; più lontano di quanto avrei mai immaginato.', 56513),
(66462, 'itIT', '...Cosa? Il combattimento è finito? Suppongo che mi si siano chiusi gli occhi a un certo punto.\n\nImmagino che tu abbia vinto, dato sei in piedi di fronte a me!', 56513),
(66461, 'itIT', 'Che spettacolo! Riuscivo a vedere le scintille fino a qui!', 56513),
(66460, 'itIT', 'Mi fa piacere che tu l\'abbia affrontato così velocemente. La puzza cominciava a salire fino al podio.', 56513),
(66459, 'itIT', 'Te la sei cavata bene! Ma ci stiamo solo riscaldando. Parla di nuovo con Gurgthock quando sarai $gpronto:pronta; a passare al secondo round.', 56513),
(70444, 'itIT', 'Ehi, tu non sei un centauro.\n\nVa be\'. Pazienza.', 56513),
(66019, 'itIT', 'I nostri antenati hanno rischiato molto per il nostro futuro. È giusto invitarli a unirsi a noi.', 56513),
(66016, 'itIT', 'Ti do il benvenuto, $gstraniero:straniera;.', 56513),
(72429, 'itIT', 'Non vedo l\'ora di vedere il tuo contributo verso i Maruuk.', 56513),
(66020, 'itIT', 'Un tradimento minaccia Ohn\'ahra stessa. Dobbiamo difenderla, $n. È arrivato il momento di cercare degli alleati.', 56513),
(66017, 'itIT', 'È bello stare di nuovo insieme al mio clan.', 56513),
(66021, 'itIT', 'I Nokhud prediligono la forza bruta e il potere sopra ogni cosa.\n\nSu parecchi argomenti non la vediamo allo stesso modo.', 56513),
(66018, 'itIT', 'Ho il dispiacere di presentarti a Bahir, uno dei tirapiedi del Khan Balakar.', 56513),
(76398, 'itIT', 'Eccellente. Le forze di Fyrakk stanno soffrendo il nostro assalto.\n\nI Draghi penseranno al resto, $n. Questo è il nostro Sogno e non tollererò più questi invasori.', 56819),
(76389, 'itIT', 'I nostri alleati combattono con la benedizione di Cenarius! È solo questione di tempo prima che le forze di Fyrakk sciolgano i ranghi e fuggano davanti a noi.', 56819),
(76388, 'itIT', 'Fyrakk si sarà anche ritirato, ma mira ancora a distruggere la barriera che protegge il Tempio della Sorgente. Dobbiamo spezzare i ranghi nemici e fermarlo.\n\nÈ allora che metteremo fine alle sue macchinazioni una volta per tutte.', 56819),
(76387, 'itIT', 'Hai aiutato gli Antichi ad affrontare i Djaradin, ma per quanto tempo? Quanti altri andranno persi prima che la battaglia finisca?\n\nQuanto sacrificio per questa guerra. Quanti caduti. Troppi.', 56819),
(76436, 'itIT', 'Speriamo di riuscire a scoprire qualcosa dalle informazioni che hai raccolto.\n\n<Alexstrasza scorre tra gli appunti che le hai portato. La sua espressione cambia lentamente da accigliata a speranzosa.>\n\nPotresti appena averci salvati tutti, $n.', 56819),
(76385, 'itIT', 'Non mi aspettavo che lo stesso Profeta delle Fiamme si unisse alla battaglia. Forse abbiamo meno tempo di quanto pensassi.', 56819),
(76386, 'itIT', 'Sono felice che la mia scaglia ti sia stata utile. Anche se non posso scendere in battaglia, posso almeno potenziarti per combattere al mio posto.\n\nDirò alle nostre truppe di terra di iniziare le indagini. Dobbiamo scoprire perché quelle protezioni delle fiamme stanno venendo potenziate.', 56819),
(76416, 'itIT', 'Grazie per essere qui, $n.\n\nLe nostre forze si sono radunate, ma le circostanze sono contro di noi. Non riusciremo a resistere a lungo senza rinforzi. Speriamo di riuscire ad attirare l\'attenzione di Fyrakk finché la Fioritura non sarà completata.', 56819),
(76384, 'itIT', 'Amirdrassil ora è più vulnerabile che mai. Che fiorisca ad Azeroth come un faro di speranza... o che diventi un araldo della rovina.\n\nDobbiamo proteggere il suo destino. E lo faremo.', 56819),
(76337, 'itIT', 'Grazie per essere qui, $p.', 56819),
(76336, 'itIT', 'È fatta.', 56819),
(76333, 'itIT', 'Galok è quasi in rotta. Non molliamo ora!', 56819),
(76335, 'itIT', 'Le sorti volgono a nostro favore! Sfruttiamo il vantaggio.', 56819),
(69902, 'itIT', 'Ottimo lavoro, $p! Spero che i piccoli abbiano imparato un\'importante lezione... o una memorabile, almeno.\n\nTerremo qui il draghetto per un po\', devo stabilire l\'occasione migliore per riportarlo alla riserva.\n\nTi nominerò anche membro onorario dei Ricercatori Coraggiosi. Il tuo impegno è stato fondamentale per la sopravvivenza di questa creatura. Ti consiglio solo di informarmi prima, se i piccoli dovessero tramare qualcosa in futuro.\n\nOra, ti prego di scusarmi, ma devo rivalutare i miei metodi di insegnamento.', 56513),
(69901, 'itIT', 'Fantastico, $p.\n\nSpero che questi mocciosi abbiano appreso qualcosa da te.\n\nCosa gli ha fatto pensare che non li avremmo aiutati? Aiutare la fauna è parte del nostro compito! Forse dobbiamo rivedere i nostri metodi di insegnamento...', 56513),
(69900, 'itIT', 'Eccellente, $p! Di sicuro non è stato... piacevole.\n\nScommetto che preferiresti limitare i tuoi compiti all\'esplorazione e alla ricerca ma, sfortunatamente, capita di doversi sporcare le mani per difendere la natura da chi la minaccia.', 56513),
(69899, 'itIT', 'Cos\'hanno fatto? Oh, questi giovani... Quando impareranno? Avrebbero potuto rimanere feriti, o essere catturati!\n\nÈ una questione molto seria.', 56513),
(69898, 'itIT', 'Oooh! Questa dev\'essere la carne più deliziosa che abbia MAI visto! Il mio progetto prenderà il voto MIGLIORE. Il proto-draghetto la vorrà sicuramente!\n\n<L\'espressione di Iyali si fa improvvisamente preoccupata.>\n\nOh, no!\n\nIntendo che, uhm, tutti vorranno copiare da me... per il progetto!\n\n<Iyali sorride in modo poco convincente.>', 56513),
(69897, 'itIT', 'Quindi, alcun proto-draghetti amano essere accarezzati e altri no?\n\nNon va bene. E se questo qui chiamasse i suoi amici? E se fosse cattivo?\n\nVoglio dire... Questa lezione, ehm, non ha senso. Questi compiti sono molto difficili.\n\nGrazie per il tuo aiuto. E comunque, mi dispiace che ti abbiano $gferito:ferita;!', 56513),
(66529, 'itIT', 'Un giorno spero di combattere per il mio popolo con lo stesso coraggio che questo proto-drago ha mostrato nei suoi ultimi momenti prima di morire.\n\nGrazie ancora, $n.', 56513),
(66528, 'itIT', 'Una lotta all\'ultimo sangue con qualcosa di altrettanto forte. Chissà se stava proteggendo la riserva dagli invasori?\n\nGrazie, $n. È bello ricordare i sacrifici di chi ci ha preceduto.', 56513),
(66527, 'itIT', 'Comunque... Non è che hai visto un\'altra fotocamera lassù, per caso?\n\nAnzi, dimentica ciò che ho detto.', 56513),
(66526, 'itIT', 'Bene. I Primalisti costituiscono ancora una minaccia, ma finalmente questi draghi possono riassaporare la loro libertà.', 56513),
(66525, 'itIT', 'Oh, guarda che roba! I colori sono perfetti. Sembra che tu sia già $gun bravo catalogatore:una brava catalogatrice;!', 56513),
(66524, 'itIT', 'Sono bellissime! Davvero bellissime! Era davvero la tua prima volta dietro l\'obiettivo?', 56513),
(72397, 'itIT', 'Hai incontrato mio nonno, vero?\n\nNon credere a tutte le sue storie, gli piace vantarsi della sua famiglia!', 56513),
(71034, 'itIT', 'Oh, un nuovo manufatto. Lascia che lo inserisca nel registro e annoti che lo hai riportato tu.\n\n<La Catalogatrice Jakes annota qualcosa nel suo registro.>\n\nFatto! Continua a portarceli!', 56513),
(70822, 'itIT', 'Abbiamo inviato centinaia di esploratori da quando siamo atterrati, ma purtroppo molti di loro non sono tornati. Potresti tenere gli occhi aperti per un qualsiasi segno durante i tuoi viaggi? Indossano spesso uno Zaino da Esploratore della Spedizione in dotazione standard. Ah, se dovessi trovare dei manufatti, ti pregherei di portarli alla Catalogatrice Jakes. Ti sarà grata.', 56513),
(66963, 'itIT', '<Il Catalogatore Wulferd ride.>\n\nNessun problema. Ho un sacco di pellicola di ricambio nel mio bagaglio a mano.', 56513),
(66123, 'itIT', 'La nostra regina!', 56513),
(66122, 'itIT', 'Saranno anche stati nostri simili, e avremmo potuto parlarci da fratelli... ma nel mio cuore non trovo pietà per la loro crudeltà.', 56513),
(66121, 'itIT', 'Quasi fatto.', 56513),
(66119, 'itIT', 'La nostra dimora recherà le ferite di questo assalto per anni, ma siamo forti. Resisteremo... e le uova portate in salvo realizzeranno un futuro radioso per tutti noi.\n\nGrazie.', 56513),
(66118, 'itIT', 'Il Tempo della Vita è forte e resterà tale.', 56513),
(66116, 'itIT', 'Userò ogni arma nel mio arsenale per fermare questi nemici.', 56513),
(66931, 'itIT', 'Io...\n\nPer quanto desideri seguire la mia regina in battaglia, devo dimostrarmi all\'altezza della sua fiducia e proteggere il Tempio della Vita.', 56513),
(65444, 'itIT', 'Ti do il benvenuto sulle Isole dei Draghi!', 56647),
(65439, 'itIT', 'Sono notizie davvero inquietanti, ma è necessario che tu sappia del pericolo che dobbiamo affrontare.', 56647),
(72256, 'itIT', 'Sono felice che un Dracthyr ci accompagni durante la spedizione.\n\nIl loro peculiare punto di vista sarà di grande valore, e imparare di più sulla loro storia li aiuterà ad accettare con più facilità le loro attuali circostanze.\n\nCome ho detto prima, la storia cura ogni ferita.', 56647),
(65443, 'itIT', 'Ho la sensazione che questa spedizione sarà un gran successo.', 56647),
(65437, 'itIT', 'È un onore che tu voglia viaggiare verso la patria dei draghi.\n\nQualcuno è ansioso di aiutarti a prepararti per ciò che ti attende.', 56647),
(65435, 'itIT', 'Grazie per aver risposto alla chiamata. Il tuo coraggio sarà apprezzato durante il viaggio che ci aspetta.', 56647),
(72589, 'itIT', 'Non è molto, ma almeno è qualcosa. Ed è questo che conta.', 56647),
(72588, 'itIT', 'Forse la prossima volta quei ladri Primalisti impareranno a tenere giù le zampe.', 56647),
(66556, 'itIT', 'Te l\'avevo detto di averci preso con la caverna. Ora possiamo pensare a stabilire delle relazioni diplomatiche come si deve.', 56647),
(66622, 'itIT', 'Grazie, $n! Ricorderò sempre, hic, il tuo eroismo!', 56647),
(66555, 'itIT', 'Ora pensiamo a tradurre questo messaggio...', 56647),
(66554, 'itIT', 'Spero tu non abbia esagerato.', 56647),
(66553, 'itIT', 'Allora, cos\'hai trovato?', 56647),
(70627, 'itIT', 'Purtroppo, $gamico mio:amica mia;... Ho delle brutte notizie per te sui Mezzorsi Mantogelido.', 56647),
(71013, 'itIT', 'Ora sai cosa c\'è in gioco.\n\nÈ ora di muoversi.', 56647),
(66730, 'itIT', 'Non è stato poi così difficile, vero?', 56647),
(67050, 'itIT', 'Hai fatto COSA?!? Bah... non importa, per ora. Non è ancora finita.', 56647),
(66703, 'itIT', 'Quindi quei maledetti sciamani sono morti?', 56647),
(66715, 'itIT', 'Puzzi come la morte... A Gelomorso piace.', 56647),
(66709, 'itIT', 'Onestamente? Pensavo che il tuo \"aiuto\" sarebbe stato la mia fine.', 56647),
(66708, 'itIT', '<Questo Tuskarr giace privo di sensi sulla neve, con una lancia di legno che gli fuoriesce dal fianco.>', 56647),
(70338, 'itIT', 'Ora che Sylvie sta guarendo, questi cuccioli saranno in buone...\n\nEhm, mani?\n\nZampe?', 56647),
(69862, 'itIT', 'È un suono debole, ma penso di sentire i versi dei cuccioli provenire dalla grotta!\n\nSi mette male...', 56647),
(68644, 'itIT', 'L\'ho curata, ma sta ancora soffrendo, si vede.\n\nMmm, mi chiedo se...', 56647),
(68642, 'itIT', 'Grazie, $n. Non ti sei $gfatto:fatta; male sui vetraculeo, vero?', 56647),
(68643, 'itIT', 'Eccellente, $n. \n\nQuesti campioni dovrebbero darci un quadro più completo di come si sta diffondendo l\'epidemia.', 56647);
INSERT INTO `quest_offer_reward_locale` (`ID`, `locale`, `RewardText`, `VerifiedBuild`) VALUES
(68641, 'itIT', 'Oh! Grazie mille, $n!\n\nSarò anche una maga, ma a volte le soluzioni naturali sono le più efficaci.', 56647),
(68639, 'itIT', '<Scarabocchia degli appunti sul suo diario.>\n\nSì, è tutto molto utile. Speriamo che il Kirin Tor possa usare queste informazioni per aiutare gli altri che sono stati contagiati dalla malattia arcana.', 56647),
(70970, 'itIT', 'To\'tik aveva ragione. Questo posto è maledetto.\n\nFaremo sapere al Kirin Tor cos\'è successo, $n. Grazie per l\'aiuto.\n\nQuesta è una lezione che non dimenticherò presto...', 56647),
(70946, 'itIT', 'È peggio di quanto pensassi. Molto peggio.', 56647),
(70931, 'itIT', 'Eccellente. Con queste schegge, potrò trovare facilmente il manufatto.', 56647),
(70937, 'itIT', 'Vediamo cos\'hai trovato...', 56647),
(70859, 'itIT', 'Dammela! Presto, ora!\n\nHai sentito anche tu i sussurri?', 56647),
(70858, 'itIT', 'Ti ringrazio sinceramente. Pensavo di morire prima di ottenere questo manufatto.', 56647),
(67111, 'itIT', 'Ah, meraviglioso! Con queste ghiandole velenifere, posso preparare un antidoto per Alia. Si sentirà meglio in men che non si dica.', 56647),
(70856, 'itIT', 'Ottimo lavoro. Questo dovrebbe darci un po\' di respiro.', 56647),
(67724, 'itIT', 'Grande! Questa seta di ragno brucerà a lungo.', 56647),
(75966, 'itIT', 'Ho trovato dei guai!', 56647),
(75949, 'itIT', 'Sembra che gli oggetti sfasati nel tempo siano tornati al loro posto. Una cosa in meno di cui Tempo dovrà preoccuparsi.\n\nMmm...Che dati interessanti. Forse ci torneranno utili più tardi.\n\nLe mie scuse se Pedgi non è stato molto d\'aiuto. Forse è meglio fargli tirare fuori la sua determinazione. È la sua canzone, dopotutto.', 56647),
(77432, 'itIT', 'Sapevo che i musicisti avevano un carattere difficile, ma tutto questo è ridicolo. Almeno è sveglio.', 56647),
(75935, 'itIT', 'Grazie per aver parlato con Tempo.\n\nPedgi può sembrare scontroso, ma nell\'animo è buono. Quasi sempre.', 56647),
(77155, 'itIT', 'Una donazione alle taverne sulle Isole dei Draghi per coprire il conto!', 56647),
(76145, 'itIT', 'Non possiamo arrenderci ora! Siamo ancora in tempo per salvare il tempio e sconfiggere quegli Infiniti una volta per tutte. Non possiamo permettere loro di controllare la vera linea temporale.\n\nE di certo non permetterò loro di trasformare Nozdormu in quel perfido Murozond.', 56647),
(76144, 'itIT', 'Be\', almeno abbiamo fermato i complici di Morcie. Quei Draghi dell\'Infinito causano sempre problemi.\n\nMa non possiamo fermarci finché Morcie non sarà stata catturata e rimandata a casa sua!', 56647),
(76143, 'itIT', '<Cromie con gli occhi ancora più spalancati ascolta il tuo rapporto su quello che le Cromie alternative ti hanno detto.>\n\nOh, no. Siamo stati ingannati! Quella Cromie del futuro non è affatto una Cromie del futuro. È la Cromie di una linea temporale alternativa, come tutte le altre Cromie qua intorno!\n\nPerché mentirti?', 56647),
(76142, 'itIT', 'Non so esattamente di cosa si tratti, ma immagino che troverò un modo per usarlo. Meglio non lasciare che niente vada sprecato.', 56647),
(76141, 'itIT', '<Cromie ascolta a occhi spalancati la tua spiegazione di come sono andate le cose.>\n\nIo? Dal futuro? Nella mia lista, è una delle tre migliori persone di cui fidarsi! \n\nMa non ha senso. Perché avrebbe voluto che tu distorcessi i flussi temporali per aiutare Nozdormu? Mi sta venendo un gran mal di testa.', 56647),
(76140, 'itIT', 'Sì, sono io! Cromie dal futuro! Piacere di conoscerti. Di nuovo.\n\nOra, non posso spiegarti bene da dove vengo o perché sono qui. Sai, quelle questioni riguardanti i flussi temporali eccetera, insomma, hai capito. Ma so esattamente cosa succederà e so esattamente come impedirlo!', 56647),
(69934, 'itIT', 'Szareth vuole guarire tutti, a prescindere dalle conseguenze. Ribelli, Giurascaglia, animali selvatici: ognuno merita la stessa cura.\n\nE anche se trovo irritante l\'idealismo di Szareth, Gelikyr dipende dalla sua esperienza.\n\nQuindi i miei ringraziamenti a Szareth, e anche a te. Queste pozioni saranno preziose.', 56647),
(69933, 'itIT', 'La Pianta Sferzante ti ha $gattaccato:attaccata;?\n\n<Szareth si acciglia, annusando i tuoi vestiti. Fa una smorfia di disgusto.>\n\nNon mi stupisce, puzzi di sangue. E non tuo, suppongo.\n\nLa guerra si è davvero abbattuta su tutte le isole.', 56647),
(69932, 'itIT', '<Szareth prende il polline e la stoffa avanzati, poi alza lo sguardo verso la sua capanna.>\n\nLe anatre devono vedersela con le arpie della scogliera. Quelle ferite atterrano qui e io le aiuto come posso.\n\nSpero che questa si riprenda.', 56647),
(66412, 'itIT', 'A esser sincero, lo invidio. Poter essere di nuovo giovane ed esplorare il mondo. Prima o poi dovrai farmi visita, così potrai raccontarmi come se la passa.', 56647),
(66139, 'itIT', 'Incredibile! Non ero sicuro che avrebbe funzionato, ma ne sono felice.', 56647),
(66137, 'itIT', 'Il problema con gli Elementali è anche più grave di quanto pensassi, se ne hai dovuti eliminare così tanti. Se non altro Alexstrasza sarà felice.', 56647),
(66136, 'itIT', 'Eccellente! Questo è proprio ciò che ci serve per spegnere quegli Elementali del Fuoco una volta per tutte.', 56647),
(66138, 'itIT', 'Ottimo lavoro. Ieri Nozdormu mi ha informato che intende esprimere la sua gratitudine.', 56647),
(66279, 'itIT', 'Grazie, $p. Nozdormu sarà felice di riaverlo indietro.', 56647),
(66278, 'itIT', 'L\'hai trovato nel capanno? Non è mio, ma credo di ricordare a chi appartiene.', 56647),
(66135, 'itIT', 'Ah, ma guardalo! Il mio adorabile assistente. Chi è il cucciolone più bravo di tutti? E con tante spine? Basilton, e chi se no! Chi è il più spinoso? Esatto! Sei tu!\n\nOh, ehm. Grazie, $p.', 56647),
(66134, 'itIT', 'Sia lode ai Titani, eccoti qua! Senza di te non credo di avere speranze contro questi parassiti.\n\nAllora, che ne dici di aiutare un vecchio dragoide con il resto dei giardini?', 56647),
(71219, 'itIT', 'Oh, cielo, $gun:una; viandante. Ti prego, perdonami, sono in uno stato pietoso al momento.', 56647),
(65920, 'itIT', 'Ottimo lavoro, $p. Le protezioni sono state ripristinate e la Bacino del Forte di Tyr è di nuovo al sicuro. Grazie per tutto ciò che hai fatto. Thaldraszus è in debito con te.', 56647),
(65916, 'itIT', 'Grazie, $p. Ora passiamo alla fase successiva: ripristinare le protezioni.', 56647),
(65921, 'itIT', 'Soffrirò sempre per coloro che abbiamo perso, ma sono grata per tutti quelli che abbiamo salvato.', 56647),
(70139, 'itIT', 'Come sospettavo. È fondamentale trovare le Pietre di Volta mancanti.\n\nAltrimenti le nostre perdite saranno state inutili.', 56647),
(65918, 'itIT', 'Grazie, $p. Questo dovrebbe tenerli a bada, per ora.', 56647),
(65913, 'itIT', 'Grazie, $R... Se non fosse stato per te, avrei perso la vita.', 56647),
(72190, 'itIT', 'Talikka ne è uscita viva?', 56647),
(79514, 'itIT', 'Adesso sì che ci siamo!', 56647),
(11441, 'itIT', 'Oh! Oh! Oh! Sei qui per la birra gratis?', 56647),
(79515, 'itIT', 'Grazie, $p. Dovrebbe bastare.', 56647),
(79512, 'itIT', 'Interessante... Che varietà di risposte.', 56647),
(70221, 'itIT', 'Ehilà, $p! Il Consorzio degli Artigiani vuole ringraziarti per tutto ciò che hai fatto. Vorremmo darti della Prova dell\'Artigiano, gratuitamente.\n\nPotresti usarla per completare alcuni Ordini di Nuova Creazione per noi!', 56647),
(70126, 'itIT', 'Prendi questi Reagenti di Finitura, usali per aumentare la tua abilità nell\'artigianato quando ti serve qualcosa di alta qualità.\n\nSii gentile con i tuoi clienti, rispettali e loro ti onoreranno negli affari, $p.', 56647),
(79511, 'itIT', 'Immagino che ti mandi Cromie?', 56647),
(76545, 'itIT', 'Sei qui per una birra? Ah! Ne abbiamo quanta ne vuoi.', 56647),
(72809, 'itIT', 'Te la sei cavata alla grande!', 56647),
(73393, 'itIT', 'Congratulazioni! La tua miniatura dell\'Uovo di Draghetto ora ha un aspetto aggiuntivo! Fantastico!', 56647),
(70839, 'itIT', 'Dal mio risveglio, ho trascorso ogni minuto a studiare i Titani. La loro storia è affascinante. Pensa a quanto potere dovevano avere per riuscire a creare gli Stormi dei Draghi! C\'è ancora tanto altro da scoprire su di loro!\n\nSe mi porterai tutte le Reliquie dei Titani che riesci a trovare nelle Isole dei Draghi, metterò una buona parola per te con l\'Accordo di Valdrakken.', 56647),
(70840, 'itIT', 'Fantastico! Questa reliquia è conservata perfettamente. Inizierò subito a studiarla.\n\nApprezzo molto il tuo impegno! Mi ricorderò della promessa di parlare bene di te all\'Accordo di Valdrakken.\n\nOra, dov\'ero? Sì, questa va messa proprio lì...', 56647),
(67007, 'itIT', '<Kemora si volta con grazia per rivolgersi a te. Prima di proferire parola, con il sorriso sulle labbra, i suoi occhi passano in rassegna la tua sagoma, partendo lentamente dai piedi fino a incrociare i tuoi occhi con un placido sguardo.>\n\nAnche tu sei in cerca di risposte, $R?\n\nSono pronta a spiegarti tutto, se intendi accettare la sfida.', 56647),
(70880, 'itIT', 'Salve, posso offrirti una forchetta? O magari un tè?\n\nÈ un piacere vedere così tante creature a Valdrakken. Certamente ci aiuterai in modo ammirevole. Se dovessi aver bisogno del coltello da abbinare alla tua forchetta, fammelo sapere e faremo uno scambio!', 56647),
(77303, 'itIT', 'Un altro messaggio dall\'ordine di Kathos appena arrivato.\n\nDice che un manufatto dei Maruuk nascosto dentro uno dei tumuli sepolcrali dei Kurgan Eterni è a rischio. La nota parla di un antico incenso che nasconde il manufatto agli occhi degli intrusi.\n\nIl resto delle informazioni è in questa nota. Buona fortuna!', 56647),
(77165, 'itIT', 'Salve, io lavoro per l\'Occhio di Azeroth.\n\nSto indagando su una strana attività a Valdrakken. Ti va di aiutarmi?\n\nHo una fonte, ma dice che parlerà solo con qualcuno che indosserà un \"Cappello Pensante\". Dovrebbe servire a concentrarsi sui pensieri o qualcosa del genere. Comunque, ho fatto un elenco dei componenti necessari e da chi si possono ottenere.\n\nTrovali, poi parleremo di nuovo.', 56647),
(77153, 'itIT', 'Una donazione alle taverne sulle Isole dei Draghi per coprire il conto!', 56647),
(70882, 'itIT', 'Saluti, $C. Hai dimostrato il tuo valore all\'Accordo di Valdrakken. Eccoti alcuni rifornimenti per aiutarti nel supportare la nostra causa. Non deluderci!', 56647),
(74381, 'itIT', 'Per fortuna, sembra che i nostri nemici non abbiano scoperto i nostri esploratori. Le Incarnazioni e la Fiamma Frammentata sono nemici formidabili. Non sono sicura che saremmo in grado di controllarli di nuovo senza subirne delle conseguenze.\n\nLa situazione si sta infiammando. Alcuni Dracthyr sono già tornati sull\'isola, ma avranno bisogno di aiuto per costruire una base delle operazioni.\n\nTemo che avrai un bel po\' da fare.', 56647),
(66244, 'itIT', 'Ti do il benvenuto a Valdrakken, $n. Kalecgos dice che avete notizie riguardanti la Vastità Azzurra.', 56647),
(66212, 'itIT', 'Mmmh.\n\nMmmmmmh.\n\n... Ben fatto!', 56647),
(79989, 'itIT', 'Ora che noi, e per noi intendo te, abbiamo capito a cosa servono questi aggeggi, non c\'è modo di sapere quanti altri ce ne siano là fuori!\n\nTieni gli occhi aperti, $n. Non si può sapere cosa troveremo in queste isole.', 56647),
(70156, 'itIT', 'Ora che noi, e per noi intendo te, abbiamo capito a cosa servono questi aggeggi, non c\'è modo di sapere quanti altri ce ne siano là fuori!\n\nTieni gli occhi aperti, $n. Non si può sapere cosa troveremo in queste isole.', 56647),
(70154, 'itIT', 'Non esattamente ciò che mi aspettavo, ma siamo $garrivati sani e salvi:arrivate sane e salve;.\n\nDevo ammettere che, considerato tutto ciò che è successo, ora sono più curiosa che mai riguardo alla potenza contenuta nel ricettacolo.', 56647),
(66582, 'itIT', 'Santo cielo, il calore all\'interno del ricettacolo è affascinante.', 56647),
(70215, 'itIT', 'Ho preparato un ricettacolo che permette di catturare e immagazzinare energia.\n\nQuesta conoscenza non è conosciuta a molti. Sarebbe saggio procedere con cautela.', 56647),
(66598, 'itIT', 'Viaggio piacevole, direi. Questi simboli di cui parli sono tanto misteriosi, quanto antichi.\n\nDato che sembri avere un interesse tale da viaggiare fino qui per trovarmi, il minimo che posso fare è offrirti qualche indicazione.', 56647),
(66447, 'itIT', 'Credo che ce la caveremo, adesso, $n. Grazie. È tempo che la spedizione scavi più a fondo!\n\n<Taiyang ride felice.>\n\nÈ solo un po\' di umorismo da Sciamani, troppo presto?', 56647),
(66442, 'itIT', 'La mia ipotesi originale è confermata. Gli elementi sono più efficaci insieme.', 56647),
(66439, 'itIT', 'Ah, il Globo delle Fiamme Primordiali. È vitale e focoso quanto Acadia. Lo terrò io, per ora.', 56647),
(70438, 'itIT', 'Ah! Le leggende erano vere, fantastico!', 56647),
(66597, 'itIT', 'Un simbolo di che?!? Non può essere...\n\n<Thaelin si gratta la barba.>\n\nC\'è solo un modo per scoprirlo.', 56647),
(66595, 'itIT', 'Messaggio? Quale messaggio?\n\nCosa significa che è sparito misteriosamente?\n\nBe\', non importa, abbiamo molto di cui parlare.', 56647),
(71035, 'itIT', 'Così tanti manufatti! Potrebbe volerci un po\'.\n\n<La Catalogatrice Jakes annota qualcosa di fretta sul suo registro.>\n\nFatto! Puoi andare! Torna, se ne trovi altri!', 56647),
(70813, 'itIT', 'La maggior parte dei tesori in queste zone si trova nel terreno: antichi manufatti, persino oggetti di valore. Ti servirà un buon badile per raggiungerli; fortunatamente per te, ho un badile ufficiale della spedizione con il tuo nome sopra. Vai in cerca di terra smossa, vedi cosa riesci a trovare.', 56647),
(70812, 'itIT', 'Un buon mantello può essere il più importante pezzo di equipaggiamento durante una spedizione. Con il tuo impegno, hai meritato di scegliere un mantello. Torna da me, se volessi ottenerne uno diverso.', 56647),
(77744, 'itIT', 'Una donazione alle taverne sulle Isole dei Draghi per coprire il conto!', 56647),
(76283, 'itIT', 'Mentre Amirdrassil sboccia su Azeroth oltre il Sogno, mia sorella indossa la carica di un nuovo Aspetto.\n\n<Alexstrasza guarda dove si trovava il portale e sorride.>\n\nE tu, $p, hai donato un bel finale a tutti questi eventi.', 56819),
(77781, 'itIT', 'Grazie, $p. Apprezzo la loro vivacità, ma non sono sulla lista degli invitati stasera.', 56819),
(76281, 'itIT', 'C\'è così tanta vita e gioia qui sotto questi rami. Che possa essere sempre così.', 56819),
(76282, 'itIT', 'Grazie. Sapevo che avrebbe parlato con te.\n\nForse ora possiamo rilassarci entrambi.', 56819),
(76280, 'itIT', 'Amirdrassil... finalmente. Mi sento come se avessi lasciato andare un respiro che non mi ero resa conto di star trattenendo. $p, non potrò mai ringraziarti abbastanza per il tuo aiuto.', 56819),
(77200, 'itIT', 'Ogni Kaldorei conosce il dolore e la gioia di un momento come questo. La sofferenza che abbiamo patito e la speranza che abbiamo per il futuro.\n\nQueste offerte sono significative e molto apprezzate.', 56819),
(77329, 'itIT', 'Amirdrassil è tutto ciò che abbiamo sempre sperato. Onoriamo il suo arrivo come si deve.', 56819),
(76276, 'itIT', 'Mi fa piacere sapere che i nostri amici stiano bene. Grazie per la visita.', 56819),
(77780, 'itIT', '<Il volto di Merithra si illumina.>\n\nSiamo tra i primi a vedere Amirdrassil qui su Azeroth. È un momento davvero prezioso.', 56819),
(78363, 'itIT', 'Hai più che meritato quest\'insegna. È tutto quello che hai sognato, no?', 56819),
(76402, 'itIT', 'Amirdrassil è salvo e con esso tutta Azeroth. La sconfitta di Fyrakk lo ha assicurato.\n\nDa $gCampione:Campionessa; delle Isole dei Draghi a $gsalvatore:salvatrice; del Sogno di Smeraldo. Tutti gli Stormi dei Draghi sono profondamente in debito con te, $n. Non lo dimenticheremo presto.', 56819),
(76331, 'itIT', 'Devo fidarmi di lei... e di me. È ora di combattere.', 56819),
(76332, 'itIT', 'Ora... siamo pronti.', 56819),
(78444, 'itIT', '<Il Custode Amrymn fa un respiro profondo.>\n\nL\'aria si è placata. La pace sta tornando nel Sogno, anche se lentamente.\n\nTutti coloro che difendono e hanno a cuore questo posto ti ringraziano.', 56819),
(77315, 'itIT', 'Grazie, $n. Gracus ora è in pace.\n\nCome lo sono coloro che si sono occupati di lui, a quanto pare. Non capita spesso di avere una seconda occasione per poter dire addio.', 56819),
(77314, 'itIT', 'Quei ricordi... Gracus soffre. Dovremmo aiutarlo.', 56819),
(77313, 'itIT', 'C\'è un senso di pace in questo luogo.\n\nGracus mi aveva evocata qui per un motivo. Lo sapeva.', 56819),
(77312, 'itIT', 'Incoraggiare una nuova crescita in un\'occasione come questa fa stare bene.', 56819),
(77311, 'itIT', 'Ero così sicura che avremmo potuto aiutarlo.\n\nYsera sembra percepire qualcosa qui che io non percepisco. Dopo tutto ciò che le è capitato, sembra proprio che la sua magia sia cambiata oltre la mia comprensione.', 56819),
(77310, 'itIT', 'Per fortuna sei qui, $n. Forse puoi aiutarci?', 56819),
(76334, 'itIT', 'Merithra annuisce solennemente ai nostri alleati.>\n\nAllora è deciso. Iniziamo i preparativi.', 56819),
(76330, 'itIT', 'Così ostacoleremo significativamente le loro forze.', 56819),
(76329, 'itIT', '<Merithra resta immobile. Solo gli occhi tradiscono la sua rabbia indicibile.>\n\nVendicheremo la nostra gente.', 56819),
(78646, 'itIT', 'Non sarà facile...', 56819),
(76328, 'itIT', 'Mia madre è in difficoltà...', 56819),
(76327, 'itIT', 'È $gquesto il nuovo:questa la nuova; generale di Igira? Non sembra granché. Prevarremo su questo mostro.', 56819),
(78046, 'itIT', 'Il loro sovrintendente è morto, dunque?\n\n<Aviana ti porge un breve cenno di approvazione.>\n\nBene.\n\nOra che Chardryn è morto, i loro esperimenti distrutti e le loro ricerche arrestate, speriamo che questa sia la fine dei loro piani corrotti.', 56819),
(78044, 'itIT', 'Immagina quanto si sono impegnati questi agenti della monotonia per far sì che io, IL LOA DEL CAMBIAMENTO, interferissi con il loro piano di trasformazione del Sogno?\n\nChe sfacciataggine!', 56819),
(78045, 'itIT', 'Ben fatto, $n.\n\nMi assicurerò che Cenarius venga informato dei danni che queste erbacce hanno inflitto. Alcune Driadi dovrebbero riuscire a ripulire l\'eventuale polline restante o i fiori che ti sono sfuggiti.\n\n<Lo sguardo di Aviana cade sul punto d\'incursione dei Druidi delle Fiamme più in basso.>\n\nOra non resta che un compito, $gcampione:campionessa;.', 56819),
(77788, 'itIT', 'È... disastrosamente ordinario. Fuliggine e cenere, eternamente immutate?\n\n<Q\'onzu scuote la sua enorme testa.>\n\nNo. Non mi piace.', 56819),
(78042, 'itIT', 'Le azioni contano più delle domande, $gcampione:campionessa;.\n\nRicordalo, la prossima volta che la preda invaderà la tua terra natale.\n\n<Aviana lancia un\'occhiata crudele a Q\'onzu.>', 56819),
(78043, 'itIT', 'Be\', questo SÌ che è interessante, vero?\n\n<Q\'onzu freme mentre zampetta entusiasta.>\n\nAffascina anche te, vero, $n? \n\nOh, ma che dico. Certo che sì!', 56819),
(78041, 'itIT', 'Mi aspettavo che Cenarius avrebbe inviato un po\' di aiuto prima o poi.\n\nMa questo folle Loa terrestre?\n\n<Aviana batte l\'artiglio infastidita mentre lancia a Q\'onzu un\'occhiataccia.>', 56819),
(78598, 'itIT', 'Il tuo contributo ci ha aiutato ad accumulare abbastanza potere per un\'altra Infusione del Sogno! Ottimo lavoro.', 56819),
(72241, 'itIT', 'Ora sai la verità.\n\nIl passato è passato. È tempo che i Dracthyr cerchino un nuovo futuro a fianco degli altri popoli di Azeroth.', 56513),
(66079, 'itIT', 'Ah, $gcampione:campionessa;! Il tuo arrivo è provvidenziale. Ora che sei qui, il mio piano avrà successo.', 56513),
(70335, 'itIT', 'Il tuo aiuto è molto apprezzato! Come segno della nostra gratitudine, voglio offrirti uno dei miei speciali attrezzi da scavo. Ne ho in vendita di tutti i tipi, quindi torna pure da me se vuoi completare il set.\n\nGrazie, $gavventuriero:avventuriera;!', 56513),
(66124, 'itIT', 'Non potevo riposare prima che le uova fossero al sicuro... È un sollievo.\n\nGrazie, $p.', 56513),
(71135, 'itIT', 'Non facciamolo mai più.', 56647),
(71000, 'itIT', 'Ecco Barst... Fastidioso come sempre.', 56647),
(70996, 'itIT', 'Guarda un po\', sembra che dovrò recarmi ad aiutare il mio amico Zannatetra, dopotutto!', 56647),
(71014, 'itIT', 'Guarda guarda, hai fatto tutta la strada fino a qui! Come posso esserti utile?', 56647),
(70940, 'itIT', 'Le imprese dei Tuskarr delle Isole dei Draghi sono numerose!\n\nTuttavia, negli anni alcune delle nostre storie sono andate perdute. Molti viaggiatori non sono mai tornati dalle loro avventure per raccontarcele.\n\nTi prego, se dovessi trovare delle pergamene che documentano i successi dei nostri fratelli dispersi, riportale da me.', 56647),
(72291, 'itIT', 'Come dici? Hai una storia per me? Siediti, racconta!\n\n<L\'Anziana Poa ascolta il tuo racconto di una vittoria contro un nemico insolito.>\n\nCom\'è stato emozionante! Ti ringrazio per avermelo raccontato, giovane.', 56647),
(70942, 'itIT', 'Salve, $gamico mio:amica mia;! Vedo che stai imparando le usanze dei Tuskarr e quindi anche il nostro modo di pescare.\n\nSe desideri, potrei costruirti qualcosa che ti permetterà di pescare nei banchi di pesce delle alture delle Isole dei Draghi. Credi di essere all\'altezza della sfida?', 56647),
(70953, 'itIT', 'Saluti, $gcaro amico:cara amica;.\n\nHai mostrato una grande gentilezza verso la nostra comunità qui a Iskaara. Ho sentito delle tue imprese e volevo regalarti un oggetto fatto a maglia come segno di ringraziamento.\n\nScegline uno! Ho cucito tantissimi cappelli per ingannare il tempo durante i lunghi inverni. Sarei anche felice di scambiarne altri con te, se vuoi!', 56647),
(70893, 'itIT', 'Quando tutti collaborano, la zuppa è BUONISSIMA!\n\nDovresti assaggiarla, quando sarà pronta!', 56647),
(66015, 'itIT', 'La Pietra del Giuramento ha nuova energia. C\'è molto da fare, ma la Vastità Azzurra è finalmente tornata ciò che era un tempo.', 56647),
(70041, 'itIT', 'Raszageth è fuggita, Vakthros è ormai stabile... e sono arrivati altri Draghi Blu.\n\nOra credo potremo riposare un po\'.', 56647),
(66009, 'itIT', 'Che piacere vederti, $gavventuriero:avventuriera;. Non c\'è tempo da perdere!', 56647),
(66007, 'itIT', 'Ti ringrazio, $n. Ora è tempo di mostrare ai Primalisti la vera forza dell\'Aspetto dello Stormo dei Draghi Blu!', 56647),
(65977, 'itIT', 'Ti ringrazio. Non possiamo abbandonare nessuno in questo scontro.', 56647),
(65958, 'itIT', 'Quel globo trabocca di potere! Sarà perfetto per ciò che verrà.', 56647),
(65943, 'itIT', 'Ottimo lavoro, parte delle loro forze si sta spostando da lassù.', 56647),
(66647, 'itIT', 'Ci siamo! Tienilo stretto... ti servirà per ciò che verrà.', 56647),
(65944, 'itIT', 'Questo dovrebbe rallentarli un po\'. Mi sa che mi sto arrugginendo, rispetto allo scontro con la Legione Infuocata...', 56647),
(65887, 'itIT', 'È peggio di quanto mi aspettassi. Non c\'è tempo da perdere.', 56647),
(67299, 'itIT', 'Grazie, $gavventuriero:avventuriera;. Ogni momento di pausa da questi attacchi è ben accetto.', 56647),
(65886, 'itIT', 'Ho visto Kalecgos e Khadgar dirigersi verso le montagne un attimo fa. Stiamo tenendo duro contro i Primalisti qui, ma un po\' di aiuto ci farebbe comodo!', 56647),
(66027, 'itIT', 'Dobbiamo muoverci, $n.', 56647),
(65911, 'itIT', 'Non avrei mai pensato di imparare così tanto dai Tuskarr. Credo che tornerò a fargli visita appena potrò, per mantenere il nostro legame d\'amicizia.', 56647),
(65850, 'itIT', '<Kalecgos sembra distante.>', 56647),
(66211, 'itIT', 'Iskaara sarebbe persa senza di te.', 56647),
(66429, 'itIT', 'Ho cominciato ad apprezzare Lathos solo alla fine... Prima avevo dato per scontate la sua pazienza e la sua esperienza.\n\nGli dobbiamo le nostre vite.\n\n<Rannan guarda verso le Rovine di Karnthar.>\n\nNon lo dimenticherò mai.', 56647),
(66428, 'itIT', 'Ci ha lasciati... così?\n\nHa dato la vita per salvarci perché il D.E... quella macchina... non ha funzionato.\n\nLathos credeva in me... Avrei dovuto dargli ascolto... L\'ho deluso...', 56647),
(66427, 'itIT', 'È fatta, allora.\n\nOra tocca a Rannan. Mi fido di lui, ce la farà. Le sue abilità ci hanno portati fin qui...', 56647),
(66426, 'itIT', 'È peggio di quanto pensassimo. L\'energia arcana ha quasi raggiunto il picco.\n\nQualcosa sta accelerando il processo.', 56647),
(66425, 'itIT', 'Ce l\'hai fatta, $p! Be\', tu e il D.E.R.A.P.S.\n\nMa lasciamo stare... Ora aiutami a riportare Lathos al Campo Che Non C\'è.', 56647),
(66423, 'itIT', 'Questa... è una pessima notizia.\n\nSe Sindragosa non è stata in grado di controllare Karnthar e ha ordinato l\'abbandono di questa stazione, posso solo immaginare per quali atrocità potrebbe usarla la Fiamma Frammentata.\n\nNon dobbiamo lasciarla cadere nelle loro mani.', 56647),
(66422, 'itIT', 'Questi tizi della Fiamma Frammentata non sono morti per mano mia... o per la \"mossa speciale\" di Rannan.\n\nErano già morti quando siamo arrivati.\n\nRannan pensa che abbiano subito ferite multiple da trauma per via dell\'energia arcana.\n\nSono d\'accordo con le sue osservazioni, ma non è chiaro se fosse la console dei draghi che si scaricava o fuoco amico...', 56647),
(66353, 'itIT', 'Mmm, hai dissipato le anomalie, ma... Sfortunatamente, il D.E.R. rileva ancora un picco arcano che cresce di minuto in minuto.\n\nNon va affatto bene.', 56647),
(66352, 'itIT', 'Ti ringrazio per il tuo impegno, $p. La tua abilità ed efficienza sono fuori dal comune.\n\nForse non sono l\'unica persona che avrà una \"buona influenza\" su Rannan.\n\nOra... scopriamo cosa sta facendo la Fiamma Frammentata.', 56647),
(66391, 'itIT', 'Sapessi cosa ti sei $gperso:persa;! Siamo finiti DRITTI di fronte a una pattuglia della Fiamma Frammentata.\n\nLathos li ha AFFETTATI con la sua spada, ma ce n\'erano troppi!\n\nQuindi io mi sono messo a lanciare esplosioni arcane da una parte all\'altra... BOOM! BANG!\n\nOh, ma ehm, sì... Il picco di energia...', 56647),
(77746, 'itIT', 'Una donazione alle taverne sulle Isole dei Draghi per coprire il conto!', 56647),
(66152, 'itIT', 'Il nostro clan è stato ridotto a brandelli.\n\nSpero che un altro ci accetterà.', 56647),
(66151, 'itIT', 'Mio Capo Tribù, mi dispiace.\n\nNon c\'era nient\'altro che si potesse fare.', 56647),
(66149, 'itIT', 'Non perdonerò mai i Primalisti per aver fatto soffrire il nostro clan.', 56647),
(66148, 'itIT', 'Mi dispiace che tu abbia incontrato il Clan Spinaruggine adesso. La mia gente non è così.', 56647),
(66150, 'itIT', 'Moltissimi membri del mio clan sono caduti in battaglia insieme ai loro fratelli e sorelle... Solo per una promessa di potere.\n\n<Radza emette un ringhio gutturale, che diventa poi un lungo sussurro di dolore.>', 56647),
(66141, 'itIT', 'Mio fratello diceva la verità.\n\nÈ ancora peggio di quando ho lasciato questo posto.', 56647),
(66972, 'itIT', 'La cosa non mi fa piacere.\n\nTuttavia, appenderò la sua zanna in un posto speciale.\n\nGrazie, $n.', 56647),
(66671, 'itIT', 'Ti manda Caddy? Lei non c\'era prima che iniziasse tutto questo scompiglio con i Tuskarr e i Mezzorsi!\n\nDire che abbiamo molto da fare all\'accampamento sarebbe un eufemismo. Siamo sommersi di problemi!', 56647),
(72784, 'itIT', 'Ci fa sempre comodo altro aiuto. Permettimi di illustrarti la nostra situazione attuale.', 56647),
(66493, 'itIT', 'Ottimo lavoro! Non preoccuparti... È stata colpa del corriere. Avrebbe dovuto scrivere \"fragile\" sul pacchetto.', 56647),
(66523, 'itIT', 'Grazie, $p. I Tizzoconi diverranno roventi, i Nuclei Elementali provvederanno al raffreddamento. Questa pelle, invece... be\', è abbastanza disgustosa. Comunque sia, i mantici che ne ricaverò saranno molto utili!\n\nOra mi serve solo un po\' di tempo.', 56647),
(66489, 'itIT', 'Ottimo lavoro!\n\nDopo aver respinto l\'attacco all\'accampamento, dobbiamo continuare a tenere a bada i Primalisti.\n\nOra ridammi la mia bacchetta, per cortesia.', 56647),
(66488, 'itIT', 'Speriamo che non ci siano altre sorprese intrappolate in quel ghiacciaio.', 56647),
(67036, 'itIT', 'Sono felice che l\'attacco sia stato respinto... ma sembra che dovremo trovare un modo per aiutare Kalecgos negli Archivi Azzurri.', 56647),
(67033, 'itIT', 'Eccellente. A breve darò il via al rituale per risolvere questo problema.', 56647),
(67035, 'itIT', 'Che sollievo! Perdere tutta quella conoscenza... non riuscivo a sopportarne il solo pensiero.', 56647),
(77096, 'itIT', 'Una donazione alle taverne sulle Isole dei Draghi per coprire il conto!', 56647),
(66228, 'itIT', 'Ah, $n. È bello vederti...\n\nUn momento... Hai sentito?', 56647),
(67177, 'itIT', 'Ottimo lavoro! Le metteremo da parte per usarle in futuro nella costruzione.\n\nÈ preoccupante che Mangiatore e la sua specie siano migrati fin qui, ma cercheremo di trarne vantaggio.', 56647),
(67175, 'itIT', 'Oggi abbiamo fatto la cosa giusta. Ci saranno altre stramberie magiche da studiare, mentre questa bimba non riceverà altri regali dal padre scomparso.', 56647),
(67174, 'itIT', 'Una barca giocattolo che in realtà è una bomba a orologeria magica?\n\nOh, cielo.', 56647),
(66227, 'itIT', 'Ah, questo andrà benissimo! Ti ringrazio.', 56647),
(76107, 'itIT', 'Spero ti piaccia la collezione mensile di merci nuove ed esotiche, $n.', 56819),
(49928, 'itIT', 'Anche se alcuni dubitano ancora di noi, le tue gesta hanno dimostrato che i Ren\'dorei servono con onore l\'Alleanza.\n\nLa tua volontà è forte, $n. Accetta questo dono come simbolo dei poteri che brandisci.', 56819),
(72584, 'itIT', 'Bene, non dimenticarti di tornare a recuperarla tra un paio d\'ore; non vogliamo che il pesce vada sprecato!', 56819),
(76735, 'itIT', 'Le locande sono piene di voci su aspiranti criminali che rubano reliquie sacre.\n\nSto supervisionando il ritorno dei beni rubati ai legittimi proprietari. Ho sentito che ci si può fidare di te.\n\nPer favore, riporta questa lancia cerimoniale dei Tuskarr a Iskaara. Fai attenzione ai saccheggiatori!', 56819),
(77203, 'itIT', 'Hai svelato il \"mistero\" e preservato il manufatto!\n\nUn buon preservatore cerca sempre di migliorare nell\'arte di preservare i manufatti. Se trovi qualcosa di nuovo, troveremo un modo per utilizzarlo sul campo.', 56819),
(66246, 'itIT', 'Mi... mi addolora sentirlo... ma lo capisco. Grazie, $C.', 56819),
(66169, 'itIT', 'Ottimo lavoro, $C. Quei mostri si meritano il doppio del dolore che gli hai inflitto!', 56819),
(66167, 'itIT', 'Hai tutta la mia gratitudine e le mie scuse, $gstraniero:straniera;. Nel cuore della battaglia diventa difficile distinguere un alleato da un nemico, e i nemici non mancano mai.', 56819),
(70885, 'itIT', 'Saluti, $C. Hai dimostrato il tuo valore all\'Accordo di Valdrakken. Eccoti alcuni rifornimenti per aiutarti nel supportare la nostra causa. Non deluderci!', 56819),
(66166, 'itIT', 'Quindi, i Primalisti stanno tramando qualcosa nella regione meridionale, mentre i soldati della Guarnigione della Rocca del Sud sembrano spariti... non è un buon segno, $n. Non è per nulla un buon segno.', 56819),
(66163, 'itIT', 'Bene, lasciamo che funga da avvertimento per i Primalisti: non saranno mai i benvenuti a Valdrakken!', 56819),
(78865, 'itIT', 'Non so cosa intenda fare adesso Iridikron, ma non posso più chiamarlo \"fratello\".', 56819),
(78643, 'itIT', 'Cieli limpidi e venti forti, $n.', 56819),
(66159, 'itIT', 'Raszageth! Sta cercando di trovarli... che notizia terribile.\n\nNon sappiamo dove andranno poi i suoi Primalisti. Dobbiamo proteggere la nostra città dal caos.', 56819),
(67073, 'itIT', 'Raszageth e i suoi alleati devono essere fermati!', 56819),
(66675, 'itIT', 'Cos\'è successo, $n? Dov\'è Alexstrasza?', 56819),
(70437, 'itIT', 'Questo spazio sembra abbastanza libero.', 56819),
(76465, 'itIT', 'I Thorignir sono liberi dall\'influenza di quel miserabile Guardiano, per ora... e speriamo per sempre.', 56819),
(76464, 'itIT', 'Come osa negare ai draghi il diritto di andare dove vogliono!', 56819),
(77198, 'itIT', 'Grazie a te, il futuro e la sicurezza del mio stormo sono assicurati.\n\nViaggiare dalle Terre Esterne fino ad Azeroth è stato travolgente, nel senso buono del termine.\n\nGli Alafatua non vedono l\'ora di iniziare a esplorare questo mondo.', 56819),
(70199, 'itIT', 'Restituirò questi pesci alle pozze. Gestire le risorse è una responsabilità importante.', 56819),
(70450, 'itIT', 'Ehi! Ottimo lavoro, $gamico:amica;. Ora possiamo pescare in santa pace!', 56819),
(76463, 'itIT', 'Grazie, $n. I cuccioli le adoreranno!\n\nOh, cielo. Prima i Draghetti d\'Ossidiana, e ora questo?\n\nNon riesco a credere di avere la fortuna di assistere a tutto questo.', 56819),
(77197, 'itIT', 'Irathion dice che ci sono nuovi draghetti in arrivo?\n\nDi un nuovo stormo? Mi confermi che non è uno scherzo?\n\nMolto bene. Iniziamo.', 56819),
(76462, 'itIT', 'Eccellente, $C. Possiamo ripulire il resto e spostarli in un\'altra caverna.', 56819),
(77195, 'itIT', 'A quanto pare, ci sono molti più ragni rispetto all\'ultima volta che sono stato qui.\n\nTuttavia, sembra che Vyranoth abbia in mente un piano d\'azione.', 56819),
(76461, 'itIT', 'Sembrano richieste molto ragionevoli. Niente di oscuro, niente di misterioso.\n\nSono quasi deluso.\n\nDi una posso occuparmi io, ma potrei aver bisogno del tuo aiuto per le altre.', 56819),
(66673, 'itIT', 'La Fiamma Frammentata non ci permetterà di recuperare queste pietre senza combattere.', 56647),
(66013, 'itIT', 'Ci servirà di più per andare avanti.', 56647),
(66012, 'itIT', 'Spero che il viaggio sia stato una bazzecola per qualcuno con le tue capacità.', 56647),
(71227, 'itIT', '$gUn altro:Un\'altra; sfidante? Ti do il benvenuto! \n\nLe Sfide Aeree sono corse a tempo su percorsi sparsi in tutte le Isole dei Draghi. Batti i tempi dei percorsi per ottenere il tuo livello.', 56647),
(73386, 'itIT', 'Congratulazioni! La tua miniatura del Tauren Zoccolo Granitico ora ha un aspetto aggiuntivo!', 56647),
(73389, 'itIT', 'Congratulazioni! La tua miniatura del Murloc ora ha un aspetto aggiuntivo!', 56647),
(67606, 'itIT', 'Oh, grazie, $n! Noi Driadi siamo così impegnate che può essere difficile vedere ogni uccellino o animale malato che vaga per queste strade.\n\nCon il tuo aiuto, però, tutto è andato splendidamente! Non sei niente male come Driade Onoraria! In effetti, potrei chiedere di nuovo il tuo aiuto. Dopotutto, ci sono tante altre adorabili piccole creature di cui occuparsi!', 56647),
(67094, 'itIT', 'Oh, che meraviglia! Scommetto che hanno tutti dei sorrisi stampati sui loro adorabili visi, sul becco, sul muso e quant\'altro.\n\nC\'è un\'altra creatura che ha bisogno del nostro aiuto, però, e temo che la situazione sia piuttosto grave.', 56647),
(72406, 'itIT', 'A nome dell\'Accordo di Valdrakken, non vediamo l\'ora di lavorare con te, $p.', 56647),
(72667, 'itIT', 'È stata una grande corsa allo spuntino, $p. Spero che i draghetti continuino a mangiare volentieri questi cibi.', 56647),
(72668, 'itIT', 'Questo dovrebbe bastare, come prima volta. Ottimo lavoro, $p.\n\nCredo che il nostro curriculum sia a buon punto. Ora, dobbiamo attendere i draghetti.', 56647),
(72666, 'itIT', 'Lasztak mi ha appena informato dei suoi rigorosi studi come Custode dei Draghetti dello Stormo Rosso. La mia esperienza è più che altro pratica. E tu...\n\n<Agapanthus sospira e si gratta il mento.>\n\nDovremo lavorare sul tuo curriculum.', 56647),
(82762, 'itIT', 'Ti aiuterò a progettare la tua insegna personale!', 56647),
(79513, 'itIT', 'Grazie, $p. Se questo non aiuterà Bracithal, temo che nulla possa farlo.', 56647),
(70745, 'itIT', 'Sono felice che la situazione possa finalmente migliorare, ci meritiamo tutti un po\' di riposo.\n\nSpero che potrai rilassarti un po\' qui, te lo meriti, $n.', 56647),
(70744, 'itIT', 'Non lo voglio sapere, vero?', 56647),
(70743, 'itIT', '<Elzara ti ignora e guarda Tesorina.>\n\nSei al sicuro, mia preziosa biscottina?\n\nI Primalisti non ti hanno sanguinato addosso, vero? Come osano!\n\n<Elzara si accorge di te.>\n\nMi aspettavo un\'esperienza senza spargimenti di sangue, darò sicuramente una sola stella a questa spa.', 56647),
(70377, 'itIT', 'I miei occhiali da sole?! Mi sembra di capire che ti aspetti una ricompensa. Il minimo che potessi fare era ripulirli.\n\n<Zeldis soffia sugli occhiali, poi li pulisce.>\n\nImmagino di poterti dare qualche spicciolo.', 56647),
(70740, 'itIT', 'Un buon inizio, ma ce ne sono ancora troppi per i miei gusti...', 56647),
(70741, 'itIT', 'È molto gentile da parte tua raccogliere questi oggetti. Li restituiremo immediatamente ai loro proprietari!', 56647),
(70738, 'itIT', 'Speriamo che quest\'esperienza non influenzi le loro recensioni!', 56647),
(72246, 'itIT', 'Ti do il benvenuto alla Spa Sogni Sereni! Qui con noi, potrai partecipare a diversi tipi di attività rilassanti!\n\nOh! Sei qui per aiutare? Sarebbe un onore ricevere il tuo aiuto.', 56647),
(72067, 'itIT', 'Che gioia. Sono così felice che tu voglia unirti a noi! Comunque, ci farebbe veramente comodo un po\' d\'aiuto.', 56647),
(66444, 'itIT', 'Il nostro fiume e la nostra gente non avrebbero potuto essere salvati senza il tuo aiuto.\n\nLa tribù degli Uktulut è in debito con te.', 56647),
(66443, 'itIT', 'Ricorda le mie parole. Se non se ne occuperà il capoclan, ridurrò in briciole quel Djaradin personalmente!', 56647),
(66415, 'itIT', 'Nulla potrà mai sostituire Ipko. Ma l\'acqua può riempire solo le mani unitesi ad accoglierla.', 56647),
(66431, 'itIT', '<Tutaqan si strofina il volto con entrambe le mani, sospirando profondamente. Sembra esausto.>', 56647),
(66440, 'itIT', '<La mascella di Tutaqan è serrata, con gli angoli degli occhi gonfi di lacrime. Non ti guarda.>', 56647),
(66414, 'itIT', 'È colpa... mia...', 56647),
(66418, 'itIT', 'Ahahah! Ho sentito quel trambusto fin qui!\n\nSe questo non servirà a smuovere Tutaqan, non so cosa lo farà.\n\nAlmeno i nostri cacciatori avranno tutte le armi di cui hanno bisogno per difendere il nostro villaggio, con o senza l\'aiuto del maestro cacciatore. Grazie, $n.', 56647),
(66417, 'itIT', 'Era ora! Sono un po\' bagnati, ma riuscirò comunque a creare un buon numero di ottime armi.', 56647),
(66413, 'itIT', 'Che Oacha\'noa ci protegga! Come mi duole il cuore nel vedere il fiume in questo stato. \n\nQuesta dev\'essere un\'altra delle atrocità dei Djaradin. La loro magia di fuoco sta scaldando il fiume ben oltre ciò che queste povere creature possono sopportare.\n\nMa sarebbe irrispettoso lasciare che questo qui vada sprecato. Avanti, buttalo nella pentola. Lo useremo per il pasto di stasera.', 56647),
(66411, 'itIT', 'Almeno i nostri figli non soffriranno la fame mentre il nostro Capoclan trascura i suoi doveri. Grazie, $n.', 56647),
(66410, 'itIT', '<Tutaqan butta il trofeo per terra, stanco e disinteressato.>', 56647),
(66409, 'itIT', 'Lo ammetto, non mi aspettavo che tornassi $gvivo:viva;.', 56647),
(68640, 'itIT', 'Sei qui per vedere come stiamo? Uhm, certo.', 56647),
(65595, 'itIT', 'Io ora guida gli Gnoll a caccia più buona. Tu... non sei male. Gli Gnoll hanno ancora fame, e tu comunque carne.\n\nVattene. Io non inseguo.', 56647),
(65594, 'itIT', 'Vivi tanto a lungo? Carne buona.', 56647),
(65302, 'itIT', 'Sempre voluto bastone di potere!\n\nORA MON-ARCA DECIDE!', 56647),
(65306, 'itIT', 'Robaccia molliccia. Molto buona.', 56647),
(65279, 'itIT', 'Ottimo inizio... ma pensiamo più in grande.', 56647),
(70954, 'itIT', 'Benché gli Gnoll restino il fulcro delle mie ricerche, sono molto curioso anche riguardo ai draghi che sono appena tornati.\n\nDopo osservazioni e studi approfonditi, ho iniziato a buttare giù qualche appunto sull\'argomento. Non sono neanche lontanamente conclusi, ma quando lo saranno, sono certo costituiranno un\'utile guida anche per te.\n\nNel frattempo, ti andrebbe di dare un\'occhiata ai miei altri manoscritti? Ho iniziato a scambiarli per oggetti che mi aiuteranno a proseguire i miei studi; se vuoi saperne di più, torna a trovarmi!', 56647),
(70943, 'itIT', 'Perbacco, impari in fretta! Le tue abilità nella pesca continuano a migliorare.\n\nVediamo come te la cavi con una lancia. Ora ti costruirò il tuo primo Arpione dei Tuskarr. Staremo a vedere cosa riuscirai a prendere con quello!\n\nSono sicura che non mi deluderai.', 56647),
(68863, 'itIT', 'Se hai un momento, $p, ti sarei grato se potessi aiutarmi.', 56647),
(71230, 'itIT', 'La mia famiglia è nota annovera da generazioni i migliori tessitori di reti e artigiani di arpioni. Se mi porti i materiali necessari, posso costruirti dei nuovi attrezzi.', 56647),
(70941, 'itIT', 'Salute, $gamico pescatore:amica pescatrice;.\n\nHo esitato un po\' prima di dirti di queste tranquille zone di pesca. Ma devo farlo, altrimenti ti priverei di un bel bottino di pesci e del piacere di trascorrere un po\' di tempo a rilassarti con la tua lenza.\n\nDico a tutti che ho paura che il mio posto speciale diventi troppo affollato, ma devo ammettere che la troppa tranquillità non mi piace. Ci si rilassa ancora di più facendosi una bella chiacchierata con gli amici di pesca!', 56647),
(70938, 'itIT', '$gPronto:Pronta; a fare magie, $gavventuriero:avventuriera;?\n\nNo, non intendo quella roba che si fa agitando le mani e che piace a certa gente. Mi riferisco alle arti mistiche degli aromi, alla profonda conoscenza di sapori e ingredienti, al modo in cui la zuppa ci parla per farci sapere di cosa ha bisogno. Hai l\'acquolina in bocca? No? Allora devo essere io.\n\nMettiamoci a cucinare!', 56647),
(75258, 'itIT', '$n, ci sono poche persone che sarebbero arrivate a tanto per aiutarmi in quest\'impresa. Non avevi nessun tornaconto personale, eppure hai rischiato la vita per me.\n\nPer questo, hai la mia più profonda gratitudine. Se un giorno avrai bisogno del mio aiuto, non dovrai far altro che chiedere.\n\n<Baine si inchina profondamente.>\n\nE ora c\'è un\'ultima persona con cui devo parlare.', 56647);
INSERT INTO `quest_offer_reward_locale` (`ID`, `locale`, `RewardText`, `VerifiedBuild`) VALUES
(72611, 'itIT', 'Bovan è morto, ma la sua gente è rimasta. Perché li ha portati qui? Cosa avrà visto nelle sue visioni?\n\nI Totem Fulgido sono sempre stati nomadi. Forse ha visto che avrebbero potuto finalmente trovare una casa.\n\nOppure... sapeva cosa sarebbe successo con i Centauri? Ci ha portato qui per fare la pace con loro? O per fare la pace con l\'odio nei nostri cuori?\n\nTutto ciò che so è che devo continuare a vivere secondo i suoi ideali. In questo modo, renderò onore alla sua vita e al suo ricordo.', 56647),
(72609, 'itIT', 'Baine non ha detto molto da quando siamo partiti dal Forte di Nokhudon. Non avevo capito quanto significasse questo Bovan per lui.\n\nPer quanto riguarda me, tornerò a Maruukai dopo questo funerale. Il compito affidatomi dalla mia khan è stato svolto, anche se non avremmo mai voluto tutto questo.', 56647),
(72607, 'itIT', 'Jamoku è morto, come molti Centauri. Abbiamo vendicato Bovan e gli altri.\n\n<Baine fa una smorfia, mentre si tiene una ferita sul fianco.>\n\nCol senno di poi, forse non avremmo dovuto affrontare l\'intero esercito dei Nokhud. Per fortuna, l\'arrivo tempestivo di Tomul ci ha aiutato.\n\n<Baine lancia un\'occhiata verso Tomul.>\n\nCentauri che combattono per salvare Tauren. Non l\'avrei mai creduto possibile.', 56647),
(72606, 'itIT', '<Dopo aver ucciso decine di Centauri, Baine è visibilmente affaticato. Sta soffrendo ed è ricoperto di ferite.>\n\nJamoku... è il responsabile di tutto questo...\n\nNon gli permetterò di farla franca...', 56647),
(72605, 'itIT', 'Sono arrivato troppo tardi...', 56647),
(72604, 'itIT', 'Ah, eccoti. Bene.', 56647),
(72603, 'itIT', 'Almeno ho qualcuno di cui fidarmi. Grazie, $n.', 56647),
(72602, 'itIT', 'Sì, ottimo! Dal momento che il tuo amico non vuole entrare nelle sorgenti, ho preparato tutto qui.', 56647),
(72601, 'itIT', 'Tomul mi ha informato di ciò che ti serve!', 56647),
(72599, 'itIT', 'Abbiamo messo al sicuro l\'accampamento e salvato chiunque potevamo, ma Bovan non è tra i prigionieri.', 56647),
(72600, 'itIT', 'Ho visto gli stendardi sparsi per tutte le alture. Questo non cambierà ciò che è successo, ma mi ha messo di buon umore.', 56647),
(72663, 'itIT', 'Tomul voleva che ti aspettassi nel suo accampamento, ma io... ho educatamente rifiutato.', 56647),
(72594, 'itIT', 'Grazie per quello che hai fatto per questa gente.\n\nPer quanto riguarda Tomul, odio ammetterlo, ma sembra che si stia dimostrando degna.\n\nNonostante la sua personalità irritante.', 56647),
(74946, 'itIT', 'La buona notizia è che abbiamo trovato gli altri Tauren.\n\nLa cattiva notizia è che questo Bovan che cerca non è qui.\n\nLa notizia irritante è che tutti mi vogliono morto.', 56647),
(72662, 'itIT', 'Ottimo, questo dovrebbe bastare.', 56647),
(72595, 'itIT', 'Ho parlato con i sopravvissuti e nessuno ha visto Bovan sin dalla battaglia.\n\nQuesto copricapo che hai trovato sul Tauren deceduto non appartiene a lui, quindi è possibile che sia ancora disperso... o che sia stato catturato.\n\n<L\'espressione di Baine si indurisce.>', 56647),
(72593, 'itIT', 'Sembra che i Centauri di qui non siano poi così diversi da quelli di Kalimdor.\n\n<Baine osserva Tomul con sospetto.>', 56647),
(72592, 'itIT', 'Ti ho inviato a ottenere informazioni, non a invitare uno di loro a unirsi a noi! Non puoi semplicemente rispedirla a casa?!?', 56647),
(71231, 'itIT', 'Cavalcadraghi! Il tuo aiuto sarà ben accetto nelle battute di caccia future.', 56647),
(72591, 'itIT', 'Ah, $n. Ti ha mandato Mayla?\n\nAnche se preferirei farlo da solo, ammetto che la tua relazione con i Centauri potrebbe essere utile.', 56647),
(65796, 'itIT', 'Grazie, questo mi darà un po\' di tranquillità mentre ci prepariamo per il nostro viaggio.', 56647),
(66698, 'itIT', 'Grazie. Il nostro clan apprezza molto il tuo aiuto.', 56647),
(65789, 'itIT', 'Ti ringrazio. Ne faremo buon uso.', 56647),
(66711, 'itIT', 'Ah, mi tornerà utile.\n\nÈ difficile fare affidamento sugli stranieri per una risorsa così importante, ma non riesco a pensare a un\'alternativa.', 56647),
(71229, 'itIT', 'Il tuo aiuto è ben accetto, Cavalcadraghi. C\'è molto da fare all\'accampamento.', 56647),
(69093, 'itIT', 'Posso stuzzicarti con la storia di una misteriosa porta sigillata?', 56647),
(72665, 'itIT', 'Amella ha detto di venire a incontrarti. Mi hanno chiesto di aiutare Agapanthus con l\'Asilo.', 56647),
(67080, 'itIT', 'Una consegna! Eccellente. È un piacere fare affari con te, $p.', 56647),
(70242, 'itIT', 'Grazie, $n. Andrà benissimo.', 56647),
(70241, 'itIT', 'Capisco, a volte non c\'è molto che possiamo fare.', 56647),
(72664, 'itIT', 'Grazie di essere qui, $p. Presto i draghetti saranno più numerosi di noi.', 56647),
(76531, 'itIT', 'Una donazione alle taverne sulle Isole dei Draghi per coprire il conto!', 56647),
(70026, 'itIT', 'Una consegna! Eccellente. È un piacere fare affari con te, $p.', 56647),
(76598, 'itIT', 'Mi addolora vedere Vyranoth in un luogo così oscuro, ma spero che si unirà a noi proprio come un tempo.\n\nL\'ho avvertita riguardo a Iridikron. È l\'unica cosa che ho potuto fare.\n\nIl resto sta a lei.', 56647),
(73076, 'itIT', 'Vieni dal continente? Allora la nostra richiesta di aiuto ha ricevuto risposta.\n\nI nostri alleati sono arrivati da ogni angolo delle Isole, ma la nostra base delle operazioni non è ancora al sicuro.\n\nVieni, $C. C\'è molto da fare.', 56647),
(71238, 'itIT', 'Sei qui per i manifesti? Funzionano davvero?!?', 56647),
(67093, 'itIT', '<Nozdormu scruta attentamente la sfera mentre gliela consegni. Le sabbie all\'interno si illuminano e turbinano al suo tocco.>\n\nPensavo che questa fosse andata perduta in questa linea temporale. Nulla è definitivo, a quanto pare.', 56647),
(76162, 'itIT', 'Grazie per il tuo aiuto.', 56647),
(76320, 'itIT', 'Arriviamo troppo tardi. Le forze di Fyrakk hanno già iniziato ad attaccare il Sogno!', 56647),
(76319, 'itIT', 'Fyrakk potrebbe attaccare l\'albero da un momento all\'altro. Ci servirà l\'aiuto degli altri Dei Selvatici.', 56647),
(76318, 'itIT', 'Il potere di Fyrakk minaccia l\'essenza stessa del Sogno. Dobbiamo sbrigarci per salvare questo regno. Questo draco ti aiuterà.', 56647),
(76317, 'itIT', 'Non molto tempo fa, l\'Albero del Mondo fu piantato dentro il Sogno di Smeraldo. Lì l\'abbiamo tenuto al sicuro.\n\nOra i nostri nemici hanno trovato un modo per entrare nel Sogno. Dobbiamo unirci e proteggerlo. Serbiamo così tante aspettative nell\'Albero... e nel suo potenziale.', 56647),
(71210, 'itIT', 'Abbiamo vinto un\'altra battaglia, ma la guerra continua.', 56647),
(75923, 'itIT', 'Dobbiamo fidarci di Alexstrasza, per ora.', 56647),
(75922, 'itIT', 'Temevo quello che avremmo potuto scoprire oggi, ma...\n\n<Shandris stringe la presa sull\'arco per controllarsi.>\n\nQuesto va oltre ogni mia immaginazione.', 56647),
(75921, 'itIT', 'Non possiamo avvicinarci oltre senza rivelare la nostra presenza.', 56647),
(75919, 'itIT', 'Distruggere quelle pietre sembra aver spento la magia del fuoco che proteggeva il ponte.\n\nNon possiamo sapere quanto a lungo resterà così, faremo meglio a muoverci rapidamente.', 56647),
(75920, 'itIT', '<Shandris guarda indietro verso i corpi dei Druidi. Sembra sconcertata, ma c\'è soprattutto dolore nei suoi occhi.>\n\nDruidi delle Fiamme?\n\nFyrakk li ha assoldati al proprio servizio?\n\nPerché un Elfo della Notte dovrebbe accettare questo...?', 56647),
(75918, 'itIT', 'Resta nelle ombre, $n.\n\nLunedane pullula già di forze di Fyrakk.', 56647),
(70507, 'itIT', 'Ce l\'hai! Non preoccuparti per me. Dovremmo poterla gestire, a meno che non proviamo a fare qualcosa di folle. Sai, come creare piccoli mostri-pesce che controllano la mente.', 56647),
(66094, 'itIT', 'Ce l\'hai fatta. Ho una bella missione per te, $n!', 56647),
(71138, 'itIT', 'Già $gpronto:pronta;? Hai fatto in fretta!\n\nCustodirò qui questo ricettacolo, sembra avere ancora dell\'energia residua!\n\nNon si sa mai se possa servirci ancora.', 56647),
(70702, 'itIT', 'Vedo che hai ricevuto la mia lettera. È bello rivederti!', 56647),
(65686, 'itIT', 'Eccellente, $gavventuriero:avventuriera;. Posso ragguagliarti sui dettagli prima di dover imparare a... pescare.', 56647),
(66340, 'itIT', 'Ehi, $gavventuriero:avventuriera;! Sono felice che la nostra richiesta di aiuto ti abbia raggiunto.', 56647),
(70183, 'itIT', 'Pazienza, giovane, c\'è ancora molto da imparare.\n\nMa oggi è una buona occasione per festeggiare il fatto che ne sai più di ieri!', 56647),
(69979, 'itIT', 'Il percorso verso la maestria è lento ma costante. Rendi onore al viaggio.\n\nSe cerchi altra saggezza, continua come hai fatto finora. Ci saranno sempre missioni nel mondo, creature da cacciare e da cui imparare.\n\nE io sarò qui per aiutarti a interpretare le conoscenze acquisite.', 56647),
(69946, 'itIT', 'Se vuoi davvero apprendere la mia conoscenza, devi dimostrare di esserne $gdegno:degna;.', 56647),
(67298, 'itIT', 'Oh, davvero interessante! Non si può mai sapere dove si troveranno delle risposte.\n\nTieni gli occhi aperti in caso di eventuali tesori come questo, forse nel mondo c\'è altra conoscenza da scoprire.\n\nE grazie per aver ammirato questo panorama con me. È davvero spettacolare, vero?', 56647),
(69981, 'itIT', 'Oh no! Santo cielo... <Mahra controlla l\'equipaggiamento.>\n\nÈ tutto rovinato, è rimasto troppo a lungo in preda agli elementi.\n\nTieni, prendi questo e crea delle nuove armature. O parla con un cancelliere degli Ordini d\'Artigianato vicino a me o a Valdrakken, e chiedi di farlo fare a qualcun altro.\n\nUn\'ultima cosa, la qualità di questi reagenti non è granché, ma puoi farti ricreare nuovo equipaggiamento più tardi per migliorarne la qualità.', 56647),
(69915, 'itIT', 'Grazie, grazie, grazie! Sei impagabile, $p!', 56647),
(67295, 'itIT', 'Eccellente. Se dovessi avere altre domande sulle specializzazioni, torna pure a parlare con me.\n\nOra esci e affina i tuoi talenti! Oh, e porta questo con te, l\'ho trovato durante i miei viaggi.\n\nHa qualcosa di misterioso, forse le conoscenze contenute al suo interno possono aiutarti con la tua specializzazione.\n\nThomas mi stava dicendo di aver incontrato un mastro artigiano l\'altro giorno, forse saprà aiutarti a sbloccare il segreto al suo interno?', 56647),
(69919, 'itIT', 'Grande, grande, grande! Continua così, ci sono sempre altri ordini da completare!', 56647),
(70985, 'itIT', 'Fiori!\n\n<L\'Esploratrice Santuun si porta la mano alla fronte>\n\nÈ così ovvio, ci ho pensato troppo, come sempre.\n\nGrazie, $n, sei $gil migliore:la migliore;!', 56647),
(70501, 'itIT', 'Eccellente! Sei $gpronto:pronta; a unirti alla Grande Caccia!\n\nInforma questo Nesingwary Jr. che cacciare non significa solo uccidere senza criterio, quindi non sarà il benvenuto tra noi.', 56647),
(72868, 'itIT', 'Solo i più abili cacciatori possono vantare così tanti straordinari trofei. Tu onori la nostra caccia.', 56647),
(71060, 'itIT', 'Le tue imprese onorano il tuo popolo, $gamico:amica; $n. Accetta questo elmo come dono per ringraziarti di tutto ciò che fai per noi.\n\nOvviamente sarò felice di commerciare con te, se dovessi volere altro.', 56647),
(72137, 'itIT', 'Portati via questo affare. Lo scambio volentieri, ti prego. Lo chiamano \"Reggizoccolo\", ma in realtà è solo una seccatura: è sempre d\'intralcio e non è neanche abbastanza grande da essere utile. Voglio sbarazzarmene.\n\nCosa? No, non posso regalartelo, mia moglie non mi perdonerebbe mai.', 56647),
(66339, 'itIT', 'Con questa vittoria, hai aiutato i Maruuk più di quanto tu possa immaginare. Il nostro più sincero ringraziamento, $n. Vai, ora, con la benedizione di Ohn\'ahra.', 56647),
(77152, 'itIT', 'Una donazione alle taverne sulle Isole dei Draghi per coprire il conto!', 56647),
(72363, 'itIT', 'Ah, Cavalcadraghi. $gBentornato:Bentornata;. Tieni, della polvere. No, non ho idea di cosa sia, sinceramente. I mistici Ohn\'ir dicono che aiuti a comunicare con i nostri antenati che sono tutt\'intorno a noi. Un\'idea un po\' ottimistica, se chiedi a me.\n\nA ogni modo, non posso pretendere di capire gli Ohn\'ir, e a essere proprio onesti: neppure voglio provarci. Sono brava gente, per lo più, ma sono strani, snervanti. Però sono alleati e mi hanno chiesto di darla a te e di fartene avere altra se la volessi; quindi, eccomi qua.', 56647),
(69096, 'itIT', '<Gli occhi di Selbekh brillano ancora di lacrime.>\n\nTaivan... quindi è questo il suo vero dono.\n\nCome ho potuto essere così cieca? È diverso dagli altri bakar, sì, ma si è dimostrato un prezioso membro del Clan Teerai. Rimarrà al mio fianco per il resto dei suoi giorni, salvando chi può e guarendo chi non mi è possibile.\n\nTi prego, vieni a trovarci quando vuoi! Siamo entrambi veramente grati per tutto quello che hai fatto per noi!', 56647),
(69095, 'itIT', 'Ed eccoci qui, di nuovo a casa, sani e salvi.\n\nNon so come esprimervi la mia gratitudine, tu e Taivan siete arrivati proprio al momento giusto. Avete salvato molte vite, oggi!', 56647),
(69094, 'itIT', 'Sembra... che ci siano tutti!\n\nTaivan! Incredibile! Ci sa fare veramente!', 56647),
(68087, 'itIT', 'Oh, $n! Grazie a Ohn\'ahra il messaggero ti ha $gtrovato:trovata;. Siamo piuttosto impegnati, qui!', 56647),
(71022, 'itIT', 'Poteva andare meglio... Scusa, ma non credo che Taivan sia portato per la pastorizia.\n\nÈ un bakar molto simpatico, ma non sembra abbastanza intelligente da capire come far entrare le argali nel recinto, o abbastanza aggressivo da prendere il comando del gregge al posto del montone.\n\nTemo di doverti rimandare da Selbekh con delle cattive notizie.', 56647),
(68085, 'itIT', 'Mmm... Taivan sembra ancora confuso. A quanto pare, non riesce proprio a capire cosa fare.\n\nTuttavia, hai fatto un ottimo lavoro! Stai pensando a una nuova carriera?', 56647),
(68084, 'itIT', 'Ohilà, salve! Cosa posso fare per te e... per il tuo grosso amico?', 56647),
(68083, 'itIT', 'Taivan è appena tornato. Suppongo che non sia stato addestrato così velocemente. Direi di no...\n\n<Sospira profondamente e guarda Taivan.>\n\nNeanche lui sembra prenderla bene. Ho un\'altra idea, se non funziona, dovremo prendere delle decisioni difficili.', 56647),
(70989, 'itIT', '<Jadar scuote la testa.>\n\nMolto deludente. Temo che Taivan non abbia la capacità di cacciare come uno Shikaar. Non riusciva a scrollarsi di dosso la sua riluttanza ad attaccare nemmeno con altri bakar che combattevano al suo fianco.\n\nChe spreco!', 56647),
(67921, 'itIT', 'Il tuo bakar, sebbene forte e imponente, non sembra avere la volontà per fare il suo dovere nella caccia. È troppo gentile!\n\nGli darò un\'altra possibilità, ma poi basta!', 56647),
(67772, 'itIT', 'Cosa ti porta nei terreni di caccia degli Shikaar?\n\nI Teerai vorrebbero che addestrassimo il tuo bakar come un cacciatore? Di solito non accettiamo tali richieste da altri clan, ma la prenderò in considerazione. Il loro dono è molto generoso e una bestia della sua taglia, ben addestrata, sarebbe uno spettacolo da vedere. Scommetto che potrebbe abbattere un mammut adulto da solo!\n\nMmm... Dovrò vederlo in azione prima di prendere la mia decisione.', 56647),
(66783, 'itIT', 'Ora che i nostri legami di fiducia sono stati rinnovati, nulla può fermarci. Per il vento e per le ali, così sia!', 56647),
(66336, 'itIT', 'Ti do il benvenuto nel Bosco Antico. Ti trovi davanti alla Pietra del Giuramento di Smeraldo dello Stormo dei Draghi Verdi.', 56647),
(66337, 'itIT', 'Finalmente è finita. La nostra isola sacra è di nuovo al sicuro. Grazie per tutto quello che hai fatto per la mia razza, $n.', 56647),
(66335, 'itIT', 'Sarò per sempre grata ai draghi per essere stati dalla nostra parte durante questa battaglia.', 56647),
(66784, 'itIT', 'Ora che abbiamo eliminato i rinforzi dei nostri nemici, la battaglia entrerà nella fase finale. Ottimo lavoro, $n.', 56647),
(66333, 'itIT', 'Finalmente, addio a quelle terribili armi. Che nessun altro drago soffra come ha sofferto Solethus.', 56647),
(66331, 'itIT', 'I nostri nemici sono un passo avanti a noi. Non disperare, la nostra determinazione è forte quanto la nostra alleanza. Preparati, $n.', 56513),
(70220, 'itIT', 'Allora, il mio stormo è pronto? Bene. Affronteremo i nemici con tutto ciò che abbiamo.', 56513),
(66344, 'itIT', 'Siamo arrivati, mortale. Ti do il benvenuto nei Giardini di Smeraldo.', 56513),
(66328, 'itIT', 'I nostri antenati dicevano che i Draghi Verdi erano temprati e saggi. Siamo fortunati che abbiano trattenuto la loro rabbia abbastanza a lungo da ascoltare la nostra versione della storia.\n\nOra che sappiamo che i Primalisti e i Nokhud sono il nostro nemico comune, è arrivato il momento di abbatterli.', 56513),
(66329, 'itIT', 'Non mi fermerò finché Balakar non risponderà dei crimini che ha commesso oggi. Il massacro del mio popolo, la blasfemia contro Ohn\'ahra, il tradimento verso il nostro alleato...\n\nMa la vendetta dovrà aspettare, ci sono questioni più urgenti: dobbiamo aiutare i Draghi Verdi.', 56513),
(70244, 'itIT', 'Cosa stanno facendo a Ohn\'ahra? Balakar e Koroleth la pagheranno cara per questo!', 56513),
(66327, 'itIT', 'Siamo arrivati tardi. I Nokhud hanno preso il Corno di Drusahl e hanno ucciso la mia gente.\n\nQuesta aggressione non resterà impunita!', 56513),
(66259, 'itIT', 'Sono notizie tragiche, $n. Tuttavia, dobbiamo rimanere concentrati. Abbiamo incassato un brutto colpo, ma non abbiamo ancora perso.', 56513),
(71058, 'itIT', '$n, tu sai cavalcare i draghi, vero? La nostra alleanza promette bene.\n\nAccetta questo dono, per celebrare la nostra sempre più solida coalizione. E ti prometto che ci sarà molto di più!', 56513),
(66258, 'itIT', 'Che caduta! Siamo fortunati a essere ancora vivi!', 56513),
(66257, 'itIT', 'Ho la certezza che ci sia di più là fuori, ma abbiamo annientato quello che potevamo. Si spera che questo almeno li rallenti.', 56513),
(66256, 'itIT', 'Dopo tutto quello che Ohn\'ahra ha fatto per noi, dobbiamo fare tutto il possibile per aiutare le sue figlie. Grazie, $n.', 56513),
(66242, 'itIT', 'Non avrei voluto nessuno spargimento di sangue, ma i Nokhud devono essere fermati.', 56513),
(66236, 'itIT', 'Balakar e quei maledetti Primalisti hanno calpestato le nostre credenze più sacre.', 56513),
(70195, 'itIT', 'Quindi, siamo in guerra con entrambi, i Nokhud e i Primalisti. Ora è ancora più importante che Ohn\'ahra e i draghi siano dalla nostra parte.\n\nGrazie per l\'aiuto, $n, e grazie per aver salvato Altan.', 56513),
(66225, 'itIT', 'Quanti totem. Quanti mistici caduti.', 56513),
(66224, 'itIT', 'Ho evitato quell\'imboscata per un soffio! Temo che i miei compagni mistici non siano stati così fortunati...', 56513),
(66254, 'itIT', 'Ancora nulla. Neanche un segno da Ohn\'ahra.', 56513),
(70229, 'itIT', 'Tu chi sei? Ti manda Ohn\'ahra?', 56513),
(66222, 'itIT', 'Non volevo creare panico, ma la gente deve essere pronta. Il Clan Nokhud non è noto per la sua misericordia.', 56513),
(66690, 'itIT', '...Pensavo non avrei più visto sorgere di nuovo il sole.', 56513),
(66201, 'itIT', '<Jebotai legge il messaggio. La sua espressione si fa sempre più preoccupata.>', 56513),
(71027, 'itIT', 'Mara\'nar è stato ucciso. Che i suoi simili imparino a restare nelle loro terre.', 56513),
(65806, 'itIT', 'Ti do il benvenuto a Maruukai.', 56513),
(66848, 'itIT', 'La tempesta è un presagio di macabra sventura. Ci sono guai all\'orizzonte.', 56513),
(65805, 'itIT', 'Eccellente. Userò questi materiali per interpretare la sua canzone.', 56513),
(65940, 'itIT', 'Percepisco qualcosa nel vento.', 56513),
(65804, 'itIT', 'Cacci e combatti in modo strano. Spero che Aru e Belika abbiano osservato la tua tecnica.', 56513),
(70185, 'itIT', '<Tomul guarda la pelle, prima di farti un piccolo cenno.>\n\nHai sconfitto Konkhular, quindi. Non male, due-piedi. Sfuggiva ai nostri cacciatori da molte lune; la sua pelle si confondeva bene con l\'ambiente circostante. Forse ora i nostri cacciatori potranno usare la sua mimetizzazione a proprio vantaggio.', 56513),
(65803, 'itIT', 'Prendi fiato, due-piedi.', 56513),
(70319, 'itIT', 'Grazie. Con questi reagenti dovrei essere in grado di impedire all\'infezione di diffondersi, quindi spero di guarire completamente. Ti devo la vita.\n\nFai attenzione a Nergazurai, viandante. La sua sete di sangue è inestinguibile.', 56513),
(66006, 'itIT', 'Hai i rifornimenti? Bene.\n\nLasciali vicino alla forgia.\n\n<Roscha si guarda intorno e aggrotta la fronte.>', 56513),
(65949, 'itIT', 'È forse... Oh sì, la mia amata ora è lassù nel cielo, che corre al fianco di Ohn\'ahra. Mi unirò a lei... quando verrà il mio momento.\n\nGrazie, $p.\n\nMi ricorderò di ciò che hai fatto per il Clan Shikaar. E per me.', 56513),
(66005, 'itIT', 'Questo medaglione è tutto ciò che resta di una mia cara amica che osò addentrarsi troppo a fondo nella palude, la scorsa stagione. Pensavo fosse ormai perduto.\n\nHo reciso questo lembo di cuoio durante la sua prima battuta di caccia ai mammut. Eravamo bambini, allora.', 56513),
(65952, 'itIT', 'Ora che il loro Capo Tribù è stato ucciso, i Gorloc non ci disturberanno più. \n\nMi stupisce la forza che hanno raggiunto sotto il comando del Capo Grrlgllmesh. \n\nNon ho mai visto prima creature tanto primitive ribellarsi contro una civiltà progredita come la nostra. Forse non siamo così diversi? O così evoluti? Suppongo di no.', 56513),
(65955, 'itIT', 'Grazie, $p. Qui siamo al sicuro e possiamo parlare liberamente. \n\nProteggerò Baba da qualsiasi Gorloc osi avvicinarsi mentre riposa.', 56513),
(65954, 'itIT', 'Che bestie magnifiche, non è vero?\n\nOgni Bakar occupa un posto speciale nel Clan Shikaar. Sono i nostri compagni cacciatori, i nostri guardiani e i nostri amici più amati.', 56513),
(65953, 'itIT', '<Khasar lancia uno sguardo contrariato verso i totem.>\n\nQuesti totem sono legati alla magia della tempesta. La magia della tempesta è un sacrilegio, un affronto verso i venti che Ohn\'ahra in persona ci dona.\n\nLi consegnerò ai mistici.', 56513),
(65950, 'itIT', 'Ti ha mandato Roscha? Dev\'essere furiosa.\n\nNe ha già passate così tante... Non posso certo tornare senza prima aver ritrovato tutto ciò che è stato perso.', 56513),
(65951, 'itIT', 'Grazie $p. Mettiamoci al lavoro!', 56513),
(65801, 'itIT', 'Il resto del clan che presenzierà ha già raggiunto Maruukai per preparare il sito. La carovana proveniente da questo avamposto sarà l\'ultima ad arrivare.', 56513),
(65802, 'itIT', '<L\'Esploratrice Tomul dà un\'occhiata alle provviste raccolte.>\n\nSembra tutto in ordine.', 56513),
(70174, 'itIT', '<La Khan Sansok annuisce leggermente.>', 56513),
(65783, 'itIT', 'Voi stranieri sembrate avere l\'abitudine di interferire negli affari degli altri.', 56513),
(65780, 'itIT', 'Sei $gun combattente:una combattente; più formidabile di quanto credessi.', 56513),
(65779, 'itIT', 'Sei $gun messaggero:una messaggera; dei draghi, allora. I tempi cambiano.', 56513),
(76401, 'itIT', 'Fyrakk ha superato la barriera! Dev\'essersi sentito disperato quando ha visto le nostre forze avvicinarsi. Per usare tutto quell\'ombrofuoco in una volta...', 56819),
(78066, 'itIT', '<Q\'onzu e i suoi seguaci sono andati via. Dev\'essere questa la risposta che meritavi, secondo loro.>\n\n<Per ora, almeno.>', 56647),
(78162, 'itIT', 'Di nuovo tu? Cos\'è che hai fatto? Ah, sì. Va bene.', 56647),
(78064, 'itIT', 'Ah! Oh, avanti. È stato divertente. Non fare quella faccia.', 56647),
(78163, 'itIT', 'Avevi davvero intenzione di rispondere a cento domande? Pensavo che sarebbe bastato a farti andare via.\n\nLa prossima volta aumenterò la cifra a mille domande.', 56647),
(78065, 'itIT', 'Q\'onzu ha detto che sarebbe arrivato qualcuno in visita. Con delle offerte, spero.', 56647),
(78319, 'itIT', 'Ah, l\'odore fresco dei fiori nell\'aria! \n\nTi ringrazio.', 56647),
(77675, 'itIT', 'Grazie, $n, per averci aiutati con Raelas e con le Pietre dello Spirito.\n\nMi occuperò subito di Shandris e la aiuterò a tornare ad Amirdrassil.', 56647),
(77674, 'itIT', 'Pensavo che Shandris stesse sfogando la sua rabbia su di me perché sono una Reietta.\n\nPensavo che, una volta finito il nostro lavoro, mi avrebbe salutata.\n\nNon sarebbe stata la prima volta.\n\nMa sono felice di essermi sbagliata. Sono arrivata a provare... un grande rispetto per lei e per le sue abilità.\n\nDobbiamo aiutarla.', 56647),
(77673, 'itIT', 'Non conosco Shandris da molto, ma il suo comportamento è anomalo.\n\nNon è da lei.\n\nChissà se...', 56647),
(77665, 'itIT', 'Sarà difficile occuparci di queste pietre con Shandris là fuori da qualche parte.', 56647),
(77664, 'itIT', 'È stato...\n\n<Shandris fissa lo sguardo su qualcos\'altro, profondamente concentrata. Poi scuote la testa come per liberarla.>\n\nIo... Shae\'lune probabilmente vorrà dare un\'occhiata a queste... pietre.', 56647),
(77739, 'itIT', 'Bene!\n\n<Shandris ripone le Pietre dello Spirito in una piccola borsa di cuoio.>\n\nOra mettiamo fine alla follia di Raelas.', 56647),
(77662, 'itIT', '$p. Bene.\n\nAbbiamo messo alle strette la preda. Lascia che ti spieghi la nostra missione.', 56647),
(77958, 'itIT', 'Grazie mille per aver controllato come stanno i miei amici.\n\nQuando si risveglieranno, saremo pronti a combattere le forze di Fyrakk ancora una volta.', 56647),
(77802, 'itIT', 'Un ottimo titolo! Lo userò il più spesso possibile.\n\nGrazie.', 56647),
(76572, 'itIT', 'Ehi, $gGuardiano:Guardiana;! Non mi sono mai sentita così viva come con una lancia in mano!\n\n<Dionaessa fa un sorriso enorme.>\n\nGrazie per la tua protezione!', 56647),
(76571, 'itIT', '$gGuardiano:Guardiana;, se gli Sporoidi stanno avvelenando il terreno da queste parti, allora anche quella crescita laggiù che emana un tanfo incredibile ha bisogno di una bella potatura!', 56647),
(76570, 'itIT', 'Questi cuori puzzano terribilmente! Un odore simile a quello degli Sporoidi, con i loro piccoli dentini...', 56647),
(76569, 'itIT', 'Tu combatti regolarmente e risolvi problemi. A volte per te, a volte per gli altri.\n\nOnestamente, non sembra molto diverso dalla mia esperienza con le Driadi.\n\nCredo che Dionaessa starà bene con te.', 56647),
(76567, 'itIT', 'Grazie, $p. Vedo che per ora le hai calmate.\n\nQuesta non è la prima volta che succede e probabilmente non sarà l\'ultima. Sarà solo per le radici di Amirdrassil? È tutto molto strano...', 56647),
(76568, 'itIT', 'Sembra che Dionaessa abbia scelto te per essere addestrata.\n\n<L\'espressione di Ethidris si irrigidisce.>\n\nPerfetto. Splendido.', 56647),
(77955, 'itIT', 'Gah! Ancora non riesco a prendere sonno! Mi vergogno a chiedertelo, ma resta solo un\'opzione.', 56647),
(77922, 'itIT', 'Grazie per aver riportato la comodità nel mio letto.', 56647),
(77911, 'itIT', 'Grazie per le foglie. Speriamo che mi aiutino a dormire.', 56647),
(77896, 'itIT', 'Le forze di Fyrakk ci hanno attaccato?\n\nCome puoi vedere, non c\'è alcun problema qui.\n\nTuttavia, ho un problema molto più grande tra le mani.', 56647),
(78431, 'itIT', 'Fantastico! Ha funzionato!', 56647),
(78430, 'itIT', 'Eccellente! Dovremmo riuscire a eseguire l\'infusione!', 56647),
(76566, 'itIT', 'Ti manda Cenarius in persona? Fantastico. Abbiamo bisogno d\'aiuto.\n\nDobbiamo trovare quella ghianda di Driade!', 56647),
(78386, 'itIT', 'Per fare una cosa, devi prima sognarla.', 56647),
(77318, 'itIT', 'La tua performance come Merithra è stata impareggiabile.\n\n<Dama Baccaluna scoppia a ridere.>\n\nRiesco a malapena a distinguervi!', 56647),
(77317, 'itIT', 'Non me l\'aspettavo. Pensavo di prendere in giro anche te!\n\nMa a quanto pare, sei meglio di quanto mi aspettassi...\n\nForse è l\'ora di una vera sfida.', 56647),
(77316, 'itIT', 'Che sollievo!\n\nOra che abbiamo recuperato quei rifornimenti molto importanti, possiamo tornare al lavoro.', 56647),
(77178, 'itIT', 'Quindi Fyrakk vuole arrivare alla Sorgente.', 56647),
(77978, 'itIT', 'Lyandris aveva conservato tutto questo? E tu... hai finito ciò che aveva iniziato.\n\nGrazie per avermi riportato il suo diario. Tieni pure i documenti. Forniranno informazioni preziose per te e i tuoi alleati. \n\nPer me sarebbero solo un triste promemoria.', 56647),
(77948, 'itIT', '<L\'espressione di Solarys si incupisce per il dolore provocato dalla tua spiegazione.>\n\nI momenti passati con la mia famiglia valgono più di un\'eternità di rimpianti. La vita stessa vale di più, ma le mie suppliche sono cadute nel vuoto.\n\nGrazie per aver salvato quel poco che è rimasto della mia famiglia.\n\nUna delle creaturine che Kery\'nael ha aiutato a salvare sembra averti preso in simpatia. Prendila con te, per favore. È il minimo che possiamo offrire al povero esserino.', 56647),
(78427, 'itIT', 'Ti siamo sempre grati per il tuo contributo.', 56647),
(76347, 'itIT', 'Non posso festeggiare la perdita di un\'amica, ma andava fatto.', 56647),
(76348, 'itIT', 'Grazie per aver impedito il suo assalto.', 56647),
(76532, 'itIT', 'Buri è qui?', 56647),
(76345, 'itIT', 'Vyranoth non riposerà finché Terro non sarà vendicato.', 56647),
(76344, 'itIT', 'Terro è sempre stato protetto verso coloro che comandava. Avrebbe voluto che ne salvassimo il più possibile.', 56647),
(76343, 'itIT', 'Lethka ha lasciato quegli appunti?', 56647),
(76342, 'itIT', 'Distruggere le loro forze dovrebbero proteggere il Sogno, per ora.', 56647),
(76403, 'itIT', 'I miei Artigli sono qui?', 56647),
(78821, 'itIT', 'Grazie! Sono questi piccoli gesti che permettono al Sogno di Smeraldo di fiorire, e quindi di nutrire Amirdrassil.', 56647),
(78381, 'itIT', 'Che bella notizia! Man mano che ne troverai altre, puoi continuare a combinarle, a giovamento del tuo equipaggiamento creato.', 56647),
(78171, 'itIT', 'Ottimo lavoro. Ora forse potremo capire come fare per ripristinare altre specie di piante dai semi che riuscirai a trovare.', 56647),
(78170, 'itIT', 'Grazie, $n. La tua disponibilità ad aiutarci a prenderci cura di questi antichi semi mi scalda il cuore.', 56647),
(77209, 'itIT', 'Denalan sarebbe orgoglioso di vedere il suo lavoro proseguito da una persona come te!', 56647),
(78385, 'itIT', 'Accetta questi Semonirici come ringraziamento per tutto ciò che hai fatto.', 56647),
(78172, 'itIT', 'Questi semi contengono la chiave per sbloccare l\'eredità di gran parte della strana flora che è andata perduta negli incendi che hanno consumato Teldrassil.', 56647),
(76443, 'itIT', 'Sono felice di rivederti, $c. Vorrei poterti dare un attimo per riprendere fiato dopo tutto il lavoro che hai fatto.\n\nPurtroppo, non possiamo permetterci questo lusso. Non appena si spegne una fiamma, ne nasce subito un\'altra. Amirdrassil è ancora in pericolo.', 56647),
(76442, 'itIT', 'Questo cosiddetto Profeta millanta di rappresentare gli interessi dei Kaldorei, ma io vedo oltre il suo gioco. Vuole solo il potere, e sfrutta la paura e la sofferenza dei Kaldorei per ottenerlo.\n\nNon può continuare così. Non finché sono ancora in vita.\n\nAbbiamo fatto tutto quello che potevamo qui, per ora. Dobbiamo tornare ad Amirdrassil.', 56647),
(76441, 'itIT', 'È difficile pensare che dei Druidi vogliano corrompere il Sogno in un modo del genere, anche dopo tutto quello che abbiamo passato.\n\n<Tyrande si rattrista.>\n\nQuesti \"druidi\" sono un affronto a tutta la sofferenza dei Kaldorei.', 56647),
(76437, 'itIT', 'Anche se distorti dalla fiamma, questi druidi non hanno dimenticato come muoversi nel Sogno. Sarà difficile impedire loro di entrare.\n\nComunque, senza una base operativa, non sarà facile per loro diffondere la propria influenza. Le tue imprese oggi hanno aiutato a mettere Amirdrassil al sicuro dal fuoco.', 56647),
(76435, 'itIT', 'Norana... Sei sempre stata un\'anima tranquilla e gentile. E pensare che avresti potuto far parte di qualcosa di così terribile...\n\n<Tyrande sospira.>\n\nC\'è ancora molto da fare.', 56647),
(76434, 'itIT', 'Non c\'è giorno dove non riviva il ricordo di coloro che sono caduti a Teldrassil, consumati da un fuoco che non ho potuto spegnere. \n\nNon lascerò che le urla degli afflitti si perdano nel vuoto, siano essi Kaldorei o Driadi. Non finché sarò ancora in vita.', 56647),
(76433, 'itIT', '<L\'espressione di Tyrande è a metà tra tristezza e convinzione.>\n\nQuesti non sono i Druidi delle Fiamme di Fandral Elmocervo. Pensare che una persona così gentile e compassionevole come Norana sia finita nei loro ranghi...\n\nForse non riusciremo mai a capire la profondità delle ferite causate dalla caduta di Teldrassil.', 56647),
(77436, 'itIT', 'Giusto in tempo, $c. Mi serve un altro paio di mani.', 56647),
(77283, 'itIT', 'Tyrande è andata a indagare sui Druidi delle Fiamme, per scoprire di più sui loro obiettivi nel Sogno di Smeraldo e identificare i loro leader.\n\nAncora non mi spiego come gli Elfi della Notte e gli abitanti del Sogno abbiano potuto cedere alla fiamma.\n\nScommetto che tu e Tyrande riuscirete a trovare la risposta.', 56647),
(76326, 'itIT', 'Ora che abbiamo un attimo di respiro, possiamo iniziare a pensare a quale sarà la nostra prossima mossa.\n\nSo che, con te dalla nostra parte, siamo più forti.', 56647),
(76460, 'itIT', 'Bene! Dovremmo andare a incontrare il rappresentante degli Alafatua.\n\nIl suo nome è Mordenaku. A quanto pare, anche lui è un principe.', 56647),
(76325, 'itIT', 'Ha abbandonato l\'albero?\n\nChe abbia un altro obiettivo?\n\nE perché sta ascoltando quel Druido delle Fiamme?', 56647),
(76324, 'itIT', 'Il Sogno di Smeraldo è un luogo di natura selvaggia, magia e vita.\n\nMi rattrista vedere una delle nostre patire questa fine. Spero che non sia la prima di molti.\n\nAspetta... Hai sentito?', 56647),
(76323, 'itIT', 'Siamo arrivati giusto in tempo. Dobbiamo intercettare Cassaphine prima che possa fare del male all\'albero... o a noi.', 56647),
(77818, 'itIT', 'Sono felice che tu ce l\'abbia fatta. Non abbiamo avuto scelta se non ritirarci verso l\'albero, prima che arrivino le forze di Fyrakk.\n\nE l\'Anziana Cassaphine... temo che l\'abbiamo già persa in questa profezia della fiamma.', 56647),
(76322, 'itIT', 'È molto peggio di quanto pensassi. Ogni volta che chiudiamo un portale, i Druidi delle Fiamme ne aprono altri.\n\nTemo che attendano di poter passare pericoli ancora più grandi.', 56647),
(76321, 'itIT', 'Hai combattuto bene, anche se temo che ora non sia più possibile fermare queste forze. Potrebbero plasmare per sempre il Sogno.', 56647);
INSERT INTO `quest_objectives_locale` (`ID`, `locale`, `QuestId`, `StorageIndex`, `Description`, `VerifiedBuild`) VALUES
(285546, 'itIT', 43609, 0, 'Signore della Rovina Kazrok ucciso', 56647),
(341060, 'itIT', 53292, 0, 'Pruno di Sirena Germogliante', 56819),
(341021, 'itIT', 53271, 0, 'Muschio Stellare Germogliante', 56647);
INSERT INTO `quest_request_items_locale` (`ID`, `locale`, `CompletionText`, `VerifiedBuild`) VALUES
(26296, 'itIT', 'Bandane rosse?!?', 56311),
(26288, 'itIT', 'Hai trovato Jango?', 56311),
(26257, 'itIT', 'Hai trovato i Golem?', 56311),
(31780, 'itIT', 'Ma da dove vengono gli allenatori come te?', 56311),
(16, 'itIT', 'Coltivare i campi mette sete. Quello che ci vuole in questi casi è l\'acqua di sorgente fresca.$B$BSe ne hai un po\' con te, possiamo fare uno scambio.', 56288),
(31693, 'itIT', 'Non c\'è nessuno che non possa sconfiggere!', 56288),
(29081, 'itIT', 'Uccidi gli Assassini Goblin!', 56288),
(65779, 'itIT', '<Tomul ti scruta dall\'alto in basso con curiosità.>\n\nDichiara i tuoi affari nelle pianure.', 56513),
(72135, 'itIT', 'Hai trovato qualche oggetto?', 56513),
(66056, 'itIT', 'Hai completato l\'incarico che ti ho affidato?', 56513),
(66055, 'itIT', 'Hai trovato i frammenti mancanti della Pietra del Giuramento?', 56513),
(66049, 'itIT', 'Hai visto la Pietra del Giuramento?', 56513),
(66048, 'itIT', 'Puoi migliorare le nostre probabilità di successo?', 56513),
(66232, 'itIT', 'Ora che me lo fai notare, ho una certa fame.', 56647),
(66147, 'itIT', 'Il lavoro sul campo è estenuante.', 56647),
(66154, 'itIT', 'Hai messo i campioni al sicuro?', 56647),
(66164, 'itIT', 'Tutto ciò è alquanto insoddisfacente.', 56647),
(66223, 'itIT', 'Quanti pesci! Voglio mangiarli tutti!\n\n...Ma non posso. Sono per Zerbino. È importante.', 56647),
(66212, 'itIT', 'Allora, cos\'hai preso?\n\nMeglio che non siano delle acciughe striminzite.', 56647),
(66210, 'itIT', 'Hai preso una scodella di zuppa?', 56647),
(70893, 'itIT', 'È stata una bella fortuna che fossi qui ad assistere al banchetto. Lo facciamo solo sei o sette volte al giorno!', 56647),
(66781, 'itIT', 'Hai trovato una roccia buona?', 56647),
(65846, 'itIT', 'Mi dispiace di non poter essere più d\'aiuto in questa forma. Riesco a percepire il decadimento che offusca la forza della mia immagine.\n\nSpero che una volta raggiunta la Lumigrotta, come la chiamano i Tuskarr, potrò teletrasportarmi nella mia forma completa.', 56647),
(66838, 'itIT', 'Eh? Oh! Sei già qui?\n\nScusa, ero presa dal mio gioco di carte...\n\nHai le pellicce?', 56647),
(66837, 'itIT', 'Hai preso della Carne di Vorquin? E dei Costati di Bruffalo? Grande! Stavo già per mettere sul menù il filetto di stivale...', 56647),
(66843, 'itIT', 'Be\'? Dov\'è finito? Li hai trovati?\n\nDobbiamo muoverci! Quella caverna crollata alla Vedetta Tre Cascate non si sgombererà da sola!', 56647),
(75888, 'itIT', 'Cos\'hai trovato tra i Crogioli e gli Stampi?\n\nTutto questo ombrofuoco mi fa prudere le scaglie.', 56647),
(70926, 'itIT', 'Sei qui per restituirci i totem?', 56647),
(66264, 'itIT', 'Dovrebbero essercene un bel po\' in giro, no?', 56647),
(72586, 'itIT', 'Non fermarti adesso: abbiamo una lingua da imparare!', 56647),
(72547, 'itIT', 'Cosa mi hai portato?', 56647),
(76422, 'itIT', 'Spero che questa esperienza possa unirci.', 56647),
(76420, 'itIT', 'Cos\'altro possiamo fare?', 56647),
(76356, 'itIT', 'Come falene temporali che volano verso una fiamma temporale, quei piccoli elementali sono stati attratti da Shalamarina!\n\nPosso solo sperare che i danni siano minimi.', 56647),
(76258, 'itIT', 'Quei maledetti elementali devono essere usciti dal cuore della mia forgia. Era destabilizzata, in qualche modo?\n\nIn ogni caso, è una pessima notizia. Qualsiasi cronofabbro degno del proprio nome sa che non bisogna mischiare energie elementali e temporali.', 56647),
(76354, 'itIT', 'Giuro sul calore della mia forgia, se uno di quei maledetti saccheggiatori ha depredato le mie casse e mi ha preso tutto...\n\nBe\', noi Draghi di Bronzo conosciamo ogni tipo di tecnica, no?', 56647),
(74942, 'itIT', 'Lo Sporco Temporale! Mi vengono una dietro l\'altra.', 56647),
(65374, 'itIT', 'La Professoressa Cinguetti mi ha detto che ho un buon talento per i congegni! Se non facessi parte dell\'esercito Dracthyr, pensi che avrei potuto lavorare in una città dei Goblin?', 56647),
(65371, 'itIT', 'Hai tutto quello che ti ho chiesto?', 56647),
(65287, 'itIT', 'Salvare queste uova dalle Arpie è fondamentale per proteggere i Piumablu da altri pericoli. Così come qualsiasi altra futura preda che intendano consumare.', 56647),
(65373, 'itIT', 'Sentivo di dover assolutamente dimostrare il mio valore!', 56647),
(65475, 'itIT', 'Già di ritorno dalle caverne?', 56647),
(66472, 'itIT', '<Thadezus ti fissa.>\n\nCosa vuoi, $C?', 56647),
(66473, 'itIT', '<Sharnax tossisce.>\n\nFatto?', 56647),
(66471, 'itIT', 'Hai qualcosa che possiamo mostrare al comandante?', 56647),
(66470, 'itIT', 'Dobbiamo chiudere quei varchi.', 56647),
(66456, 'itIT', 'Fai in fretta, $n. Sto tenendo Nori stabile per ora, ma il veleno si sta diffondendo.', 56647),
(66230, 'itIT', 'Hai trovato altro, $n?', 56647),
(66100, 'itIT', '<Alvi guarda nella tua direzione, chiaramente nel panico. Sembra che al momento le scorte mancanti siano l\'ultima cosa che ha in mente.>', 56647),
(66687, 'itIT', 'Hai già riportato le offerte?', 56513),
(66658, 'itIT', 'Sei $griuscito:riuscita; a sconfiggere gli spiriti leggendari dei nostri fondatori?', 56513),
(70928, 'itIT', 'Cosa mi hai portato?', 56513),
(65901, 'itIT', 'Se mi farai scoprire, ti perseguiterò con il fantasma più ventoso di sempre, PER SEMPRE! Non azzardarti!', 56513),
(66657, 'itIT', 'Quando sarà tutto finito, non avrà una tomba sua.', 56513),
(66655, 'itIT', 'Hai i reagenti? Dobbiamo liberare gli antenati prima che il Clan Ukhel li allontani dai Kurgan.', 56513),
(66654, 'itIT', 'Hai recuperato le armi da quei ladri di tombe?', 56513),
(66652, 'itIT', 'Hai fermato il rituale? Qualche indizio su cosa stesse succedendo?', 56513),
(65937, 'itIT', 'È terribile vedere il bosco, e Theramus, in un tale stato.', 56513),
(65900, 'itIT', 'Sai perché il bocciolaspro cresce sotto gli alberi costieri?\n\nLe radici degli alberi intrappolano moltissimi nutrienti dalle onde, che poi nutrono il bocciolaspro. Questo dà ai fiori un incredibile valore nutritivo.', 56513),
(65903, 'itIT', 'Che morbidezza! Potrei passare tutto il giorno ad accarezzarli.', 56513),
(70062, 'itIT', 'C\'è un inizio e una fine per tutte le creature. Non importa quanto sia lunga o breve una vita.', 56513),
(66700, 'itIT', 'Hai qualcosa da farmi vedere?', 56513),
(65898, 'itIT', 'Sono felice che tu ce l\'abbia fatta. Hai il Locus?', 56513),
(65895, 'itIT', 'Cos\'hai scoperto?', 56513),
(65893, 'itIT', 'Queste rovine sono già abbastanza... rovinate.', 56513),
(70730, 'itIT', 'Narman merita un gesto degno della sua grandezza.', 56513),
(66019, 'itIT', 'I Maruuk hanno fatto ciclicamente ritorno in questo luogo per generazioni e generazioni. Camminiamo al fianco dei nostri antenati.', 56513),
(66020, 'itIT', 'La Khan Tigari è molto brava a leggere i presagi. Con il suo aiuto potremo scoprire di più su questo presagio.', 56513),
(76436, 'itIT', 'Se Fyrakk dovesse entrare nel Tempio della Sorgente, non sarà solo Amirdrassil a bruciare. Tutta Azeroth verrà data alle fiamme.', 56819),
(76461, 'itIT', 'Gli Alafatua sono uno stormo affascinante.', 56819),
(69898, 'itIT', 'La mamma dice che il cibo rende felici tutti.\n\nForse allora diventeremo amici...\n\nCioè, saremo tutti amici! E il professor Tyrgon non mi darà un brutto voto se inserisco la carne di bestia dei fiumi nel progetto!', 56513),
(71034, 'itIT', 'Hai qualcosa per gli archivi?', 56513),
(72809, 'itIT', 'La macchina da gioco Warcraft Rumble si trova davanti a te.\n\nHai il coraggio di giocare?', 56647),
(72589, 'itIT', 'Quanti ne hanno uccisi i Primalisti?', 56647),
(72588, 'itIT', 'Un intero villaggio dipende da queste provviste, quindi cerca di recuperarne quante più possibile.', 56647),
(71013, 'itIT', 'È difficile pescare qui. È questo il punto.', 56647),
(66703, 'itIT', 'Gli amici Tuskarr non hanno una bella cera, $R.', 56647),
(66709, 'itIT', 'Certo, prenditi pure tutto il tempo che vuoi. È quello che voi cuccioli sapete fare meglio.', 56647),
(68642, 'itIT', 'Fai attenzione quando maneggi le penne! Sono MOLTO taglienti. Chiedimi come lo so!\n\n<Steria sospira>', 56647),
(68643, 'itIT', 'Hai riempito tutte le fiale?', 56647),
(68641, 'itIT', 'Hai raccolto il muschio?', 56647),
(70931, 'itIT', 'I sussurri... sono più... più... forti. Hai i frammenti?', 56647),
(70859, 'itIT', 'Hai trovato la scheggia?', 56647),
(67111, 'itIT', 'Hai le ghiandole velenifere che ti ho chiesto?', 56647),
(67724, 'itIT', 'Sei $griuscito:riuscita; a trovare della seta di ragno?', 56647),
(77432, 'itIT', 'Il dolcetto di Pedgi dovrebbe farlo smettere di piagnucolare. Per i Titani, non posso credere di aver appena detto questa cosa...', 56647),
(76144, 'itIT', 'Oh, quella Morcie! In tutta la mia vita non ho mai incontrato una Cromie così falsa e cattiva.', 56647),
(76143, 'itIT', 'So che non è molto educato intrappolare una Cromie, ma dobbiamo sincronizzare le loro firme temporali il prima possibile!\n\nSono certa che capiranno. Io lo capirei! Almeno credo...', 56647),
(76142, 'itIT', 'Cos\'è questo? Essenza Perduta nel Tempo? Un Estrattore... Epocale?', 56647),
(69933, 'itIT', 'Presto! Un ingrediente fresco è un ingrediente potente.', 56647),
(69932, 'itIT', 'Allora?', 56647),
(66136, 'itIT', 'In tutti i miei anni, non ho mai visto così tanti elementali in un unico posto. Perché proprio i miei giardini?', 56647),
(65916, 'itIT', 'Sicuramente, una volte recuperate le Pietre di Volta, Zuttiki non avrà un\'aria così... lugubre.', 56647),
(77236, 'itIT', 'Vieni, queste fenditure non si chiuderanno da sole.', 56647),
(79514, 'itIT', 'Questi elementali instabili sono la base perfetta per i fuochi d\'artificio!', 56647),
(73393, 'itIT', 'Applica un altro Foglio di Rumble al tuo Mini di Warcraft Rumble e ottieni un aspetto ancora più nuovo!', 56647),
(70840, 'itIT', 'Hai trovato una Reliquia dei Titani?', 56647),
(72193, 'itIT', 'Spero ti stia divertendo all\'Accademia. È davvero un posto incredibile.', 56647),
(79226, 'itIT', 'Non capita tutti i giorni di dissotterrare antichi misteri dei draghi... o persino un drago intero!', 56647),
(66447, 'itIT', 'C\'è molto da esaminare nella cripta, ma dovremmo procedere a piccoli passi!', 56647),
(66439, 'itIT', 'Acadia aveva indizi su dove trovare il Globo delle Fiamme Primordiali. L\'hai trovato?', 56647),
(70201, 'itIT', 'Se peschiamo troppo in questo posto, non ci sarà più pesce per nessuno. La sostenibilità è la chiave.\n\nPortami i pesci che vuoi liberare nelle pozze.', 56647),
(70200, 'itIT', 'Se peschiamo troppo in questo posto, non ci sarà più pesce per nessuno. La sostenibilità è la chiave.\n\nPortami i pesci che vuoi liberare nelle pozze.', 56647),
(70199, 'itIT', 'Se peschiamo troppo in questo posto, non ci sarà più pesce per nessuno. La sostenibilità è la chiave.\n\nPortami i pesci che vuoi liberare nelle pozze.', 56647),
(70935, 'itIT', 'Se peschiamo troppo in questo posto, non ci sarà più pesce per nessuno. La sostenibilità è la chiave.\n\nPortami i pesci che vuoi liberare nelle pozze.', 56647),
(70203, 'itIT', 'Se peschiamo troppo in questo posto, non ci sarà più pesce per nessuno. La sostenibilità è la chiave.\n\nPortami i pesci che vuoi liberare nelle pozze.', 56647),
(70202, 'itIT', 'Se peschiamo troppo in questo posto, non ci sarà più pesce per nessuno. La sostenibilità è la chiave.\n\nPortami i pesci che vuoi liberare nelle pozze.', 56647),
(71035, 'itIT', 'Hai qualcosa per gli archivi?', 56647),
(76280, 'itIT', 'Amirdrassil...', 56819),
(77200, 'itIT', 'Hai raccolto tutte le offerte per la cerimonia?', 56819),
(76276, 'itIT', 'Amirdrassil è arrivato sano e salvo, ma dobbiamo assicurarci che anche i nostri alleati lo siano.', 56819),
(76331, 'itIT', 'Ci siamo.', 56819),
(77312, 'itIT', 'Dev\'esserci qualcosa di più che...\n\nNo. Ysera sembra sicura.', 56819),
(77313, 'itIT', 'Sono felice di dare loro l\'opportunità di salutarlo.', 56819),
(77311, 'itIT', 'Le condizioni di Gracus sono gravi. Dobbiamo fare tutto il possibile per aiutarlo.', 56819),
(76332, 'itIT', 'La nostra trappola funzionerà, lo so.\n\nFa\' in fretta, $n. Persino con mia madre e la mia forza... È come se una parte di lei si stesse trattenendo dall\'entrare in sintonia. Non oso rimuginarci.', 56819),
(76328, 'itIT', 'In fretta, $p! I nostri difensori stanno soffrendo.', 56819),
(78046, 'itIT', 'Se a Chardryn e ai suoi folli erboristi viene permesso di scatenare una guerra biologica qui nel Sogno, allora Amirdrassil e tutta Azeroth sono a rischio.\n\nNon possiamo permettere che questi tirapiedi del fuoco restino in vita.', 56819),
(78045, 'itIT', 'Se gli Asfodeli Cinerei diffondessero il loro polline indisturbati, il resto del Sogno sarebbe in grave pericolo.\n\n<Aviana fa una smorfia.>', 56819),
(77788, 'itIT', '<Q\'onzu sbatte lentamente le palpebre mentre ti fissa.>', 56819),
(78042, 'itIT', 'Per ogni minuto in cui agiscono indisturbati, perdiamo un\'altra parte del Sogno a causa delle loro malefatte.', 56819),
(71135, 'itIT', 'Non avremo pace finché Gelomorso e gli Gnoll Mantonevoso non saranno stati eliminati.', 56647),
(72291, 'itIT', 'Le storie più incredibili possono accadere a chiunque.\n\nLe nostre azioni ci rendono chi siamo. Sono sempre entusiasta di scoprire le gesta più impressionanti e farne un esempio per gli altri.', 56647),
(66647, 'itIT', 'Se riesci a recuperarlo, il Focus Elementale ci tornerà utile.', 56647),
(65850, 'itIT', 'È bello rallentare, di tanto in tanto. Ed è interessante vedere le tradizioni dei Tuskarr.\n\nÈ passato molto tempo dall\'ultima volta che lo Stormo dei Draghi Blu ha avuto tradizioni come queste.', 56647),
(66423, 'itIT', 'Hai scoperto qualcosa sulle rovine?', 56647),
(66352, 'itIT', 'Hai trovato qualcosa, $n?', 56647),
(66151, 'itIT', 'Il nostro capo ambiva al potere per proteggere il clan... e invece ci ha tolto tutto.', 56647),
(66972, 'itIT', 'Fatto?', 56647),
(70550, 'itIT', 'Avremo bisogno di tutto l\'aiuto possibile.', 56647),
(77251, 'itIT', 'I venti brillano di essenza del sogno, diffondendola ovunque.', 56647),
(66523, 'itIT', 'Aria fresca e reliquie magiche. Che cosa vuoi di più dalla vita? Un...', 56647),
(67033, 'itIT', 'Hai portato i pezzi? Ricordo esattamente com\'era assemblato, quindi ripararlo non dovrebbe essere un problema.', 56647),
(67035, 'itIT', 'Hai con te i tomi?', 56647),
(67177, 'itIT', 'Hai con te le corna?', 56647),
(67175, 'itIT', 'La bacchetta dovrebbe riuscire a dissolvere tutto, se non è troppo tardi.', 56647),
(66227, 'itIT', 'Fammi sapere se ti serve qualche dritta.', 56647),
(77203, 'itIT', 'Quel mistero non si risolverà da solo!', 56819),
(66166, 'itIT', 'Allora, hai trovato qualcosa di utile?', 56819),
(76465, 'itIT', 'Questi draghi saranno liberi.', 56819),
(76464, 'itIT', 'Scopriremo perché questo Stormo dei Draghi della Tempesta non ha risposto al richiamo delle isole.', 56819),
(76463, 'itIT', 'I draghetti adorano mangiare quegli scarabei.', 56819),
(73386, 'itIT', 'Applica un Foglio di Rumble al tuo Mini di Warcraft Rumble e ottieni un nuovo aspetto!', 56647),
(73389, 'itIT', 'Applica un Foglio di Rumble al tuo Mini di Warcraft Rumble e ottieni un nuovo aspetto!', 56647),
(72667, 'itIT', 'Era lo stesso ad Aszuna. Formaggio e cracker sono tra i cibi preferiti da tutti i draghetti.', 56647),
(70377, 'itIT', 'Non posso assolutamente farmi vedere nell\'area VIP senza i miei occhiali da sole!\n\nVedi, ho preso un aliante e, mentre facevo delle foto STU-PEN-DE, ho guardato giù e ho visto tutti questi piccoli elementali grandi come formiche! Allora ho pensato: elementali grandi come formiche, che opportunità per una foto.\n\nMa, dal vivo, erano almeno tre volte più grandi di una formica! Uno fangoso mi ha inseguito, ma sono molto veloce. Non oso pensare a cosa sia successo ai miei occhiali...', 56647),
(66415, 'itIT', 'Sapevo che sarebbe successo un giorno, anche se ciò non attenua il dolore.', 56647),
(66414, 'itIT', 'Non avrei dovuto lasciarla vagare così lontano...', 56647),
(66417, 'itIT', 'Dopo che i cacciatori e le guardie avranno nuove armi, potrò formare un gruppo per prendere il resto.', 56647),
(66411, 'itIT', 'Un tempo, il fiume era bellissimo e abbondante di vita. Prego che un giorno ritorni com\'era.', 56647),
(66409, 'itIT', 'Se quell\'arma è solo per dar spettacolo, diccelo e non farci perdere tempo.', 56647),
(65302, 'itIT', 'Portato armi o vuoi che io mangia te?', 56647),
(65306, 'itIT', 'SERVE PIÙ MELMA!', 56647),
(72606, 'itIT', 'Gliela farò pagare per ciò che hanno fatto!', 56647),
(72602, 'itIT', 'Hai trovato tutto?', 56647),
(72662, 'itIT', 'Quanta ne hai raccolta?', 56647),
(72595, 'itIT', 'Cos\'hai trovato?', 56647),
(65789, 'itIT', 'Hai scoperto tutto?', 56647),
(66711, 'itIT', 'Fai attenzione alle trappole, potrebbero contenere delle seccature ancora più aggressive.', 56647),
(67080, 'itIT', 'Cosa può fare per te il Consorzio degli Artigiani, quest\'oggi?', 56647),
(70242, 'itIT', 'Sei $griuscito:riuscita; a trovare Trellain?', 56647),
(70026, 'itIT', 'Cosa può fare per te il Consorzio degli Artigiani, quest\'oggi?', 56647),
(67093, 'itIT', 'Questa terra è come un gigante addormentato. Dovremmo svegliarla con estrema cautela.', 56647),
(76162, 'itIT', 'Hai trovato il mojo mio?', 56647),
(75922, 'itIT', 'Terrò a bada eventuali rinforzi che dovessero arrivare. Tu occupati del custode!', 56647),
(75921, 'itIT', 'Dobbiamo avvicinarci alle Incarnazioni il più possibile.\n\nNon possiamo permetterci di perdere una singola parola della loro conversazione.', 56647),
(70507, 'itIT', 'A quanto pare, i Gorloc non sono adatti come guardie del corpo. Mi chiedo quanto sarebbe stata pericolosa se non fosse impazzita.', 56647),
(71138, 'itIT', 'Che cosa stai aspettando?', 56647),
(70190, 'itIT', 'Quali conoscenze stai cercando?', 56647),
(70183, 'itIT', 'Quali conoscenze stai cercando?', 56647),
(69979, 'itIT', 'Torni $gvittorioso:vittoriosa;? Una grande caccia porta grandi ricompense.', 56647),
(67298, 'itIT', 'Potrei stare qui a rilassarmi per sempre.', 56647),
(69981, 'itIT', '<Mahra fischietta tra sé e sé mentre lavora.>', 56647),
(67295, 'itIT', 'Sì, questo è il succo della questione, comunque.', 56647),
(70501, 'itIT', 'Hai completato il tuo addestramento?', 56647),
(72868, 'itIT', 'Cosa mi hai portato?', 56647),
(70989, 'itIT', 'Hai già abbattuto quel draco? Il mio bakar dovrebbe essere più che sufficiente per la tua preda.', 56647),
(66783, 'itIT', 'La formula dice:\n\nDai cacciatori che valutano l\'abilità sopra ogni cosa, un rito di passaggio: un primo.\n\nDai mistici che comunicano col vento, il suo tocco più gentile: un passaggio.\n\nDai discendenti della matriarca, una goccia di progenie intatta: un retaggio.', 56647),
(66335, 'itIT', 'Apprezzerei se non mi stessi così vicino con quei semi incantati. Grazie.', 56647),
(66333, 'itIT', 'Fai in fretta, mortale. Non porterò i draghi in battaglia finché ci saranno quelle baliste.', 56647),
(70220, 'itIT', 'Vai con la mia benedizione.', 56513),
(70195, 'itIT', 'Ho i miei sospetti sull\'identità di questi nuovi alleati dei Nokhud, ma devo esserne certa.', 56513),
(66225, 'itIT', 'I totem sono infusi con la magia del vento di Ohn\'ahra.\n\nEppure i Nokhud hanno abbandonato i suoi insegnamenti. Cosa stanno combinando?', 56513),
(66224, 'itIT', '$n, stai bene! Sia ringraziata Ohn\'ahra.\n\nOh, i miei Totem!', 56513),
(66690, 'itIT', 'Balakar non si separa mai dal suo pendente. Dovrai ucciderlo.', 56513),
(66201, 'itIT', 'Cosa vuoi?', 56513),
(71027, 'itIT', 'Salve, viandante.', 56513),
(65805, 'itIT', 'La canzone di Ohn\'ahra è effimera. Dobbiamo agire in fretta.', 56513),
(65804, 'itIT', 'I nostri giovani cacciatori sono appassionati e determinati. $gAttento:Attenta; che non ti mettano in imbarazzo.', 56513),
(70185, 'itIT', 'Sei $gtornato:tornata; dalla tua caccia?', 56513),
(70319, 'itIT', 'La mia febbre sta peggiorando, $gamico mio:amica mia;. Temo che se non curerò presto l\'infezione, morirò.', 56513),
(65953, 'itIT', 'Gli sciamani dei gorloc hanno esagerato.', 56513),
(65950, 'itIT', 'Ci sono troppi gorloc qua attorno. Non siamo al sicuro.', 56513),
(65802, 'itIT', 'Non disturbarmi finché non avrai le provviste per la carovana.', 56513),
(77675, 'itIT', 'Farò del mio meglio per aiutare Shandris. È il minimo che possa fare per una commilitona.', 56647),
(77739, 'itIT', 'Portami tutte e quattro le Pietre dello Spirito. Dobbiamo tenerle vicine, così che non cadano nelle mani sbagliate.', 56647),
(76570, 'itIT', 'Il Druido Guardiafiume mi aveva detto che le piante sferzanti di solito si appostano per colpire la loro preda.\n\nPer fortuna, non queste. Rende la battaglia più interessante!', 56647),
(78431, 'itIT', 'Continua! Voglio vederti infondere Rithro.', 56647),
(78428, 'itIT', 'Ricordati di chiedere a Vashonir di aiutarti a preparare le spedizioni!', 56647),
(77316, 'itIT', 'Se non riusciremo a recuperare i rifornimenti da quei fastidiosi Spriggan, non riusciremo a tener fede al programma!', 56647),
(77978, 'itIT', 'Che c\'è?', 56647),
(78427, 'itIT', 'Vashonir ti aiuterà a preparare le spedizioni.', 56647),
(78381, 'itIT', 'Hai trovato un\'altra Scintilla dei Sogni Frammentata?', 56647),
(78171, 'itIT', 'Hai raccolto i tre boccioli?', 56647),
(78170, 'itIT', 'Hai dato le Gocce Senza Età ai semi germoglianti?', 56647),
(76433, 'itIT', 'Fa\' in fretta. Queste fiamme diventano più intense ogni istante che passa.', 56647),
(77283, 'itIT', 'Hai trovato ciò che ti serviva qui all\'accampamento?', 56647);
