INSERT INTO `quest_description_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(32470, 924, 16908, 'itIT', 'Oh, ciao! Non la trovi anche tu una foto grandiosa? Adoro la mia Fotocamera S.E.L.F.I.E.!\n\nVuoi che te ne faccia una? Mi servono solo alcune parti!\n\nPer la cinghia, mi serve una Cintura Color Ruggine da uno dei mercanti d\'armature di Roccavento.\n\nHo già ordinato altri corpi macchina, sei $glibero:libera; di prenderne uno; devi solo scoprire dov\'è finita la mia spedizione!\n\nE, naturalmente, un Mirino Standard, che qualsiasi ingegnere è in grado di procurarti.\n\nBene, sei $gpronto:pronta; a scatenare le tue doti fotografiche?', 1, 56311), -- Light Camera Action
(32470, 923, 16926, 'itIT', 'Sembra proprio tu abbia un buon occhio per le arti visive, ti va di provare con la fotografia?\n\nPosso costruirti una di queste Fotocamere S.E.L.F.I.E., mi servono solo alcune parti.\n\nPer la tracolla, portami una Cintura Color Ruggine da uno dei mercanti d\'armature qui nei paraggi.\n\nMi hanno spedito dei nuovi corpi macchina che aspettano solo di essere recuperati all\'entrata posteriore della città; puoi prenderne uno se passi di lì.\n\nOh, e portami anche un Mirino Standard, che qualsiasi ingegnere è in grado di costruirti.\n\nOra vai là fuori, la fama ti attende!', 0, 56311), -- Light Camera Action
(78177, 44108, 212162, 'itIT', '$n, è ora di tornare a casa. I Reietti hanno lasciato la nostra terra, come promesso.\n\nTuttavia, in loro assenza, i membri della Crociata Scarlatta hanno deciso di entrare in città e di usarla come una loro roccaforte personale. Ho intenzione di cacciarli.\n\nFacciamogli visita e dimostriamogli cosa succede quando si ostacola un Gilneano.', 0, 56513), -- To Gilneas
(72591, 40576, 202656, 'itIT', '$n, ho sentito che sei in buoni rapporti con i Centauri delle Pianure di Ohn\'ahra. Vorrei chiederti un favore.\n\nBaine è partito per le Pianure di Ohn\'ahra qualche giorno fa, alla ricerca di un gruppo di Tauren scomparsi. Mi sono offerta di accompagnarlo, ma ha insistito per andare da solo.\n\nI Tauren di Picco del Tuono, come ben sai, hanno un passato sanguinoso con i Centauri di Kalimdor. Per quanto i Centauri Maruuk non vi siano direttamente collegati, sono comunque preoccupata.\n\nLa tua presenza potrebbe appianare le tensioni. Spero.', 0, 56647), -- A Debt That Must Be Paid
(72256, 101846, 0, 'itIT', 'Naleidea sembra entusiasta, ma è una storica, non un soldato come noi. Non sa niente dei pericoli che affronteremo nelle Isole dei Draghi.\n\nNon che l\'Orda si debba preoccupare. Dopo tutto, la spedizione è protetta dagli Artigli Oscuri.\n\nDiscuterò della logistica con Ebissian e gli altri capi dell\'Orda.\n\nKodethi sta esplorando la città con gli altri. Digli di riunire tutti alla Torre degli Zeppelin. Ci vedremo lì.', 0, 56647), -- The Dark Talons
(65437, 99433, 0, 'itIT', 'È bello rivederti, $p. Spero che la tua esplorazione di Orgrimmar sia stata fruttuosa. È una città costruita sulla fratellanza e il coraggio.\n\nHo appena parlato con il Concilio dell\'Orda, che ha accettato l\'invito degli Aspetti per le Isole dei Draghi.\n\nI preparativi per il viaggio inizieranno a breve.\n\nVieni, parliamo con gli altri.', 0, 56647), -- Aspectral Invitation
(66556, 5793, 0, 'itIT', '', 0, 56647), -- Ice Cave Ya Got There
(76107, 923, 0, 'itIT', '<I tuoi occhi intravedono il bagliore di un oggetto lontano. Ti ricordi improvvisamente di avere delle monete da riscattare all\'Emporio di Zen\'shiri.>', 0, 56819), -- Report to the Trading Post
(78643, 117323, 187678, 'itIT', 'È stata una lunga strada per tutti noi, $p.\n\nMa dopo aver superato difficoltà e conflitti, i dragoidi sono pronti a entrare in una nuova era.\n\nPrima di partire per la tua prossima avventura, io e i miei compagni Aspetti vorremmo ringraziarti per tutto ciò che hai fatto per noi.', 0, 56819), -- Fair Skies and Strong Winds
(75891, 110815, 202701, 'itIT', 'È passato molto tempo dall\'ultima volta che ci siamo visti, $n. Vorrei che queste fossero circostanze migliori.\n\nLa corruzione demoniaca è tornata a tormentare Vilbosco, di recente. Tyrande ha inviato un contingente di Sentinelle e una delle sue Sacerdotesse per indagare ulteriormente. Non è tornata anima viva.\n\nTyrande ha chiesto alle Custodi di indagare sulla questione, ma è stato richiesto anche il tuo aiuto. Maiev ti fornirà i dettagli quando arriverà, ma temo per ciò che troveremo in quel luogo maledetto.', 0, 56819), -- Ancient Curses
(72241, 95579, 0, 'itIT', '$n! Mi fa piacere rivederti. Irathion ci ha aiutati dopo che siamo emersi dalla nostra lunga stasi, ora tocca a noi aiutarlo.\n\nMa prima... Ci sono un po\' di cose che dovresti sapere.\n\nDopo che abbiamo lasciato l\'Isola Proibita, ho ricevuto visioni da Nozdormu, l\'Eterno. Mi ha mostrato molte verità sui draghi, sul destino di Neltharion e sull\'origine del nostro popolo. \n\nLascia che ti racconti cos\'ho visto. Devi ascoltare direttamente tu $gstesso:stessa;.', 0, 56513); -- Lessons From Our Past
INSERT INTO `quest_completion_log_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(74381, 0, 0, 'itIT', '', 0, 56513), -- Hidden Legacies
(71239, 0, 0, 'itIT', '', 0, 56647), -- Lost to the Skies
(66676, 0, 0, 'itIT', '', 0, 56513), -- Sneaking In
