(78172, 0, 0, 'itIT', '', 0, 56819), -- Mysterious Seeds
(66673, 0, 0, 'itIT', '', 0, 56647), -- Speak to Koranos
(67606, 0, 0, 'itIT', '', 0, 56647), -- A Dryadic Remedy
