INSERT INTO `quest_offer_reward_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(65437, 99433, 0, 'itIT', 'Le Isole dei Draghi hanno molti più segreti delle Isole Proibite.\n\n\n\nLe loro meraviglie saranno nuove per te come per l\'Orda.', 0, 56647), -- Aspectral Invitation
(72241, 95579, 0, 'itIT', 'Ora sai la verità, $p.\n\nIl passato è passato. Ora dobbiamo occuparci gli uni degli altri. Per tutti i Dracthyr.', 0, 56513), -- Lessons From Our Past
(76107, 923, 185472, 'itIT', 'Spero ti piaccia la collezione mensile di merci nuove ed esotiche, $n.', 0, 56819), -- Report to the Trading Post
(77198, 111727, 207352, 'itIT', 'La sicurezza e il futuro degli Alafatua sono ora al sicuro, $n.\n\nViaggiare dalle Terre Esterne ad Azeroth è stato sconvolgente, ma in senso positivo. Sono felice che ci fossi anche tu.\n\nIl mio stormo prospera. Non potrò mai ringraziarti abbastanza per il tuo aiuto nel corso degli anni.', 0, 56819), -- Home in Time for Tea
(75258, 34467, 201566, 'itIT', '$n, senza di te questo viaggio sarebbe finito diversamente. Grazie per essere $grimasto:rimasta; al mio fianco durante tutto questo.\n\nInoltre, mi hai aperto gli occhi... C\'è una nuova via per la nostra gente che non avrei mai immaginato possibile. Per questo meriti un dono speciale.\n\nQuesti totem sono intarsiati con la storia del nostro popolo. Una storia intrisa del sangue dei Centauri.\n\nMi hai insegnato che è bene ricordare il passato, ma non dobbiamo permettere che ci ostacoli.\n\nPrendi questi totem con la mia più profonda gratitudine.', 0, 56647), -- A Final Word
(72599, 0, 200932, 'itIT', 'Hai salvato alcuni prigionieri, ma non c\'è traccia di Bovan? Cerchiamo di nuovo.', 0, 56647), -- Joint Rescue Operation
(73076, 101846, 0, 'itIT', 'Eccoti di nuovo a casa, $p.\n\nSembra quasi come il giorno in cui ci siamo ritirati. Per fortuna con meno fulmini, però.', 0, 56647), -- Return to the Reach
(65686, 101846, 185603, 'itIT', 'Ah, $gun avventuriero:un\'avventuriera;. Devi essere $gun:una; Dracthyr. \n\nIl Kirin Tor potrebbe aver bisogno del tuo aiuto, ma anche alcuni dei tuoi alleati qui cercano supporto.\n\nTi suggerisco di parlare con loro prima di vedere cosa chiede il Kirin Tor.', 0, 56647); -- To the Azure Span
INSERT INTO `quest_request_items_conditional` (`QuestId`, `PlayerConditionId`, `QuestgiverCreatureId`, `locale`, `Text`, `OrderIndex`, `VerifiedBuild`) VALUES
(76464, 111906, 207351, 'itIT', 'Ma è... è...', 0, 56819), -- The Thorignir
(77955, 0, 0, 'itIT', 'I miei occhi sono stanchi, ma il mio corpo è ancora sveglio...', 0, 56647), -- Heated Hearthstone Hustle
(77922, 0, 0, 'itIT', 'La salvia dovrebbe essere abbastanza soffice per creare un buon posto per dormire. Grazie per l\'aiuto.', 0, 56647), -- Fluffy Filler Retrieval
(77911, 0, 0, 'itIT', 'Per il Sogno di Smeraldo, certo che è piuttosto caotico qui.', 0, 56647); -- Build-a-Blanket
